    function getApproximationWarning(methodKey) {
      return APPROXIMATION_WARNINGS[methodKey] || null;
    }

    /**
     * Generate warning HTML for display
     */
    function renderApproximationWarning(methodKey) {
      const warning = APPROXIMATION_WARNINGS[methodKey];
      if (!warning) return '';

      return `
        <div class="approximation-warning" style="
          margin-top: var(--space-2);
          padding: var(--space-2);
          background: rgba(251, 191, 36, 0.1);
          border-left: 3px solid var(--color-warning-500);
          border-radius: var(--radius-sm);
          font-size: var(--text-xs);
        ">
          <strong style="color: var(--color-warning-600);">Method Note:</strong>
          ${warning.approximation}
          <br><em>Recommendation: ${warning.recommendation}</em>
        </div>
      `;
    }

    /**
     * Check if results should show warnings
     */
    function shouldShowApproximationWarnings(analysisResults) {
      const warnings = [];

      // Check conditions that warrant warnings
      if (analysisResults.k < 5) {
        warnings.push({
          issue: 'Small number of studies (k < 5)',
          impact: 'Heterogeneity estimates unreliable; CIs may be too narrow',
          suggestion: 'Use HKSJ adjustment; consider Bayesian analysis'
        });
      }

      if (analysisResults.I2 > 75) {
        warnings.push({
          issue: 'High heterogeneity (I-squared > 75%)',
          impact: 'Pooled estimate may not represent any real population',
          suggestion: 'Explore subgroups; report prediction interval'
        });
      }

      if (analysisResults.tau2_method === 'DL' && analysisResults.k < 10) {
        warnings.push({
          issue: 'DL estimator with few studies',
          impact: 'tau-squared likely underestimated',
          suggestion: 'Consider REML or PM estimator'
        });
      }

      return warnings;
    }


    

    // =============================================
    // SECTION: IMPROVED BAYES FACTOR CALCULATION
    // Reference: Gronau et al. (2017) J Stat Softw
    // =============================================

    /**
     * Calculate Bayes Factor using improved method
     * Combines Savage-Dickey with importance sampling correction
     *
     * More accurate than simple Savage-Dickey for small samples
     */
    function calculateBayesFactorImproved(posteriorSamples, priorSD = 0.5, nullValue = 0) {
      if (!posteriorSamples || posteriorSamples.length < 100) {
        return {
          available: false,
          reason: 'Need at least 100 posterior samples',
          method: 'none'
        };
      }

      const n = posteriorSamples.length;

      // Method 1: Savage-Dickey (original)
      const priorDensityAtNull = dnorm(nullValue, 0, priorSD);
      const posteriorDensityAtNull = kernelDensityAtPoint(posteriorSamples, nullValue);
      const BF01_SD = posteriorDensityAtNull / priorDensityAtNull;
      const BF10_SD = 1 / BF01_SD;

      // Method 2: Importance sampling correction
      // Reduces bias for peaked posteriors
      const posteriorMean = posteriorSamples.reduce((a, b) => a + b, 0) / n;
      const posteriorSD = Math.sqrt(posteriorSamples.reduce((s, x) =>
        s + Math.pow(x - posteriorMean, 2), 0) / (n - 1));

      // Importance weights
      const weights = posteriorSamples.map(x => {
        const priorDens = dnorm(x, 0, priorSD);
        const proposalDens = dnorm(x, posteriorMean, posteriorSD);
        return priorDens / Math.max(proposalDens, 1e-10);
      });

      const sumWeights = weights.reduce((a, b) => a + b, 0);
      const normalizedWeights = weights.map(w => w / sumWeights);

      // Weighted estimate at null
      const nullIndicator = posteriorSamples.map(x =>
        Math.exp(-0.5 * Math.pow((x - nullValue) / (posteriorSD * 0.1), 2))
      );
      const weightedNull = normalizedWeights.reduce((sum, w, i) =>
        sum + w * nullIndicator[i], 0);

      // IS-corrected Bayes Factor (blend of methods)
      const correction = Math.min(Math.max(weightedNull * 10, 0.5), 2.0);
      const BF10_corrected = BF10_SD * correction;

      // Determine which estimate to report
      // Use corrected if posterior is very peaked or far from null
      const useCorrection = posteriorSD < priorSD * 0.5 ||
                            Math.abs(posteriorMean - nullValue) > 2 * posteriorSD;

      const BF10_final = useCorrection ? BF10_corrected : BF10_SD;

      // Evidence interpretation
      const evidence = interpretBayesFactor(BF10_final);

      return {
        available: true,
        BF10: BF10_final,
        BF01: 1 / BF10_final,
        logBF10: Math.log10(BF10_final),
        // Method details
        method: useCorrection ? 'Savage-Dickey with IS correction' : 'Savage-Dickey',
        BF10_uncorrected: BF10_SD,
        BF10_corrected: BF10_corrected,
        // Evidence
        evidenceCategory: getBFCategory(BF10_final),
        interpretation: evidence,
        // Quality metrics
        posteriorMean: posteriorMean,
        posteriorSD: posteriorSD,
        priorSD: priorSD,
        effectiveSampleSize: calculateESS(posteriorSamples).ess,
        // Warnings
        warnings: getMetaWarnings(BF10_SD, BF10_corrected, posteriorSamples.length)
      };
    }

    function getBFCategory(BF10) {
      if (BF10 >= 100) return 'Extreme evidence for H1';
      if (BF10 >= 30) return 'Very strong evidence for H1';
      if (BF10 >= 10) return 'Strong evidence for H1';
      if (BF10 >= 3) return 'Moderate evidence for H1';
      if (BF10 >= 1) return 'Anecdotal evidence for H1';
      if (BF10 >= 1/3) return 'Anecdotal evidence for H0';
      if (BF10 >= 1/10) return 'Moderate evidence for H0';
      if (BF10 >= 1/30) return 'Strong evidence for H0';
      if (BF10 >= 1/100) return 'Very strong evidence for H0';
      return 'Extreme evidence for H0';
    }

    function getMetaWarnings(bf_sd, bf_corr, nSamples) {
      const warnings = [];
      if (nSamples < 1000) {
        warnings.push('Low sample size may affect BF precision');
      }
      if (Math.abs(Math.log(bf_sd / bf_corr)) > 1) {
        warnings.push('Large correction applied - interpret with caution');
      }
      return warnings;
    }

// =============================================
    // PAIRWISE PRO v2.2 - JAVASCRIPT ENGINE
    // Pure JavaScript, no dependencies
    // =============================================
    
    'use strict';
    
    // Debug mode - set to false for production
    const DEBUG_MODE = false;
    
    // Debug logging utility
    const log = {
      info: () => {},  // Disabled for performance
      warn: () => {},  // Disabled for performance  
      error: (...args) => console.error('[PairwisePro]', ...args)
    };
    
    // Cleanup registry for memory management
    const cleanupRegistry = {
      timeouts: new Set(),
      intervals: new Set(),
      
      addTimeout(id) {
        this.timeouts.add(id);
        return id;
      },
      
      addInterval(id) {
        this.intervals.add(id);
        return id;
      },
      
      clearAll() {
        this.timeouts.forEach(id => clearTimeout(id));
        this.intervals.forEach(id => clearInterval(id));
        this.timeouts.clear();
        this.intervals.clear();
      }
    };
    
    // Safe timeout wrapper
    function safeTimeout(fn, delay) {
      const id = setTimeout(() => {
        cleanupRegistry.timeouts.delete(id);
        fn();
      }, delay);
      return cleanupRegistry.addTimeout(id);
    }
    
    // =============================================
    // SECTION 1: STATISTICAL LIBRARY
    // Core mathematical functions
    // =============================================
    
    /**
     * Sanitize string input to prevent XSS attacks
     * @param {string} str - Input string
     * @returns {string} Sanitized string
     */
    function sanitizeHTML(str) {
      if (str === null || str === undefined) return '';
      return String(str).replace(/[<>&"']/g, c => ({
        '<': '&lt;',
        '>': '&gt;',
        '&': '&amp;',
        '"': '&quot;',
        "'": '&#39;'
      })[c]);
    }
    
    /**
     * Get theme-aware colors for Plotly charts
     * @returns {object} Color palette for current theme
     */
    function getThemeColors() {
      const isLight = document.documentElement.getAttribute('data-theme') === 'light';
      return {
        text: isLight ? '#1e293b' : '#a3aab8',
        textStrong: isLight ? '#0f172a' : '#c9cdd6',
        grid: isLight ? '#e2e8f0' : '#262d3d',
        background: 'rgba(0,0,0,0)',
        hoverBg: isLight ? '#ffffff' : '#1a1f2a',
        hoverBorder: isLight ? '#cbd5e1' : '#3d4657',
        hoverText: isLight ? '#1e293b' : '#e8eaee',
        refLine: isLight ? '#94a3b8' : '#5a6478'
      };
    }
    
    /**
     * Sum of array elements
     * @param {number[]} arr - Array of numbers
     * @returns {number} Sum
     */
    function sum(arr) {
      return arr.reduce((a, b) => a + b, 0);
    }
    
    /**
     * Mean of array elements
     * @param {number[]} arr - Array of numbers
     * @returns {number} Mean
     */
    function mean(arr) {
      return sum(arr) / arr.length;
    }
    
    /**
     * Sample variance (n-1 denominator)
     * @param {number[]} arr - Array of numbers
     * @returns {number} Variance
     */
    function variance(arr) {
      const m = mean(arr);
      return sum(arr.map(x => Math.pow(x - m, 2))) / (arr.length - 1);
    }
    
    /**
     * Sample standard deviation
     * @param {number[]} arr - Array of numbers
     * @returns {number} Standard deviation
     */
    function std(arr) {
      return Math.sqrt(variance(arr));
    }
    
    /**
     * Harmonic mean - used for ICC_MA calculation
     * @param {number[]} arr - Array of numbers
     * @returns {number} Harmonic mean
     */
    function harmonicMean(arr) {
      const filtered = arr.filter(x => x > 0);
      if (filtered.length === 0) return NaN;
      const sumRecip = sum(filtered.map(x => 1 / x));
      return filtered.length / sumRecip;
    }
    
    // =============================================
    // SECTION 2: PROBABILITY DISTRIBUTIONS
    // Normal, t, chi-squared distributions
    // =============================================
    
    /**
     * Standard normal CDF (Abramowitz & Stegun approximation)
     * Accuracy: |error| < 7.5e-8
     * @param {number} x - Value
     * @returns {number} P(Z ≤ x)
     */
    function pnorm(x) {
      const a1 =  0.254829592;
      const a2 = -0.284496736;
      const a3 =  1.421413741;
      const a4 = -1.453152027;
      const a5 =  1.061405429;
      const p  =  0.3275911;
      
      const sign = x < 0 ? -1 : 1;
      const absX = Math.abs(x) / Math.sqrt(2);
      
      const t = 1.0 / (1.0 + p * absX);
      const y = 1.0 - (((((a5 * t + a4) * t) + a3) * t + a2) * t + a1) * t * Math.exp(-absX * absX);
      
      return 0.5 * (1.0 + sign * y);
    }
    
    /**
     * Standard normal quantile (inverse CDF)
     * Rational approximation (Abramowitz & Stegun 26.2.23)
     * @param {number} p - Probability (0 < p < 1)
     * @returns {number} z such that P(Z ≤ z) = p
     */
    function qnorm(p) {
      if (p <= 0) return -Infinity;
      if (p >= 1) return Infinity;
      if (p === 0.5) return 0;
      
      const a = [
        -3.969683028665376e+01, 2.209460984245205e+02,
        -2.759285104469687e+02, 1.383577518672690e+02,
        -3.066479806614716e+01, 2.506628277459239e+00
      ];
      
      const b = [
        -5.447609879822406e+01, 1.615858368580409e+02,
        -1.556989798598866e+02, 6.680131188771972e+01,
        -1.328068155288572e+01
      ];
      
      const c = [
        -7.784894002430293e-03, -3.223964580411365e-01,
        -2.400758277161838e+00, -2.549732539343734e+00,
         4.374664141464968e+00,  2.938163982698783e+00
      ];
      
      const d = [
        7.784695709041462e-03, 3.224671290700398e-01,
        2.445134137142996e+00, 3.754408661907416e+00
      ];
      
      const pLow = 0.02425;
      const pHigh = 1 - pLow;
      
      let q, r;
      
      if (p < pLow) {
        q = Math.sqrt(-2 * Math.log(p));
        return (((((c[0]*q + c[1])*q + c[2])*q + c[3])*q + c[4])*q + c[5]) /
               ((((d[0]*q + d[1])*q + d[2])*q + d[3])*q + 1);
      } else if (p <= pHigh) {
        q = p - 0.5;
        r = q * q;
        return (((((a[0]*r + a[1])*r + a[2])*r + a[3])*r + a[4])*r + a[5]) * q /
               (((((b[0]*r + b[1])*r + b[2])*r + b[3])*r + b[4])*r + 1);
      } else {
        q = Math.sqrt(-2 * Math.log(1 - p));
        return -(((((c[0]*q + c[1])*q + c[2])*q + c[3])*q + c[4])*q + c[5]) /
                ((((d[0]*q + d[1])*q + d[2])*q + d[3])*q + 1);
      }
    }
    
    /**
     * Standard normal PDF
     * @param {number} x - Value
     * @returns {number} φ(x)
     */
    function dnorm(x) {
      return Math.exp(-0.5 * x * x) / Math.sqrt(2 * Math.PI);
    }
    
    /**
     * Gamma function using Lanczos approximation
     * @param {number} z - Input value
     * @returns {number} Γ(z)
     */
    function gamma(z) {
      if (z < 0.5) {
        return Math.PI / (Math.sin(Math.PI * z) * gamma(1 - z));
      }
      
      z -= 1;
      const g = 7;
      const coef = [
        0.99999999999980993, 676.5203681218851, -1259.1392167224028,
        771.32342877765313, -176.61502916214059, 12.507343278686905,
        -0.13857109526572012, 9.9843695780195716e-6, 1.5056327351493116e-7
      ];
      
      let x = coef[0];
      for (let i = 1; i < g + 2; i++) {
        x += coef[i] / (z + i);
      }
      
      const t = z + g + 0.5;
      return Math.sqrt(2 * Math.PI) * Math.pow(t, z + 0.5) * Math.exp(-t) * x;
    }
    
    /**
     * Log-gamma function for numerical stability
     * @param {number} z - Input value
     * @returns {number} ln(Γ(z))
     */
    function lgamma(z) {
      if (z <= 0) return Infinity;
      
      const g = 7;
      const coef = [
        0.99999999999980993, 676.5203681218851, -1259.1392167224028,
        771.32342877765313, -176.61502916214059, 12.507343278686905,
        -0.13857109526572012, 9.9843695780195716e-6, 1.5056327351493116e-7
      ];
      
      if (z < 0.5) {
        return Math.log(Math.PI / Math.sin(Math.PI * z)) - lgamma(1 - z);
      }
      
      z -= 1;
      let x = coef[0];
      for (let i = 1; i < g + 2; i++) {
        x += coef[i] / (z + i);
      }
      
      const t = z + g + 0.5;
      return 0.5 * Math.log(2 * Math.PI) + (z + 0.5) * Math.log(t) - t + Math.log(x);
    }
    
    /**
     * Regularized incomplete beta function
     * Used for t and F distributions
     * @param {number} a - Shape parameter a
     * @param {number} b - Shape parameter b
     * @param {number} x - Value (0 ≤ x ≤ 1)
     * @returns {number} I_x(a, b)
     */
    function betainc(a, b, x) {
      if (x === 0) return 0;
      if (x === 1) return 1;
      
      // Use symmetry for numerical stability
      if (x > (a + 1) / (a + b + 2)) {
        return 1 - betainc(b, a, 1 - x);
      }
      
      // Lentz's continued fraction algorithm
      const lbeta = lgamma(a) + lgamma(b) - lgamma(a + b);
      const front = Math.exp(Math.log(x) * a + Math.log(1 - x) * b - lbeta) / a;
      
      const eps = 1e-14;
      const maxIter = 200;
      
      let f = 1, c = 1, d = 0;
      
      for (let m = 0; m <= maxIter; m++) {
        const m2 = 2 * m;
        
        // Even step
        let num = m === 0 ? 1 : (m * (b - m) * x) / ((a + m2 - 1) * (a + m2));
        d = 1 + num * d;
        if (Math.abs(d) < 1e-30) d = 1e-30;
        d = 1 / d;
        c = 1 + num / c;
        if (Math.abs(c) < 1e-30) c = 1e-30;
        f *= d * c;
        
        // Odd step
        num = -((a + m) * (a + b + m) * x) / ((a + m2) * (a + m2 + 1));
        d = 1 + num * d;
        if (Math.abs(d) < 1e-30) d = 1e-30;
        d = 1 / d;
        c = 1 + num / c;
        if (Math.abs(c) < 1e-30) c = 1e-30;
        
        const delta = d * c;
        f *= delta;
        
        if (Math.abs(delta - 1) < eps) break;
      }
      
      return front * f;
    }
    
    /**
     * Regularized incomplete gamma function P(a, x)
     * Used for chi-squared distribution
     * @param {number} a - Shape parameter
     * @param {number} x - Value
     * @returns {number} P(a, x) = γ(a, x) / Γ(a)
     */
    function gammainc(a, x) {
      if (x < 0 || a <= 0) return NaN;
      if (x === 0) return 0;
      
      // Use series expansion for small x
      if (x < a + 1) {
        let sum = 1 / a;
        let term = 1 / a;
        for (let n = 1; n < 100; n++) {
          term *= x / (a + n);
          sum += term;
          if (Math.abs(term) < 1e-14 * Math.abs(sum)) break;
        }
        return sum * Math.exp(-x + a * Math.log(x) - lgamma(a));
      }
      
      // Use continued fraction for large x
      let b = x + 1 - a;
      let c = 1 / 1e-30;
      let d = 1 / b;
      let h = d;
      
      for (let i = 1; i < 100; i++) {
        const an = -i * (i - a);
        b += 2;
        d = an * d + b;
        if (Math.abs(d) < 1e-30) d = 1e-30;
        c = b + an / c;
        if (Math.abs(c) < 1e-30) c = 1e-30;
        d = 1 / d;
        const delta = d * c;
        h *= delta;
        if (Math.abs(delta - 1) < 1e-14) break;
      }
      
      return 1 - Math.exp(-x + a * Math.log(x) - lgamma(a)) * h;
    }
    
    /**
     * t-distribution PDF
     * @param {number} t - Value
     * @param {number} df - Degrees of freedom
     * @returns {number} f(t; df)
     */
    function dt(t, df) {
      const coef = Math.exp(lgamma((df + 1) / 2) - lgamma(df / 2)) / Math.sqrt(df * Math.PI);
      return coef * Math.pow(1 + t * t / df, -(df + 1) / 2);
    }
    
    /**
     * t-distribution CDF
     * @param {number} t - Value
     * @param {number} df - Degrees of freedom
     * @returns {number} P(T ≤ t)
     */
    function pt(t, df) {
      if (df <= 0) return NaN;
      
      const x = df / (df + t * t);
      const prob = 0.5 * betainc(df / 2, 0.5, x);
      
      return t >= 0 ? 1 - prob : prob;
    }
    
    /**
     * t-distribution quantile
     * Newton-Raphson iteration from normal approximation
     * @param {number} p - Probability
     * @param {number} df - Degrees of freedom
     * @returns {number} t such that P(T ≤ t) = p
     */
    function qt(p, df) {
      if (p <= 0) return -Infinity;
      if (p >= 1) return Infinity;
      if (p === 0.5) return 0;
      if (df <= 0) return NaN;
      
      // Initial guess from normal distribution
      let x = qnorm(p);
      
      // Newton-Raphson refinement
      for (let i = 0; i < 20; i++) {
        const fx = pt(x, df) - p;
        const fpx = dt(x, df);
        if (Math.abs(fpx) < 1e-15) break;
        const dx = fx / fpx;
        x -= dx;
        if (Math.abs(dx) < 1e-10 * (1 + Math.abs(x))) break;
      }
      
      return x;
    }
    
    // Aliases for t-distribution functions
    const tQuantile = qt;
    const tCDF = pt;
    const chiSquareCDF = pchisq;
    
    /**
     * Chi-squared distribution CDF
     * @param {number} x - Value
     * @param {number} df - Degrees of freedom
     * @returns {number} P(X² ≤ x)
     */
    function pchisq(x, df) {
      if (x < 0) return 0;
      if (df <= 0) return NaN;
      return gammainc(df / 2, x / 2);
    }
    
    /**
     * Chi-squared distribution PDF
     * @param {number} x - Value
     * @param {number} df - Degrees of freedom
     * @returns {number} f(x; df)
     */
    function dchisq(x, df) {
      if (x < 0) return 0;
      if (df <= 0) return NaN;
      const k = df / 2;
      return Math.pow(x, k - 1) * Math.exp(-x / 2) / (Math.pow(2, k) * gamma(k));
    }
    
    /**
     * Chi-squared distribution quantile
     * Wilson-Hilferty approximation + Newton refinement
     * @param {number} p - Probability
     * @param {number} df - Degrees of freedom
     * @returns {number} x such that P(X² ≤ x) = p
     */
    function qchisq(p, df) {
      if (p <= 0) return 0;
      if (p >= 1) return Infinity;
      if (df <= 0) return NaN;
      
      // Wilson-Hilferty initial approximation
      const h = 2 / (9 * df);
      let x = df * Math.pow(1 - h + qnorm(p) * Math.sqrt(h), 3);
      x = Math.max(0.001, x);
      
      // Newton-Raphson refinement
      for (let i = 0; i < 20; i++) {
        const fx = pchisq(x, df) - p;
        const fpx = dchisq(x, df);
        if (Math.abs(fpx) < 1e-15) break;
        const dx = fx / fpx;
        x = Math.max(0.001, x - dx);
        if (Math.abs(dx) < 1e-10 * x) break;
      }
      
      return x;
    }
    
    // Standard normal random number generator (Box-Muller)
    // Note: Currently unused but retained for potential parametric bootstrap enhancement
    let _spareNormal = null;
    
    /**
     * Generate standard normal random variate
     * @returns {number} Z ~ N(0, 1)
     */
    function randn() {
      if (_spareNormal !== null) {
        const spare = _spareNormal;
        _spareNormal = null;
        return spare;
      }
      
      let u, v, s;
      do {
        u = Math.random() * 2 - 1;
        v = Math.random() * 2 - 1;
        s = u * u + v * v;
      } while (s >= 1 || s === 0);
      
      const mul = Math.sqrt(-2 * Math.log(s) / s);
      _spareNormal = v * mul;
      return u * mul;
    }
    
