    /**
     * Initialize tab navigation
     */
    function initializeTabs() {
      const tabBtns = document.querySelectorAll('.tab-btn');
      const tabPanels = document.querySelectorAll('.tab-panel');
      
      tabBtns.forEach(btn => {
        btn.addEventListener('click', () => {
          const targetTab = btn.dataset.tab;
          
          // Update button states
          tabBtns.forEach(b => b.classList.remove('tab-btn--active'));
          btn.classList.add('tab-btn--active');
          
          // Update panel visibility
          tabPanels.forEach(panel => {
            panel.classList.remove('tab-panel--active');
            if (panel.id === `panel-${targetTab}`) {
              panel.classList.add('tab-panel--active');
            }
          });
          
          // Tab-specific initialization
          if (targetTab === 'multioutcome') {
            populateOutcomeDictionary();
          }
          // TruthCert Verdict tab initialization
          if (targetTab === 'verdict' && typeof renderVerdictPanel === 'function') {
            renderVerdictPanel();
          }
          // HTA tab initialization - populate dropdowns
          if (targetTab === 'hta' && typeof populateHTADropdowns === 'function') {
            populateHTADropdowns();
          }
        });
      });
    }
    
