    /**
     * Rebuild table with current data type
     */
    function rebuildTable() {
      const tbody = document.getElementById('studyTableBody');
      const currentRowCount = tbody.children.length;
      
      // Update headers
      updateTableHeaders();
      
      // Clear and rebuild rows
      tbody.innerHTML = '';
      
      const rowCount = Math.max(5, currentRowCount);
      for (let i = 0; i < rowCount; i++) {
        addStudyRow();
      }
      
      updateDataSummary();
    }
    
    /**
     * Add a new study row to the table
     */
    function addStudyRow(data = null) {
      const tbody = document.getElementById('studyTableBody');
      const rowIndex = tbody.children.length + 1;
      const dataType = AppState.settings.dataType;
      const columns = getTableColumns(dataType);
      
      // Debug: show what data we're adding
      if (data) {
        // log.info('addStudyRow - data:', data);
      }
      
      const row = document.createElement('tr');
      
      // Row number cell
      let rowHTML = `<td class="font-mono text-secondary">${rowIndex}</td>`;
      
      // Data cells based on columns
      columns.forEach(col => {
        const value = data && data[col.key] !== undefined ? data[col.key] : '';
        const safeValue = col.type === 'text' ? sanitizeHTML(String(value)) : value;
        const stepAttr = col.step ? `step="${col.step}"` : '';
        const minAttr = col.type === 'number' && col.key !== 'yi' ? 'min="0"' : '';
        
        rowHTML += `<td><input type="${col.type}" class="input input--sm ${col.type === 'number' ? 'input--mono' : ''}" 
          placeholder="${col.placeholder}" ${minAttr} ${stepAttr} value="${safeValue}" data-key="${col.key}"></td>`;
      });
      
      // Remove button
      rowHTML += `<td><button class="btn btn--ghost btn--icon btn--sm remove-study-btn" title="Remove study" aria-label="Remove study">×</button></td>`;
      
      row.innerHTML = rowHTML;
      tbody.appendChild(row);
      
      // Bind remove button
      row.querySelector('.remove-study-btn').addEventListener('click', () => {
        row.remove();
        renumberRows();
        updateDataSummary();
      });
      
      // Bind input changes with validation
      row.querySelectorAll('input').forEach(input => {
        const validateRow = () => {
          validateStudyRow(row, dataType);
          updateDataSummary();
        };
        
        input.addEventListener('change', validateRow);
        input.addEventListener('input', validateRow);
      });
    }
    
    /**
     * Validate a study row based on data type
     */
    function validateStudyRow(row, dataType) {
      const inputs = row.querySelectorAll('input');
      
      // Reset styles
      inputs.forEach(inp => {
        inp.style.borderColor = '';
        inp.title = '';
      });
      row.style.background = '';
      row.title = '';
      
      if (dataType === 'binary') {
        const events_t = parseInt(inputs[1]?.value) || 0;
        const n_t = parseInt(inputs[2]?.value) || 0;
        const events_c = parseInt(inputs[3]?.value) || 0;
        const n_c = parseInt(inputs[4]?.value) || 0;
        
        if (n_t > 0 && events_t > n_t) {
          inputs[1].style.borderColor = 'var(--color-danger-500)';
          inputs[1].title = 'Events cannot exceed N';
        }
        if (n_c > 0 && events_c > n_c) {
          inputs[3].style.borderColor = 'var(--color-danger-500)';
          inputs[3].title = 'Events cannot exceed N';
        }
        
        if (n_t > 0 && n_c > 0) {
          const hasZeroCell = events_t === 0 || events_c === 0 || events_t === n_t || events_c === n_c;
          if (hasZeroCell) {
            row.style.background = 'rgba(245, 158, 11, 0.1)';
            row.title = 'Zero cell detected - continuity correction will be applied';
          }
        }
      } else if (dataType === 'continuous') {
        const sd_t = parseFloat(inputs[2]?.value) || 0;
        const sd_c = parseFloat(inputs[5]?.value) || 0;
        
        if (sd_t < 0) {
          inputs[2].style.borderColor = 'var(--color-danger-500)';
          inputs[2].title = 'SD must be positive';
        }
        if (sd_c < 0) {
          inputs[5].style.borderColor = 'var(--color-danger-500)';
          inputs[5].title = 'SD must be positive';
        }
      } else if (dataType === 'proportion') {
        const events = parseInt(inputs[1]?.value) || 0;
        const n = parseInt(inputs[2]?.value) || 0;
        
        if (n > 0 && events > n) {
          inputs[1].style.borderColor = 'var(--color-danger-500)';
          inputs[1].title = 'Events cannot exceed N';
        }
      }
    }
    
    /**
     * Renumber table rows after deletion
     */
    function renumberRows() {
      const tbody = document.getElementById('studyTableBody');
      Array.from(tbody.children).forEach((row, i) => {
        row.children[0].textContent = i + 1;
      });
    }
    
    /**
     * Debounce utility
     */
    function debounce(fn, delay) {
      let timeoutId;
      return function(...args) {
        clearTimeout(timeoutId);
        timeoutId = setTimeout(() => fn.apply(this, args), delay);
      };
    }
    
    /**
     * Update data summary statistics (internal)
     */
    function _updateDataSummary() {
      const studies = getStudyData();
      const validStudies = studies.filter(s => s.valid);
      const dataType = AppState.settings.dataType;
      
      document.getElementById('statStudies').textContent = validStudies.length;
      
      // Calculate total N based on data type
      let totalN = 0;
      switch (dataType) {
        case 'binary':
        case 'continuous':
          totalN = validStudies.reduce((sum, s) => sum + (s.n_t || 0) + (s.n_c || 0), 0);
          break;
        case 'hr':
          // For HR, show total events if available
          totalN = validStudies.reduce((sum, s) => sum + (s.n_events || 0), 0);
          break;
        case 'proportion':
          totalN = validStudies.reduce((sum, s) => sum + (s.n || 0), 0);
          break;
        case 'generic':
          totalN = validStudies.length;  // No N available, show study count
          break;
      }
      document.getElementById('statTotalN').textContent = totalN.toLocaleString();
      
      // Update status alert
      const alert = document.getElementById('dataStatusAlert');
      if (validStudies.length === 0) {
        alert.className = 'alert alert--info';
        alert.innerHTML = `
          <span class="alert__icon">ℹ️</span>
          <div class="alert__content">
            <div class="alert__text">Enter study data or load a demo dataset to begin.</div>
          </div>
        `;
      } else if (validStudies.length < 3) {
        alert.className = 'alert alert--warning';
        alert.innerHTML = `
          <span class="alert__icon">⚠️</span>
          <div class="alert__content">
            <div class="alert__text">${validStudies.length} valid studies. Minimum 3 studies recommended for reliable estimates.</div>
          </div>
        `;
      } else if (validStudies.length > 100) {
        // Warning for very large datasets
        alert.className = 'alert alert--warning';
        alert.innerHTML = `
          <span class="alert__icon">⚠️</span>
          <div class="alert__content">
            <div class="alert__text">${validStudies.length} studies detected. Large datasets may be slow. Consider using R/Python for >100 studies.</div>
          </div>
        `;
      } else {
        alert.className = 'alert alert--success';
        const nLabel = dataType === 'generic' || dataType === 'hr' ? (dataType === 'hr' ? 'total events' : 'studies') : 'total participants';
        alert.innerHTML = `
          <span class="alert__icon">✓</span>
          <div class="alert__content">
            <div class="alert__text">${validStudies.length} valid studies${totalN > 0 ? ', ' + totalN.toLocaleString() + ' ' + nLabel : ''}. Ready for analysis.</div>
          </div>
        `;
      }
      
      AppState.studies = validStudies;
    }
    
    // Debounced version for input events (prevents excessive updates during typing)
    const updateDataSummary = debounce(_updateDataSummary, 150);
    
    /**
     * Get study data from table inputs
     * @returns {object[]} Array of study objects
     */
    function getStudyData() {
      const tbody = document.getElementById('studyTableBody');
      const studies = [];
      const dataType = AppState.settings.dataType;
      const columns = getTableColumns(dataType);
      
      Array.from(tbody.children).forEach((row, i) => {
        const inputs = row.querySelectorAll('input');
        
        const study = { index: i + 1 };
        
        // Extract values based on column configuration
        columns.forEach((col, j) => {
          const input = inputs[j];
          if (!input) return;
          
          if (col.type === 'text') {
            study[col.key] = input.value.trim() || (col.key === 'name' ? `Study ${i + 1}` : '');
          } else {
            study[col.key] = col.step === 'any' ? parseFloat(input.value) : parseInt(input.value);
            if (isNaN(study[col.key])) study[col.key] = col.key.includes('mean') || col.key === 'yi' ? NaN : 0;
          }
        });
        
        // Validate based on data type
        switch (dataType) {
          case 'binary':
            study.valid = study.n_t > 0 && study.n_c > 0 && 
                          study.events_t <= study.n_t && study.events_c <= study.n_c;
            break;
          case 'continuous':
            study.valid = study.n_t > 0 && study.n_c > 0 && 
                          study.sd_t > 0 && study.sd_c > 0 &&
                          !isNaN(study.mean_t) && !isNaN(study.mean_c);
            break;
          case 'hr':
            study.valid = study.hr > 0 && study.ci_lower > 0 && study.ci_upper > 0 &&
                          study.ci_lower < study.hr && study.hr < study.ci_upper;
            break;
          case 'proportion':
            study.valid = study.n > 0 && study.events <= study.n && study.events >= 0;
            break;
          case 'generic':
            study.valid = !isNaN(study.yi) && study.vi > 0;
            break;
          default:
            study.valid = false;
        }
        
        studies.push(study);
      });
      
      return studies;
    }
    
