                <p style="margin-top: var(--space-2);"><strong>I² 95% CI:</strong> ${r.het && r.het.I2_ci ? `${r.het.I2_ci.lower.toFixed(1)}% – ${r.het.I2_ci.upper.toFixed(1)}%` : 'N/A'}</p>
