    /**
     * Generate Methods Section
     * Brief: ~80 words, Standard: ~200 words, Detailed: ~350 words, Extended: ~500 words
     */
    function generateMethodsSection(r, settings) {
      var length = (settings && settings.length) || 'standard';
      var measure = r.measure || 'OR';
      var method = AppState.settings.tau2Method || 'REML';
      var hksj = AppState.settings.hksj;
      var k = r.k || 0;
      
      var measureNames = {
        'OR': 'odds ratios', 'RR': 'risk ratios', 'HR': 'hazard ratios',
        'RD': 'risk differences', 'SMD': 'standardized mean differences', 'MD': 'mean differences'
      };
      var measureName = measureNames[measure] || 'effect sizes';
      
      var methodNames = {
        'REML': 'restricted maximum likelihood (REML)',
        'DL': 'DerSimonian-Laird',
        'PM': 'Paule-Mandel',
        'ML': 'maximum likelihood',
        'EB': 'empirical Bayes',
        'SJ': 'Sidik-Jonkman',
        'HE': 'Hedges'
      };
      var methodFullName = methodNames[method] || method;
      
      var text = '<h3>Statistical Analysis</h3>';
      
      // === BRIEF (~80 words) ===
      if (length === 'brief') {
        text += '<p>We conducted a random-effects meta-analysis of ' + k + ' studies. ';
        text += 'Effect sizes were expressed as ' + measureName + '. ';
        text += 'Between-study variance (tau-squared) was estimated using the ' + method + ' method. ';
        text += 'Heterogeneity was assessed using I-squared and Cochran Q test. ';
        text += 'Publication bias was evaluated using funnel plots and Egger test.</p>';
        return text;
      }
      
      // === STANDARD (~200 words) ===
      text += '<p>We performed a pairwise meta-analysis following established methodological guidelines. ';
      text += 'Effect sizes were expressed as ' + measureName;
      if (measure !== 'RD' && measure !== 'MD') {
        text += ' on the natural logarithm scale for analysis, then back-transformed for presentation';
      }
      text += '. ';
      text += 'A random-effects model was used to account for expected clinical and methodological heterogeneity across studies. ';
      text += 'Between-study variance (tau-squared) was estimated using the ' + methodFullName + ' estimator. ';
      if (hksj) {
        text += 'Confidence intervals were calculated using the Hartung-Knapp-Sidik-Jonkman (HKSJ) adjustment, which provides improved coverage when the number of studies is small. ';
      } else {
        text += 'Confidence intervals were calculated using the Wald-type method with normal distribution approximation. ';
      }
      text += '</p>';
      
      text += '<p>Heterogeneity was quantified using the I-squared statistic (proportion of variability due to heterogeneity rather than sampling error), ';
      text += 'tau-squared (absolute between-study variance), and Cochran Q test. ';
      text += 'We calculated 95% prediction intervals to estimate the range of effects expected in future similar settings. ';
      text += 'Publication bias was assessed visually using funnel plots and statistically using Egger regression test. ';
      text += 'Sensitivity analyses included leave-one-out analysis to identify influential studies. ';
      text += 'All analyses were conducted using Pairwise Pro v2.2, with results validated against the metafor package in R.</p>';
      
      if (length === 'standard') {
        return text;
      }
      
      // === DETAILED (~350 words) - adds more specifics ===
      text += '<p>For binary outcomes, we extracted the number of events and total participants in each treatment arm. ';
      if (r.studies && r.studies.some(function(s) { return s.events_t === 0 || s.events_c === 0; })) {
        text += 'Studies with zero events in one or both arms were handled using continuity correction (adding 0.5 to all cells). ';
      }
      text += 'We interpreted I-squared values of less than 25% as low, 25-50% as moderate, 50-75% as substantial, and greater than 75% as high heterogeneity, ';
      text += 'while acknowledging that clinical interpretation depends on context. ';
      text += 'We also examined tau (square root of tau-squared) which represents the standard deviation of true effects across studies.</p>';
      
      text += '<p>Additional publication bias assessments included Peters test (which is less affected by heterogeneity for binary outcomes), ';
      text += 'Begg rank correlation test, and trim-and-fill analysis to estimate the number of potentially missing studies and calculate bias-adjusted estimates. ';
      text += 'We applied the PET-PEESE conditional estimator as a sensitivity analysis for small-study effects. ';
      text += 'Influence diagnostics were examined using Cook distance and DFBETAS to identify outlying observations.</p>';
      
      if (length === 'detailed') {
        return text;
      }
      
      // === EXTENDED (~500 words) - adds DDMA and cross-disciplinary ===
      text += '<p>Beyond traditional null hypothesis significance testing, we employed a decision-driven meta-analysis (DDMA) framework. ';
      text += 'We calculated posterior probabilities of clinically meaningful effects using both the confidence distribution (for the population-average effect) ';
      text += 'and predictive distribution (for effects expected in future clinical settings). ';
      var mcidPct = AppState.settings.mcid ? Math.round((1 - Math.exp(-AppState.settings.mcid)) * 100) : 15;
      text += 'The minimum clinically important difference (MCID) threshold was set at a ' + mcidPct + '% relative change. ';
      text += 'This approach provides clinicians with more actionable information than dichotomous p-value interpretation.</p>';
      
      text += '<p>We also applied several cross-disciplinary methodological approaches to enhance robustness: ';
      text += '(1) the Particle Data Group (PDG) scale factor method from high-energy physics to inflate confidence intervals when studies disagree more than expected by chance; ';
      text += '(2) winner\'s curse correction methods adapted from genome-wide association studies to estimate potential effect size inflation due to selection; ';
      text += '(3) tension statistics to detect hidden pairwise disagreements between studies even when global heterogeneity tests are non-significant; ';
      text += '(4) power calculations for the Q test to assess whether low I-squared reflects true homogeneity or insufficient statistical power; ';
      text += 'and (5) E-values to assess sensitivity to unmeasured confounding. ';
      text += 'Statistical significance was set at alpha = 0.05 (two-sided).</p>';

      return text;
    }

    /**
     * Generate TruthCert Verdict Report Section
     */
    function generateVerdictReportSection() {
      const v = AppState.verdict;
      if (!v) return '<p>No verdict available. Run analysis first.</p>';

      let html = '<h3>TruthCert Evidence Assessment</h3>';

      // Verdict summary
      html += '<p><strong>Overall Verdict:</strong> ' + (v.verdict || 'Not assessed') + '</p>';
      html += '<p><strong>HTA Tier:</strong> ' + (v.tier || 'N/A') + '</p>';

      // Severity score
      if (v.severity) {
        html += '<p><strong>Severity Score:</strong> ' + v.severity.total + '/13</p>';
        if (v.severity.triggers && v.severity.triggers.length > 0) {
          html += '<p><strong>Active Triggers:</strong> ' + v.severity.triggers.join(', ') + '</p>';
        }
      }

      // Threat ledger summary
      if (AppState.threatLedger && AppState.threatLedger.length > 0) {
        const threats = AppState.threatLedger.filter(t => t.status === 'fail');
        const passes = AppState.threatLedger.filter(t => t.status === 'pass');
        html += '<p><strong>Threat Assessment:</strong> ' + passes.length + ' passed, ' + threats.length + ' failed out of ' + AppState.threatLedger.length + ' checks.</p>';
        if (threats.length > 0) {
          html += '<ul>';
          threats.forEach(t => {
            html += '<li>' + t.label + ': ' + (t.detail || 'Failed') + '</li>';
          });
          html += '</ul>';
        }
      }

      // GRADE assessment
      if (AppState.grade) {
        html += '<h4>GRADE Certainty Assessment</h4>';
        html += '<p><strong>Overall Certainty:</strong> ' + (AppState.grade.overall || 'Not assessed') + '</p>';
        if (AppState.grade.domains) {
          html += '<ul>';
          Object.entries(AppState.grade.domains).forEach(([domain, rating]) => {
            html += '<li><strong>' + domain + ':</strong> ' + (rating.rating || 'N/A') + (rating.reason ? ' - ' + rating.reason : '') + '</li>';
          });
          html += '</ul>';
        }
      }

      return html;
    }

    /**
     * Generate HTA Report Section
     */
    function generateHTAReportSection() {
      const hta = AppState.hta;
      if (!hta || !hta.results) return '<p>No HTA analysis available. Configure and run HTA analysis first.</p>';

      const r = hta.results;
      const config = hta.config || {};
      const currency = config.currency || { symbol: '$', code: 'USD' };

      let html = '<h3>Health Technology Assessment (S14-HTA+)</h3>';

      // Configuration summary
      html += '<h4>Analysis Parameters</h4>';
      html += '<ul>';
      html += '<li><strong>Country:</strong> ' + (config.country || 'Not specified') + '</li>';
      html += '<li><strong>Intervention:</strong> ' + (config.intervention?.name || 'Not specified') + ' (' + currency.symbol + (config.intervention?.cost || 0).toLocaleString() + ')</li>';
      html += '<li><strong>Comparator:</strong> ' + (config.comparator?.name || 'Standard care') + ' (' + currency.symbol + (config.comparator?.cost || 0).toLocaleString() + ')</li>';
      html += '<li><strong>Time Horizon:</strong> ' + (config.horizon || 10) + ' years</li>';
      html += '<li><strong>Discount Rate:</strong> ' + ((config.discountRate || 0.035) * 100).toFixed(1) + '%</li>';
      html += '<li><strong>WTP Threshold:</strong> ' + currency.symbol + (config.wtp || 50000).toLocaleString() + '/QALY</li>';
      html += '</ul>';

      // Economic results
      html += '<h4>Economic Results</h4>';
      html += '<ul>';
      if (r.icer !== undefined && r.icer !== null) {
        html += '<li><strong>ICER:</strong> ' + (isFinite(r.icer) ? currency.symbol + r.icer.toLocaleString(undefined, {maximumFractionDigits: 0}) + '/QALY' : 'Dominant') + '</li>';
      }
      if (r.nmb !== undefined) {
        html += '<li><strong>Net Monetary Benefit:</strong> ' + currency.symbol + r.nmb.toLocaleString(undefined, {maximumFractionDigits: 0}) + '</li>';
      }
      if (r.incrementalCost !== undefined) {
        html += '<li><strong>Incremental Cost:</strong> ' + currency.symbol + r.incrementalCost.toLocaleString(undefined, {maximumFractionDigits: 0}) + '</li>';
      }
      if (r.incrementalQALY !== undefined) {
        html += '<li><strong>Incremental QALYs:</strong> ' + r.incrementalQALY.toFixed(3) + '</li>';
      }
      html += '</ul>';

      // Recommendation
      if (r.recommendation) {
        html += '<h4>Recommendation</h4>';
        html += '<p><strong>Class:</strong> ' + r.recommendation.class + '</p>';
        html += '<p><strong>Rationale:</strong> ' + r.recommendation.rationale + '</p>';
      }

      return html;
    }

    /**
     * Generate Results Section
     * Brief: ~100 words, Standard: ~300 words, Detailed: ~500 words, Extended: ~700 words
     */
    function generateResultsSection(r, settings) {
      if (!r || !r.pooled) return '<p>No results available.</p>';
      
      var length = (settings && settings.length) || 'standard';
      var sections = (settings && settings.sections) || { results: true, heterogeneity: true, bias: true, sensitivity: true, ddma: true };
      var measure = r.measure || 'OR';
      var isRatio = (measure !== 'RD' && measure !== 'MD');
      
      // Safe number formatting
      function fmt(val, dec) {
        if (val === undefined || val === null || isNaN(val)) return 'N/A';
        return Number(val).toFixed(dec === undefined ? 2 : dec);
      }
      
      var effect = isRatio ? Math.exp(r.pooled.theta) : r.pooled.theta;
      var ci_lower = isRatio ? Math.exp(r.pooled.ci_lower) : r.pooled.ci_lower;
      var ci_upper = isRatio ? Math.exp(r.pooled.ci_upper) : r.pooled.ci_upper;
      
      // Prediction intervals
      var pi_lower = null, pi_upper = null;
      if (r.pi && r.pi.standard) {
        pi_lower = isRatio ? Math.exp(r.pi.standard.lower) : r.pi.standard.lower;
        pi_upper = isRatio ? Math.exp(r.pi.standard.upper) : r.pi.standard.upper;
      }
      
      var measureNamesShort = { 'OR': 'OR', 'RR': 'RR', 'HR': 'HR', 'RD': 'RD', 'SMD': 'SMD', 'MD': 'MD' };
      var measureNamesLong = {
        'OR': 'odds ratio', 'RR': 'risk ratio', 'HR': 'hazard ratio',
        'RD': 'risk difference', 'SMD': 'standardized mean difference', 'MD': 'mean difference'
      };
      var measureShort = measureNamesShort[measure] || measure;
      var measureLong = measureNamesLong[measure] || 'effect size';
      
      // Calculate totals
      var totalN = 0, totalEvents = 0;
      if (r.studies && r.studies.length) {
        for (var i = 0; i < r.studies.length; i++) {
          var s = r.studies[i];
          totalN += (s.n_t || 0) + (s.n_c || 0);
          totalEvents += (s.events_t || 0) + (s.events_c || 0);
        }
      }
      
      var pVal = 'N/A';
      if (r.pooled.p_value !== undefined && r.pooled.p_value !== null) {
        pVal = r.pooled.p_value < 0.001 ? '<0.001' : fmt(r.pooled.p_value, 4);
      }
      
      var I2 = (r.het && r.het.I2 !== undefined) ? fmt(r.het.I2, 1) : 'N/A';
      var tau2 = (r.tau2 !== undefined) ? fmt(r.tau2, 4) : 'N/A';
      var tau = (r.tau2 !== undefined) ? fmt(Math.sqrt(r.tau2), 3) : 'N/A';
      var Q = (r.het && r.het.Q !== undefined) ? fmt(r.het.Q, 2) : 'N/A';
      var df = (r.het && r.het.df !== undefined) ? r.het.df : (r.k - 1);
      var pQ = (r.het && r.het.p_Q !== undefined) ? (r.het.p_Q < 0.001 ? '<0.001' : fmt(r.het.p_Q, 4)) : 'N/A';
      
      var hetLevel = 'low';
      if (r.het && r.het.I2 !== undefined) {
        if (r.het.I2 > 75) hetLevel = 'high';
        else if (r.het.I2 > 50) hetLevel = 'substantial';
        else if (r.het.I2 > 25) hetLevel = 'moderate';
      }
      
      var text = '';
      
      // === MAIN RESULTS ===
      if (sections.results !== false) {
        text += '<h3>Main Results</h3>';
        
        // Brief version
        if (length === 'brief') {
          text += '<p>' + r.k + ' studies (N=' + totalN.toLocaleString() + ') were included. ';
          text += 'Pooled ' + measureShort + ' = ' + fmt(effect) + ' (95% CI: ' + fmt(ci_lower) + '-' + fmt(ci_upper) + '; p=' + pVal + '). ';
          text += 'I-squared = ' + I2 + '%. ';
          if (r.egger) {
            text += 'Egger test p=' + (r.egger.p_value !== undefined ? (r.egger.p_value < 0.001 ? '<0.001' : fmt(r.egger.p_value, 3)) : 'N/A') + '.</p>';
          }
          return text;
        }
        
        // Standard and above
        text += '<p>A total of <strong>' + r.k + ' studies</strong> met inclusion criteria, comprising ' + totalN.toLocaleString() + ' participants';
        if (totalEvents > 0) {
          text += ' with ' + totalEvents.toLocaleString() + ' events';
        }
        text += '. ';
        
        if (length !== 'brief' && length !== 'standard') {
          // Get year range if available
          var years = [];
          if (r.studies) {
            for (var j = 0; j < r.studies.length; j++) {
              if (r.studies[j].year) years.push(r.studies[j].year);
            }
          }
          if (years.length > 0) {
            text += 'Studies were published between ' + Math.min.apply(null, years) + ' and ' + Math.max.apply(null, years) + '. ';
          }
        }
        text += '</p>';
        
        text += '<p>The pooled ' + measureLong + ' was <strong>' + measureShort + ' = ' + fmt(effect) + '</strong> ';
        text += '(95% CI: ' + fmt(ci_lower) + ' to ' + fmt(ci_upper) + '; p=' + pVal + ')';
        
        var sig = r.pooled.p_value !== undefined && r.pooled.p_value < 0.05;
        if (sig) {
          text += ', indicating a statistically significant ';
          if (isRatio) {
            text += (effect < 1) ? 'reduction' : 'increase';
          } else {
            text += 'difference';
          }
        } else {
          text += ', which did not reach statistical significance';
        }
        text += '. ';
        
        // Relative risk reduction
        if (isRatio && effect !== 1) {
          var rrr = Math.abs((1 - effect) * 100);
          text += 'This corresponds to a <strong>' + fmt(rrr, 0) + '% relative ' + (effect < 1 ? 'reduction' : 'increase') + '</strong> in risk. ';
        }
        text += '</p>';
        
        // Prediction interval
        if (pi_lower !== null && pi_upper !== null) {
          text += '<p>The 95% prediction interval ranged from ' + fmt(pi_lower) + ' to ' + fmt(pi_upper);
          var piCrossesNull = (isRatio && pi_lower < 1 && pi_upper > 1) || (!isRatio && pi_lower < 0 && pi_upper > 0);
          if (piCrossesNull) {
            text += ', crossing the null value, indicating that effects in future similar settings may vary from beneficial to harmful';
          } else {
            text += ', suggesting consistent ' + (isRatio ? (pi_upper < 1 ? 'benefit' : 'harm') : (pi_upper < 0 ? 'benefit' : 'harm')) + ' across settings';
          }
          text += '.</p>';
        }
      }
      
      // === HETEROGENEITY ===
      if (sections.heterogeneity !== false) {
        text += '<h3>Heterogeneity</h3>';
        text += '<p>Statistical heterogeneity was <strong>' + hetLevel + '</strong>. ';
        text += 'The I-squared statistic was ' + I2 + '%';
        if (r.het && r.het.I2_ci) {
          text += ' (95% CI: ' + fmt(r.het.I2_ci.lower, 1) + '% to ' + fmt(r.het.I2_ci.upper, 1) + '%)';
        }
        text += ', indicating that ';
        if (r.het && r.het.I2 !== undefined) {
          if (r.het.I2 < 25) text += 'most of the observed variance was due to sampling error rather than true differences between studies';
          else if (r.het.I2 < 50) text += 'a moderate proportion of observed variance reflected true differences between studies';
          else text += 'the majority of observed variance reflected true differences between studies';
        }
        text += '. ';
        
        text += 'The between-study variance was tau-squared = ' + tau2;
        if (isRatio && r.tau2 !== undefined && r.tau2 > 0) {
          var typicalVar = Math.round((Math.exp(Math.sqrt(r.tau2)) - 1) * 100);
          text += ' (tau = ' + tau + ', corresponding to approximately ' + typicalVar + '% typical variation in effects on the ratio scale)';
        }
        text += '. ';
        
        text += 'Cochran Q test: Q = ' + Q + ', df = ' + df + ', p=' + pQ;
        if (r.het && r.het.p_Q !== undefined) {
          text += (r.het.p_Q < 0.10) ? ' (significant)' : ' (not significant)';
        }
        text += '.</p>';
        
        // Extended: add H-squared
        if (length === 'detailed' || length === 'extended') {
          if (r.het && r.het.Q !== undefined && df > 0) {
            var H2 = r.het.Q / df;
            text += '<p>The H-squared statistic was ' + fmt(H2, 2) + ', suggesting that observed variance was ' + fmt(H2, 1) + ' times larger than expected under homogeneity.</p>';
          }
        }
      }
      
      // === PUBLICATION BIAS ===
      if (sections.bias !== false && r.egger) {
        text += '<h3>Publication Bias</h3>';
        
        var eggerP = (r.egger.p_value !== undefined) ? (r.egger.p_value < 0.001 ? '<0.001' : fmt(r.egger.p_value, 4)) : 'N/A';
        var eggerInt = (r.egger.intercept !== undefined) ? fmt(r.egger.intercept, 3) : 'N/A';
        var eggerSE = (r.egger.se !== undefined) ? fmt(r.egger.se, 3) : 'N/A';
        var eggerSig = r.egger.p_value !== undefined && r.egger.p_value < 0.10;
        
        text += '<p>Visual inspection of the funnel plot ' + (eggerSig ? 'suggested asymmetry' : 'did not reveal obvious asymmetry') + '. ';
        text += 'Egger regression test ' + (eggerSig ? 'was significant' : 'was not significant') + ' ';
        text += '(intercept = ' + eggerInt + ', SE = ' + eggerSE + ', p=' + eggerP + '), ';
        text += (eggerSig ? 'suggesting possible publication bias or small-study effects' : 'providing no strong evidence of publication bias') + '. ';
        
        if (length !== 'brief' && r.peters) {
          var petersP = (r.peters.p_value !== undefined) ? (r.peters.p_value < 0.001 ? '<0.001' : fmt(r.peters.p_value, 4)) : 'N/A';
          text += 'Peters test (less affected by heterogeneity): p=' + petersP + '. ';
        }
        
        if (r.begg && (length === 'detailed' || length === 'extended')) {
          var beggTau = (r.begg.tau !== undefined) ? fmt(r.begg.tau, 3) : 'N/A';
          var beggP = (r.begg.p_value !== undefined) ? (r.begg.p_value < 0.001 ? '<0.001' : fmt(r.begg.p_value, 4)) : 'N/A';
          text += 'Begg rank correlation: tau = ' + beggTau + ', p=' + beggP + '. ';
        }
        text += '</p>';
        
        // Trim and fill
        if (r.trimfill) {
          text += '<p>Trim-and-fill analysis imputed ' + (r.trimfill.k0_imputed || 0) + ' potentially missing studies';
          if (r.trimfill.k0_imputed > 0 && r.trimfill.adjusted) {
            var adjEffect = isRatio ? Math.exp(r.trimfill.adjusted.theta) : r.trimfill.adjusted.theta;
            var adjLower = isRatio ? Math.exp(r.trimfill.adjusted.ci_lower) : r.trimfill.adjusted.ci_lower;
            var adjUpper = isRatio ? Math.exp(r.trimfill.adjusted.ci_upper) : r.trimfill.adjusted.ci_upper;
            text += ', yielding an adjusted estimate of ' + measureShort + ' = ' + fmt(adjEffect) + ' (95% CI: ' + fmt(adjLower) + ' to ' + fmt(adjUpper) + ')';
          }
          text += '.</p>';
        }
      }
      
      // === SENSITIVITY ANALYSES ===
      if (sections.sensitivity !== false && (length === 'detailed' || length === 'extended')) {
        text += '<h3>Sensitivity Analyses</h3>';
        text += '<p>Leave-one-out analysis was performed to assess the influence of individual studies on the pooled estimate. ';
        
        if (r.loo && r.loo.studies) {
          var maxChange = 0, maxStudy = '';
          for (var m = 0; m < r.loo.studies.length; m++) {
            var looStudy = r.loo.studies[m];
            if (looStudy.change_pct !== undefined && Math.abs(looStudy.change_pct) > Math.abs(maxChange)) {
              maxChange = looStudy.change_pct;
              maxStudy = looStudy.name || ('Study ' + (m + 1));
            }
          }
          if (maxStudy) {
            text += 'The most influential study was ' + maxStudy + ', whose removal changed the estimate by ' + fmt(Math.abs(maxChange), 1) + '%. ';
          }
        }
        
        text += 'Results were robust to the removal of any single study.</p>';
      }
      
      // === DDMA / DECISION ANALYSIS ===
      if (sections.ddma !== false && (length === 'detailed' || length === 'extended') && r.ddma) {
        text += '<h3>Decision-Driven Analysis</h3>';
        text += '<p>Using the confidence distribution, the probability of any beneficial effect (' + measureShort + ' ';
        text += (isRatio ? '<1' : '<0') + ') was ';
        var pBenefit = r.ddma.P_benefit_conf !== undefined ? fmt(r.ddma.P_benefit_conf * 100, 1) : 'N/A';
        text += pBenefit + '%. ';
        
        if (r.ddma.P_mcid_conf !== undefined) {
          text += 'The probability of exceeding the minimum clinically important difference was ' + fmt(r.ddma.P_mcid_conf * 100, 1) + '%. ';
        }
        
        if (r.ddma.P_benefit_pred !== undefined) {
          text += 'Using the predictive distribution (accounting for heterogeneity), the probability that a future similar setting would show benefit was ' + fmt(r.ddma.P_benefit_pred * 100, 1) + '%.</p>';
        } else {
          text += '</p>';
        }
      }
      
      return text;
    }
    
    /**
     * Generate PRISMA Checklist
     */
    function generatePRISMAChecklist(r) {
      return `
        <div class="card" style="margin-top: var(--space-6);">
          <div class="card__header">
            <h3 class="card__title">✅ PRISMA 2020 Checklist (Synthesis Methods)</h3>
            <button class="btn btn--ghost btn--sm" onclick="copyReportSection('prismaChecklist')">📋 Copy</button>
          </div>
          <div class="card__body">
            <div id="prismaChecklist" style="background: var(--surface-base); padding: var(--space-4); border-radius: var(--radius-lg);">
              <table style="width: 100%; border-collapse: collapse; font-size: var(--text-sm);">
                <thead>
                  <tr style="background: var(--surface-secondary);">
                    <th style="padding: var(--space-2); text-align: left; border-bottom: 2px solid var(--border-muted);">Item</th>
                    <th style="padding: var(--space-2); text-align: left; border-bottom: 2px solid var(--border-muted);">Checklist Item</th>
                    <th style="padding: var(--space-2); text-align: center; border-bottom: 2px solid var(--border-muted);">Status</th>
                  </tr>
                </thead>
                <tbody>
                  <tr>
                    <td style="padding: var(--space-2); border-bottom: 1px solid var(--border-muted);">13a</td>
                    <td style="padding: var(--space-2); border-bottom: 1px solid var(--border-muted);">Describe the processes used to decide which studies were eligible for each synthesis</td>
                    <td style="padding: var(--space-2); text-align: center; border-bottom: 1px solid var(--border-muted);">✓ Reported</td>
                  </tr>
                  <tr>
                    <td style="padding: var(--space-2); border-bottom: 1px solid var(--border-muted);">13b</td>
                    <td style="padding: var(--space-2); border-bottom: 1px solid var(--border-muted);">Describe any methods required to prepare the data for synthesis</td>
                    <td style="padding: var(--space-2); text-align: center; border-bottom: 1px solid var(--border-muted);">✓ Effect measure: ${r.measure}</td>
                  </tr>
                  <tr>
                    <td style="padding: var(--space-2); border-bottom: 1px solid var(--border-muted);">13c</td>
                    <td style="padding: var(--space-2); border-bottom: 1px solid var(--border-muted);">Describe any methods used to tabulate or visually display results</td>
                    <td style="padding: var(--space-2); text-align: center; border-bottom: 1px solid var(--border-muted);">✓ Forest plot</td>
                  </tr>
                  <tr>
                    <td style="padding: var(--space-2); border-bottom: 1px solid var(--border-muted);">13d</td>
                    <td style="padding: var(--space-2); border-bottom: 1px solid var(--border-muted);">Describe any methods used to synthesize results</td>
                    <td style="padding: var(--space-2); text-align: center; border-bottom: 1px solid var(--border-muted);">✓ RE model (${AppState.settings.tau2Method})</td>
                  </tr>
                  <tr>
                    <td style="padding: var(--space-2); border-bottom: 1px solid var(--border-muted);">13e</td>
                    <td style="padding: var(--space-2); border-bottom: 1px solid var(--border-muted);">Describe any methods used to explore possible causes of heterogeneity</td>
                    <td style="padding: var(--space-2); text-align: center; border-bottom: 1px solid var(--border-muted);">✓ I², τ², Q-test, PI</td>
                  </tr>
                  <tr>
                    <td style="padding: var(--space-2); border-bottom: 1px solid var(--border-muted);">13f</td>
                    <td style="padding: var(--space-2); border-bottom: 1px solid var(--border-muted);">Describe any sensitivity analyses conducted</td>
                    <td style="padding: var(--space-2); text-align: center; border-bottom: 1px solid var(--border-muted);">✓ Leave-one-out, τ² estimators</td>
                  </tr>
                  <tr>
                    <td style="padding: var(--space-2); border-bottom: 1px solid var(--border-muted);">14</td>
                    <td style="padding: var(--space-2); border-bottom: 1px solid var(--border-muted);">Describe any methods used to assess risk of bias due to missing results</td>
                    <td style="padding: var(--space-2); text-align: center; border-bottom: 1px solid var(--border-muted);">✓ Egger, Peters, T&F, PET-PEESE</td>
                  </tr>
                  <tr>
                    <td style="padding: var(--space-2); border-bottom: 1px solid var(--border-muted);">15</td>
                    <td style="padding: var(--space-2); border-bottom: 1px solid var(--border-muted);">Describe any methods used to assess certainty in the body of evidence</td>
                    <td style="padding: var(--space-2); text-align: center; border-bottom: 1px solid var(--border-muted);">✓ DDMA probabilities</td>
                  </tr>
                </tbody>
              </table>
            </div>
          </div>
        </div>
      `;
    }
    
    /**
     * Generate GRADE Summary
     */
    function generateGRADESummary(r) {
      // Determine GRADE factors
      const riskOfBias = 'Not assessed';  // Would need RoB data
      const inconsistency = r.het.I2 > 75 ? 'Serious (-1)' : r.het.I2 > 50 ? 'Moderate' : 'Not serious';
      const indirectness = 'Not assessed';  // Would need PICO data
      const imprecision = r.pooled.ci_upper / r.pooled.ci_lower > 2 ? 'Serious (-1)' : 'Not serious';
      const publicationBias = r.egger.p_value < 0.10 ? 'Suspected (-1)' : 'Undetected';
      
      return `
        <div class="card" style="margin-top: var(--space-6);">
          <div class="card__header">
            <h3 class="card__title">📊 GRADE Evidence Profile</h3>
            <button class="btn btn--ghost btn--sm" onclick="copyReportSection('gradeProfile')">📋 Copy</button>
          </div>
          <div class="card__body">
            <div id="gradeProfile" style="background: var(--surface-base); padding: var(--space-4); border-radius: var(--radius-lg);">
              <table style="width: 100%; border-collapse: collapse; font-size: var(--text-sm);">
                <thead>
                  <tr style="background: var(--surface-secondary);">
                    <th style="padding: var(--space-2); text-align: left; border-bottom: 2px solid var(--border-muted);">Domain</th>
                    <th style="padding: var(--space-2); text-align: left; border-bottom: 2px solid var(--border-muted);">Assessment</th>
                    <th style="padding: var(--space-2); text-align: left; border-bottom: 2px solid var(--border-muted);">Basis</th>
                  </tr>
                </thead>
                <tbody>
                  <tr>
                    <td style="padding: var(--space-2); border-bottom: 1px solid var(--border-muted);">Risk of bias</td>
                    <td style="padding: var(--space-2); border-bottom: 1px solid var(--border-muted);">${riskOfBias}</td>
                    <td style="padding: var(--space-2); border-bottom: 1px solid var(--border-muted);">Requires RoB assessment data</td>
                  </tr>
                  <tr>
                    <td style="padding: var(--space-2); border-bottom: 1px solid var(--border-muted);">Inconsistency</td>
                    <td style="padding: var(--space-2); border-bottom: 1px solid var(--border-muted);">${inconsistency}</td>
                    <td style="padding: var(--space-2); border-bottom: 1px solid var(--border-muted);">I² = ${r.het && r.het.I2 !== undefined ? r.het.I2.toFixed(0) : 'N/A'}%, PI crosses null: ${r.pi && r.pi.standard ? ((r.pi.standard.lower < 0 && r.pi.standard.upper > 0) || (Math.exp(r.pi.standard.lower) < 1 && Math.exp(r.pi.standard.upper) > 1) ? 'Yes' : 'No') : 'N/A'}</td>
                  </tr>
                  <tr>
                    <td style="padding: var(--space-2); border-bottom: 1px solid var(--border-muted);">Indirectness</td>
                    <td style="padding: var(--space-2); border-bottom: 1px solid var(--border-muted);">${indirectness}</td>
                    <td style="padding: var(--space-2); border-bottom: 1px solid var(--border-muted);">Requires PICO assessment</td>
                  </tr>
                  <tr>
                    <td style="padding: var(--space-2); border-bottom: 1px solid var(--border-muted);">Imprecision</td>
                    <td style="padding: var(--space-2); border-bottom: 1px solid var(--border-muted);">${imprecision}</td>
                    <td style="padding: var(--space-2); border-bottom: 1px solid var(--border-muted);">CI width ratio: ${r.pooled && r.pooled.ci_upper !== undefined && r.pooled.ci_lower !== undefined ? (Math.exp(r.pooled.ci_upper) / Math.exp(r.pooled.ci_lower)).toFixed(2) : 'N/A'}</td>
                  </tr>
                  <tr>
                    <td style="padding: var(--space-2); border-bottom: 1px solid var(--border-muted);">Publication bias</td>
                    <td style="padding: var(--space-2); border-bottom: 1px solid var(--border-muted);">${publicationBias}</td>
                    <td style="padding: var(--space-2); border-bottom: 1px solid var(--border-muted);">Egger p = ${r.egger && r.egger.p_value !== undefined ? r.egger.p_value.toFixed(3) : 'N/A'}, T&F: ${r.trimfill ? r.trimfill.k0_imputed : 'N/A'} imputed</td>
                  </tr>
                </tbody>
              </table>
              
              <div style="margin-top: var(--space-4); padding: var(--space-3); background: var(--surface-secondary); border-radius: var(--radius-md);">
                <strong>Summary of Findings:</strong><br>
                ${r.k} studies, N = ${r.studies.reduce((sum, s) => sum + (s.n_t || 0) + (s.n_c || 0), 0).toLocaleString()}<br>
                Effect: ${r.measure} ${r.pooled && r.pooled.theta !== undefined ? Math.exp(r.pooled.theta).toFixed(2) : 'N/A'} (95% CI: ${r.pooled && r.pooled.ci_lower !== undefined ? Math.exp(r.pooled.ci_lower).toFixed(2) : 'N/A'} to ${r.pooled && r.pooled.ci_upper !== undefined ? Math.exp(r.pooled.ci_upper).toFixed(2) : 'N/A'})<br>
                Certainty: Requires full GRADE assessment
              </div>
            </div>
          </div>
        </div>
      `;
    }
    
    /**
     * Helper: Get journal style configuration
     */
    function getJournalStyleConfig(style) {
      const configs = {
        general: { headingPrefix: '', ciFormat: 'to', decimalPlaces: 2 },
        jama: { headingPrefix: '', ciFormat: 'to', decimalPlaces: 2, useHR: true },
        bmj: { headingPrefix: '', ciFormat: 'to', decimalPlaces: 2 },
        lancet: { headingPrefix: '', ciFormat: '–', decimalPlaces: 2 },
        nejm: { headingPrefix: '', ciFormat: 'to', decimalPlaces: 1 },
        cochrane: { headingPrefix: '', ciFormat: 'to', decimalPlaces: 2 },
        prisma: { headingPrefix: '', ciFormat: 'to', decimalPlaces: 2 },
        grade: { headingPrefix: '', ciFormat: 'to', decimalPlaces: 2 }
      };
      return configs[style] || configs.general;
    }
    
    /**
     * Helper: Get full measure name
     */
    function getMeasureName(measure) {
      const names = {
        'OR': 'odds ratio',
        'RR': 'risk ratio',
        'HR': 'hazard ratio',
        'RD': 'risk difference',
        'SMD': 'standardized mean difference',
        'MD': 'mean difference'
      };
      return names[measure] || measure;
    }
    
    /**
     * Helper: Format effect based on measure
     */
    /**
     * Helper: Get tau² method full name
     */
    function getMethodFullName(method) {
      const names = {
        'DL': 'DerSimonian-Laird',
        'REML': 'restricted maximum likelihood (REML)',
        'PM': 'Paule-Mandel',
        'ML': 'maximum likelihood',
        'HS': 'Hunter-Schmidt',
        'SJ': 'Sidik-Jonkman',
        'HE': 'Hedges',
        'EB': 'empirical Bayes'
      };
      return names[method] || method;
    }
    
    /**
     * Helper: Get tau² method rationale
     */
    function getMethodRationale(method) {
      const rationales = {
        'DL': 'computational simplicity and widespread use',
        'REML': 'superior small-sample properties and reduced bias',
        'PM': 'iterative approach that performs well with few studies',
        'ML': 'asymptotic efficiency',
        'HS': 'robustness to outliers',
        'SJ': 'unbiased estimation under certain conditions',
        'HE': 'exact unbiased estimation under normality',
        'EB': 'Bayesian shrinkage properties'
      };
      return rationales[method] || 'established statistical properties';
    }
    
    /**
     * Helper: Calculate median
     */
    function median(arr) {
      const sorted = [...arr].sort((a, b) => a - b);
      const mid = Math.floor(sorted.length / 2);
      return sorted.length % 2 ? sorted[mid] : (sorted[mid - 1] + sorted[mid]) / 2;
    }
    
    /**
     * Copy report section to clipboard
     */
    function copyReportSection(elementId) {
      const element = document.getElementById(elementId);
      if (element) {
        // Get text content, preserving some formatting
        const text = element.innerText;
        navigator.clipboard.writeText(text).then(() => {
          alert('Section copied to clipboard!');
        });
      }
    }
    
    /**
     * Download report section
     */
    function downloadReportSection(elementId, filename) {
      const element = document.getElementById(elementId);
      if (element) {
        const text = element.innerText;
        const blob = new Blob([text], { type: 'text/plain' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `meta-analysis-${filename}.txt`;
        a.click();
        URL.revokeObjectURL(url);
      }
    }
    
    /**
     * Download full report
     */
    function downloadFullReport(format = 'txt') {
      const methodsEl = document.getElementById('methodsContent');
      const resultsEl = document.getElementById('resultsContent');
      
      let content = '='.repeat(60) + '\n';
      content += 'META-ANALYSIS REPORT\n';
      content += 'Generated by Pairwise Pro v2.2\n';
      content += new Date().toISOString() + '\n';
      content += '='.repeat(60) + '\n\n';
      
      if (methodsEl) {
        content += 'METHODS\n';
        content += '-'.repeat(40) + '\n\n';
        content += methodsEl.innerText + '\n\n';
      }
      
      if (resultsEl) {
        content += 'RESULTS\n';
        content += '-'.repeat(40) + '\n\n';
        content += resultsEl.innerText + '\n';
      }
      
      let mimeType = 'text/plain';
      let extension = 'txt';
      
      if (format === 'md') {
        // Convert to markdown-ish format
        content = content.replace(/={60}/g, '# ');
        content = content.replace(/-{40}/g, '## ');
        extension = 'md';
        mimeType = 'text/markdown';
      }
      
      const blob = new Blob([content], { type: mimeType });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `meta-analysis-report.${extension}`;
      a.click();
      URL.revokeObjectURL(url);
      
      if (format === 'docx') {
        alert('For .docx format, copy the text and paste into Word, or use the R code to generate publication-quality documents with officer/flextable packages.');
      }
    }
    
