    // =============================================
    // BENCHMARK VERIFICATION (metafor reference)
    // =============================================
    
    /**
     * Reference values from metafor 4.4-0 for BCG dataset
     * Used to verify statistical accuracy of Pairwise Pro
     */
    const BENCHMARK_REFERENCE = {
      dataset: 'BCG Vaccine (k=13, metafor::dat.bcg)',
      software: 'R metafor 4.4-0',
      values: {
        // τ² estimation
        tau2_DL: 0.3088,
        tau2_REML: 0.3132,
        tau2_PM: 0.2685,
        
        // Pooled estimate (REML)
        theta: -0.7145,
        se: 0.1787,
        ci_lower: -1.0648,
        ci_upper: -0.3643,
        z_value: -4.00,
        p_value: 0.0001,
        
        // Transformed
        OR: 0.4894,
        OR_lower: 0.3449,
        OR_upper: 0.6948,
        
        // Heterogeneity
        Q: 152.233,
        Q_df: 12,
        I2: 92.22,
        H2: 12.86,
        tau: 0.5597,
        
        // Prediction interval
        pi_lower: -1.9335,
        pi_upper: 0.5044,
        
        // Egger's test
        egger_intercept: -2.97,
        egger_se: 1.08,
        egger_pval: 0.02,
        
        // Trim and fill
        trimfill_k0: 0,
        trimfill_theta: -0.7145
      },
      tolerances: {
        tau2: 0.01,
        theta: 0.001,
        se: 0.001,
        I2: 0.5,
        Q: 0.1,
        pi: 0.01
      }
    };
    
    /**
     * Run benchmark verification against R reference values
     * @returns {object} Verification results
     */
    function runBenchmarkVerification() {
      // log.info('Running benchmark verification against metafor...');
      
      const results = {
        passed: 0,
        failed: 0,
        tests: []
      };
      
      // Create BCG test data
      const bcgData = [
        { name: 'Aronson 1948', events_t: 4, n_t: 123, events_c: 11, n_c: 139 },
        { name: 'Ferguson 1949', events_t: 6, n_t: 306, events_c: 29, n_c: 303 },
        { name: 'Rosenthal 1960', events_t: 3, n_t: 231, events_c: 11, n_c: 220 },
        { name: 'Hart 1977', events_t: 62, n_t: 13598, events_c: 248, n_c: 12867 },
        { name: 'Frimodt-Moller 1973', events_t: 33, n_t: 5069, events_c: 47, n_c: 5808 },
        { name: 'Stein 1953', events_t: 180, n_t: 1541, events_c: 372, n_c: 1451 },
        { name: 'Vandiviere 1973', events_t: 8, n_t: 2545, events_c: 10, n_c: 629 },
        { name: 'TPT Madras 1980', events_t: 505, n_t: 88391, events_c: 499, n_c: 88391 },
        { name: 'Coetzee 1968', events_t: 29, n_t: 7499, events_c: 45, n_c: 7277 },
        { name: 'Rosenthal 1961', events_t: 17, n_t: 1716, events_c: 65, n_c: 1665 },
        { name: 'Comstock 1969', events_t: 186, n_t: 50634, events_c: 141, n_c: 27338 },
        { name: 'Comstock 1974', events_t: 5, n_t: 2498, events_c: 3, n_c: 2341 },
        { name: 'Comstock 1976', events_t: 27, n_t: 16913, events_c: 29, n_c: 17854 }
      ];
      
      // Calculate log ORs
      const yi = bcgData.map(s => {
        const a = s.events_t + 0.5;
        const b = (s.n_t - s.events_t) + 0.5;
        const c = s.events_c + 0.5;
        const d = (s.n_c - s.events_c) + 0.5;
        return Math.log((a * d) / (b * c));
      });
      
      const vi = bcgData.map(s => {
        const a = s.events_t + 0.5;
        const b = (s.n_t - s.events_t) + 0.5;
        const c = s.events_c + 0.5;
        const d = (s.n_c - s.events_c) + 0.5;
        return 1/a + 1/b + 1/c + 1/d;
      });
      
      const ref = BENCHMARK_REFERENCE.values;
      const tol = BENCHMARK_REFERENCE.tolerances;
      
      // Test DL τ²
      const tau2_dl = estimateTau2_DL(yi, vi);
      const dl_pass = Math.abs(tau2_dl.tau2 - ref.tau2_DL) < tol.tau2;
      results.tests.push({
        name: 'τ² (DL)',
        expected: ref.tau2_DL,
        actual: tau2_dl.tau2,
        passed: dl_pass
      });
      if (dl_pass) results.passed++; else results.failed++;
      
      // Test REML τ²
      const tau2_reml = estimateTau2_REML(yi, vi);
      const reml_pass = Math.abs(tau2_reml.tau2 - ref.tau2_REML) < tol.tau2;
      results.tests.push({
        name: 'τ² (REML)',
        expected: ref.tau2_REML,
        actual: tau2_reml.tau2,
        passed: reml_pass
      });
      if (reml_pass) results.passed++; else results.failed++;
      
      // Test pooled estimate
      const pooled = pooledEstimate_RE(yi, vi, tau2_reml.tau2);
      const theta_pass = Math.abs(pooled.theta - ref.theta) < tol.theta;
      results.tests.push({
        name: 'θ (pooled log OR)',
        expected: ref.theta,
        actual: pooled.theta,
        passed: theta_pass
      });
      if (theta_pass) results.passed++; else results.failed++;
      
      // Test SE
      const se_pass = Math.abs(pooled.se - ref.se) < tol.se;
      results.tests.push({
        name: 'SE',
        expected: ref.se,
        actual: pooled.se,
        passed: se_pass
      });
      if (se_pass) results.passed++; else results.failed++;
      
      // Test heterogeneity
      const het = calculateHeterogeneity(yi, vi, tau2_reml.tau2);
      const I2_pass = Math.abs(het.I2 - ref.I2) < tol.I2;
      results.tests.push({
        name: 'I²',
        expected: ref.I2,
        actual: het.I2,
        passed: I2_pass
      });
      if (I2_pass) results.passed++; else results.failed++;
      
      const Q_pass = Math.abs(het.Q - ref.Q) < tol.Q;
      results.tests.push({
        name: 'Q statistic',
        expected: ref.Q,
        actual: het.Q,
        passed: Q_pass
      });
      if (Q_pass) results.passed++; else results.failed++;
      
      // Summary
      results.summary = {
        total: results.passed + results.failed,
        passed: results.passed,
        failed: results.failed,
        accuracy: ((results.passed / (results.passed + results.failed)) * 100).toFixed(1) + '%'
      };
      
      // log.info('Benchmark verification complete:', results.summary);
      
      return results;
    }
    
    // Expose for console testing
    window.runBenchmarkVerification = runBenchmarkVerification;
    window.BENCHMARK_REFERENCE = BENCHMARK_REFERENCE;
    window.rma_mv_multilevel = rma_mv_multilevel;
    window.rma_mv_multivariate = rma_mv_multivariate;
    window.correlationSensitivity = correlationSensitivity;
    window.Matrix = Matrix;

    // =========================================================================
    // TRUTHCERT MODULE - Evidence Quality Assessment
    // Merged from TruthCert v8.8.2 S14-HTA+ v1.4.2
    // =========================================================================

    /**
     * TruthCert Configuration
     */
    const TruthCertConfig = {
      // Core parameters
      minK: 4,                    // Minimum studies for reliable pooling
      delta: 0.1054,              // Default MCID (log scale, ~10% RRR)
      rho: 0.5,                   // Working correlation for RVE
      selModelMinK: 10,           // Minimum k for selection models
      rareThreshold: 0.05,        // Rare event threshold for Peters test
      permReps: 10000,            // Permutation replicates
      bootReps: 1000,             // Bootstrap replicates
      seed: 12345,                // Deterministic seed

      // Threat Ledger thresholds (configurable)
      thresholds: {
        heterogeneity: {
          low: 25,                // I² below this = green
          moderate: 50,           // I² below this = amber, above = red
          high: 75                // Extreme heterogeneity trigger
        },
        breakdown: {
          good: 0.30,             // Fraction to flip >= this = green
          moderate: 0.15          // Fraction >= this = amber, below = red
        },
        fragility: {
          good: 3,                // FI >= this = green
          moderate: 1             // FI >= this = amber, below = red
        },
        influence: {
          maxFlagged: 2           // More than this = amber
        },
        estimatorSpread: {
          stable: 0.1             // tau² spread below this = stable
        },
        precision: {
          excellent: 0.30,        // CI width < this = excellent (for STABLE-NID)
          good: 0.50,             // CI width < this = good precision
          adequate: 1.00          // CI width < this = adequate precision
        }
      },

      // Severity scoring weights
      severity: {
        insufficientStudies: 2,
        estimatorDisagreement: 2,
        extremeHeterogeneity: 1,
        tau2Unstable: 1,
        publicationBias: 1,
        lowBreakdown: 1,
        lowFragility: 1,
        piCrossesNull: 1,
        permDifferent: 1,
        highInfluence: 1,
        robSensitive: 1,
        oisNotMet: 1
      }
    };

    // Event system for analysis completion
    const AnalysisEvents = {
      listeners: {},
      on(event, callback) {
        if (!this.listeners[event]) this.listeners[event] = [];
        this.listeners[event].push(callback);
      },
      emit(event, data) {
        if (this.listeners[event]) {
          this.listeners[event].forEach(cb => {
            try { cb(data); } catch (e) { console.error('Event handler error:', e); }
          });
        }
      },
      off(event, callback) {
        if (this.listeners[event]) {
          this.listeners[event] = this.listeners[event].filter(cb => cb !== callback);
        }
      }
    };

    /**
     * Decision log for audit trail
     */
    const decisionLog = [];
    function logDecision(type, msg) {
      decisionLog.push({ time: new Date().toISOString(), type, msg });
    }

    /**
     * Tier D HTA Analysis Audit Log
     * Stores records of HTA analyses run on UNCERTAIN evidence for compliance/audit purposes
     */
    const tierDAuditLog = [];

    function generateSessionId() {
      const id = 'hta_' + Date.now() + '_' + Math.random().toString(36).substr(2, 9);
      window.sessionStorage.setItem('htaSessionId', id);
      return id;
    }

    function logTierDAnalysis(record) {
      tierDAuditLog.push(record);
      logDecision('audit', 'Tier D HTA analysis initiated: ' + JSON.stringify(record));

      // Store in localStorage for persistence across sessions
      const existingLog = JSON.parse(localStorage.getItem('tierDAuditLog') || '[]');
      existingLog.push(record);
      localStorage.setItem('tierDAuditLog', JSON.stringify(existingLog));

      console.warn('[AUDIT] Tier D HTA Analysis:', record);
    }

    function getTierDAuditLog() {
      return JSON.parse(localStorage.getItem('tierDAuditLog') || '[]');
    }

    function exportTierDAuditLog() {
      const log = getTierDAuditLog();
      const csv = 'timestamp,verdict,tier,userConfirmed,sessionId\n' +
        log.map(r => [r.timestamp, r.verdict, r.tier, r.userConfirmed, r.sessionId].join(',')).join('\n');

      const blob = new Blob([csv], { type: 'text/csv' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = 'tier_d_hta_audit_log.csv';
      a.click();
      URL.revokeObjectURL(url);
    }

