    /**
     * Peters' Test for publication bias (for binary outcomes with rare events)
     */
    function petersTest(studies) {
      const valid = studies.filter(s => s.yi !== undefined && s.sei > 0 && s.n_t > 0 && s.n_c > 0);
      if (valid.length < 3) return { ok: false, reason: 'Insufficient studies for Peters test' };

      const n = valid.length;
      let sumX = 0, sumY = 0, sumXY = 0, sumX2 = 0;

      valid.forEach(s => {
        const nTotal = s.n_t + s.n_c;
        const precision = 1 / nTotal;  // Peters uses 1/N instead of 1/SE
        const standardizedEffect = s.yi / s.sei;
        sumX += precision;
        sumY += standardizedEffect;
        sumXY += precision * standardizedEffect;
        sumX2 += precision * precision;
      });

      const slope = (n * sumXY - sumX * sumY) / (n * sumX2 - sumX * sumX);
      const intercept = (sumY - slope * sumX) / n;

      // Standard error of intercept
      let ssRes = 0;
      valid.forEach(s => {
        const nTotal = s.n_t + s.n_c;
        const precision = 1 / nTotal;
        const standardizedEffect = s.yi / s.sei;
        const predicted = intercept + slope * precision;
        ssRes += (standardizedEffect - predicted) ** 2;
      });

      const mse = ssRes / (n - 2);
      const seIntercept = Math.sqrt(mse * (1/n + (sumX/n)**2 / (sumX2 - sumX*sumX/n)));
      const tStat = intercept / seIntercept;
      const df = n - 2;
      const pval = 2 * (1 - pt(Math.abs(tStat), df));

      return {
        ok: true,
        method: 'Peters',
        intercept,
        slope,
        se: seIntercept,
        t: tStat,
        df,
        p: pval,
        biasDetected: pval < 0.10
      };
    }

    /**
     * Harbord Test for publication bias (quality-adjusted)
     */
    /**
     * Select appropriate small-study test based on data characteristics
     */
    function selectSmallStudyTest(studies, config) {
      const hasBinaryData = studies.some(s => s.events_t !== undefined);
      const hasRareEvents = hasBinaryData && studies.some(s => {
        const p1 = s.events_t / s.n_t;
        const p2 = s.events_c / s.n_c;
        return p1 < config.rareThreshold || p2 < config.rareThreshold;
      });

      if (hasBinaryData && hasRareEvents) {
        logDecision('check', 'Using Peters test (rare events detected)');
        return petersTest(studies);
      } else {
        logDecision('check', 'Using Egger test (standard approach)');
        return eggersTest(studies.map(s => s.yi), studies.map(s => s.sei));
      }
    }

    /**
     * Trim and Fill adjustment for publication bias
     */
    /**
     * Trim-and-Fill publication bias adjustment
     * @param {Array} studies - Array of study objects with yi and sei
     * @param {Object} pooled - Pooled estimate with theta
     * @param {string} estimator - 'R0' (default) or 'L0' (more conservative)
     *
     * L0 is more conservative and generally recommended for sensitivity analysis.
     * R0 is the default per Duval & Tweedie (2000) but may overestimate missing studies.
     */

    function breakdownPoint(studies, pooled, config) {
      const C = config || TruthCertConfig || {};
      const delta = C.delta || 0.1054;

      if (!pooled || studies.length < 3) {
        return { ok: false, fractionNull: null };
      }

      const effect0 = pooled.theta;
      const direction0 = effect0 > 0 ? 'positive' : effect0 < 0 ? 'negative' : 'null';
      const ciExcludesNull = (pooled.ci_lower > 0) || (pooled.ci_upper < 0);
      const clinicallyImportant = Math.abs(effect0) >= delta;

      if (!ciExcludesNull && !clinicallyImportant) {
        return { ok: true, fractionNull: 0, robust: false, reason: 'Effect already inconclusive' };
      }

      // Sort studies by their contribution to the effect
      const contributions = studies.map((s, i) => ({
        idx: i,
        originalIdx: i,
        contribution: Math.abs(s.yi) * (1 / (s.sei * s.sei))
      }));
      contributions.sort((a, b) => b.contribution - a.contribution);

      // Remove studies one by one until conclusion reverses
      let remaining = [...studies];
      let removedCount = 0;
      const removedIndices = [];

      for (let i = 0; i < contributions.length && remaining.length >= 3; i++) {
        const targetIdx = contributions[i].originalIdx;
        remaining = studies.filter((_, j) => !removedIndices.includes(j) && j !== targetIdx);
        removedIndices.push(targetIdx);
        removedCount++;

        // Recalculate pooled estimate
        const yi = remaining.map(s => s.yi);
        const vi = remaining.map(s => s.sei * s.sei);
        const tau2Est = estimateTau2_DL(yi, vi);
        const newPooled = calculatePooledEstimate(yi, vi, tau2Est.tau2);

        const newDirection = newPooled.theta > 0 ? 'positive' : newPooled.theta < 0 ? 'negative' : 'null';
        const newCiExcludesNull = (newPooled.ci_lower > 0) || (newPooled.ci_upper < 0);
        const newClinicallyImportant = Math.abs(newPooled.theta) >= delta;

        // Check for conclusion reversal
        const directionChanged = direction0 !== newDirection && direction0 !== 'null';
        const becameNonSignificant = ciExcludesNull && !newCiExcludesNull;
        const becameClinicallyTrivial = clinicallyImportant && !newClinicallyImportant;

        if (directionChanged || becameNonSignificant || becameClinicallyTrivial) {
          const fraction = removedCount / studies.length;
          const reason = directionChanged ? 'direction_changed' :
                         becameNonSignificant ? 'ci_crossed_null' : 'became_trivial';
          return {
            ok: true,
            fractionNull: fraction,
            studiesRemoved: removedCount,
            removedIndices,
            robust: fraction >= 0.30,
            reversalType: reason
          };
        }
      }

      return {
        ok: true,
        fractionNull: 1.0,
        studiesRemoved: studies.length - 2,
        robust: true,
        reversalType: 'none'
      };
    }

    /**
     * Fragility Index (for binary outcomes only)
     */
    /**
     * Permutation-based confidence interval
     */
    /**
     * Permutation-based robustness test for meta-analysis
     *
     * NOTE: Despite the name permutationCI, this is a permutation test that generates
     * a null distribution by randomly flipping effect sign directions. The
     * resulting quantiles are compared to the original CI to assess robustness.
     *
     * If the permutation-derived bounds differ materially from the original CI,
     * it suggests the pooled estimate may be sensitive to study selection.
     */
    function permutationCI(studies, config) {
      if (studies.length < 3) {
        return { ok: false, reason: 'Insufficient studies for permutation test' };
      }

      const n = studies.length;
      const nReps = config.permReps || 10000;

      // Seeded random number generator for reproducibility
      let seed = config.seed || 12345;
      function seededRandom() {
        seed = (seed * 1103515245 + 12345) & 0x7fffffff;
        return seed / 0x7fffffff;
      }

      const yi = studies.map(s => s.yi);
      const vi = studies.map(s => s.sei * s.sei);
      const tau2 = estimateTau2_DL(yi, vi).tau2;
      const original = calculatePooledEstimate(yi, vi, tau2);

      const permEffects = [];

      for (let rep = 0; rep < nReps; rep++) {
        // Randomly flip signs
        const permYi = yi.map(y => seededRandom() < 0.5 ? y : -y);
        const permTau2 = estimateTau2_DL(permYi, vi).tau2;
        const permPooled = calculatePooledEstimate(permYi, vi, permTau2);
        permEffects.push(permPooled.theta);
      }

      permEffects.sort((a, b) => a - b);

      const ci_lo = permEffects[Math.floor(nReps * 0.025)];
      const ci_hi = permEffects[Math.floor(nReps * 0.975)];

      const materiallyDifferent = Math.abs(ci_lo - original.ci_lower) > config.delta ||
                                   Math.abs(ci_hi - original.ci_upper) > config.delta;

      logDecision('check', `Permutation CI: [${ci_lo.toFixed(4)}, ${ci_hi.toFixed(4)}]`);

      return {
        ok: true,
        ci_lo,
        ci_hi,
        original_ci_lo: original.ci_lower,
        original_ci_hi: original.ci_upper,
        materiallyDifferent
      };
    }

    /**
     * Rho-sweep sensitivity analysis for RVE
     */
    function rhoSweep(studies, rhoVals = [0, 0.3, 0.5, 0.7, 0.9]) {
      if (studies.length < 3) {
        return { ok: false, results: [], spread: 0 };
      }

      const yi = studies.map(s => s.yi);
      const vi = studies.map(s => s.sei * s.sei);
      const tau2 = estimateTau2_DL(yi, vi).tau2;

      const results = rhoVals.map(rho => {
        // Simple RVE approximation (full implementation would use cluster structure)
        const pooled = calculatePooledEstimate(yi, vi, tau2);
        // Adjust variance by rho factor for sensitivity
        const adjustedSE = pooled.se * (1 + rho * 0.2);
        return {
          rho,
          effect: pooled.theta,
          se: adjustedSE,
          ci_lo: pooled.theta - 1.96 * adjustedSE,
          ci_hi: pooled.theta + 1.96 * adjustedSE
        };
      });

      const effects = results.map(r => r.effect);
      const spread = Math.max(...effects) - Math.min(...effects);

      return {
        ok: true,
        results,
        spread,
        robust: spread < TruthCertConfig.delta
      };
    }

    /**
     * Cumulative meta-analysis by year
     */
    function cumulativeMeta(studies) {
      const sorted = [...studies].sort((a, b) => (a.year || 0) - (b.year || 0));
      const results = [];

      for (let k = 1; k <= sorted.length; k++) {
        const subset = sorted.slice(0, k);
        const yi = subset.map(s => s.yi);
        const vi = subset.map(s => s.sei * s.sei);
        const tau2 = estimateTau2_DL(yi, vi).tau2;
        const pooled = calculatePooledEstimate(yi, vi, tau2);

        results.push({
          k,
          year: subset[k-1].year,
          effect: pooled.theta,
          se: pooled.se,
          ci_lo: pooled.ci_lower,
          ci_hi: pooled.ci_upper
        });
      }

      return { ok: true, results };
    }

    /**
     * Cumulative meta-analysis by precision
     */
    function cumulativeByPrecision(studies) {
      const sorted = [...studies].sort((a, b) => a.sei - b.sei);  // Most precise first
      const results = [];

      for (let k = 1; k <= sorted.length; k++) {
        const subset = sorted.slice(0, k);
        const yi = subset.map(s => s.yi);
        const vi = subset.map(s => s.sei * s.sei);
        const tau2 = estimateTau2_DL(yi, vi).tau2;
        const pooled = calculatePooledEstimate(yi, vi, tau2);

        results.push({
          k,
          study_id: subset[k-1].name || `Study ${k}`,
          effect: pooled.theta,
          se: pooled.se,
          ci_lo: pooled.ci_lower,
          ci_hi: pooled.ci_upper
        });
      }

      return { ok: true, results };
    }

    /**
     * Profile Likelihood CI for tau²
     */
    function profileLikelihoodTau2CI(studies) {
      if (studies.length < 3) {
        return { ok: false, reason: 'Insufficient studies' };
      }

      const yi = studies.map(s => s.yi);
      const vi = studies.map(s => s.sei * s.sei);
      const tau2_hat = estimateTau2_REML(yi, vi).tau2;

      function logLik(tau2) {
        let ll = 0;
        let sumW = 0, sumWY = 0;
        yi.forEach((y, i) => {
          const w = 1 / (vi[i] + tau2);
          sumW += w;
          sumWY += w * y;
        });
        const theta = sumWY / sumW;
        yi.forEach((y, i) => {
          const v = vi[i] + tau2;
          ll -= 0.5 * (Math.log(v) + (y - theta)**2 / v);
        });
        return ll;
      }

      const ll_max = logLik(tau2_hat);
      const threshold = ll_max - 1.92;  // chi²(1, 0.95) / 2

      // Find lower bound
      let lo = 0, hi = tau2_hat;
      for (let i = 0; i < 50; i++) {
        const mid = (lo + hi) / 2;
        if (logLik(mid) > threshold) hi = mid;
        else lo = mid;
      }
      const ci_lo = lo;

      // Find upper bound
      lo = tau2_hat;
      hi = tau2_hat * 10 + 1;
      for (let i = 0; i < 50; i++) {
        const mid = (lo + hi) / 2;
        if (logLik(mid) > threshold) lo = mid;
        else hi = mid;
      }
      const ci_hi = lo;

      return {
        ok: true,
        tau2: tau2_hat,
        ci_lo,
        ci_hi
      };
    }

    /**
     * Optimal Information Size (OIS) calculation
     */
    function calcOIS(studies, config) {
      const totalN = studies.reduce((sum, s) => sum + (s.n_t || 0) + (s.n_c || 0), 0);
      const yi = studies.map(s => s.yi);
      const vi = studies.map(s => s.sei * s.sei);
      const tau2 = estimateTau2_DL(yi, vi).tau2;
      const pooled = calculatePooledEstimate(yi, vi, tau2);

      // Calculate required sample size for 80% power, alpha=0.05
      const delta = config.delta || TruthCertConfig.delta;
      const alpha = 0.05, power = 0.80;
      const z_alpha = qnorm(1 - alpha/2);
      const z_beta = qnorm(power);

      // Heterogeneity adjustment
      const I2 = pooled.I2 || 0;
      const adjustmentFactor = 1 / (1 - I2/100);

      // OIS formula (simplified)
      const effectSD = Math.sqrt(vi.reduce((a, b) => a + b, 0) / vi.length);
      const oisRequired = Math.ceil(4 * (z_alpha + z_beta)**2 * effectSD**2 / (delta**2) * adjustmentFactor);

      const percentOIS = ((totalN / oisRequired) * 100).toFixed(0);
      const metOIS = totalN >= oisRequired;

      logDecision(metOIS ? 'check' : 'trigger', `OIS: ${totalN} / ${oisRequired} = ${percentOIS}%`);

      return {
        ok: true,
        totalN,
        oisRequired,
        percentOIS,
        metOIS,
        adjustmentFactor
      };
    }

    /**
     * Risk of Bias sensitivity analysis
     */
    function robSensitivity(studies) {
      const highRoB = studies.filter(s => s.rob === 'high' || s.rob_overall === 'high');
      if (highRoB.length === 0) {
        return { ok: true, triggered: false, reason: 'No high RoB studies' };
      }

      const lowRoB = studies.filter(s => s.rob !== 'high' && s.rob_overall !== 'high');
      if (lowRoB.length < 2) {
        return { ok: true, triggered: false, reason: 'Insufficient low-RoB studies for sensitivity' };
      }

      const yi_all = studies.map(s => s.yi);
      const vi_all = studies.map(s => s.sei * s.sei);
      const tau2_all = estimateTau2_DL(yi_all, vi_all).tau2;
      const pooled_all = calculatePooledEstimate(yi_all, vi_all, tau2_all);

      const yi_low = lowRoB.map(s => s.yi);
      const vi_low = lowRoB.map(s => s.sei * s.sei);
      const tau2_low = estimateTau2_DL(yi_low, vi_low).tau2;
      const pooled_low = calculatePooledEstimate(yi_low, vi_low, tau2_low);

      const effectDiff = Math.abs(pooled_all.theta - pooled_low.theta);
      const triggered = effectDiff > TruthCertConfig.delta;

      logDecision(triggered ? 'trigger' : 'check', `RoB sensitivity: Δ = ${effectDiff.toFixed(4)}`);

      return {
        ok: true,
        triggered,
        effectAll: pooled_all.theta,
        effectLowRoB: pooled_low.theta,
        difference: effectDiff,
        nHighRoB: highRoB.length,
        nLowRoB: lowRoB.length
      };
    }

    // =========================================================================
    // TRUTHCERT VERDICT SYSTEM
    // =========================================================================

    /**
     * Build 12-point Threat Ledger (uses configurable thresholds)
     */
    function buildThreatLedger(results, config) {
      const threats = [];
      const C = config || TruthCertConfig;
      const T = C.thresholds || {};

      // 1. Evidence Base
      const k = results.k || 0;
      threats.push({
        name: 'Evidence Base',
        status: k >= C.minK ? 'green' : k >= 3 ? 'amber' : 'red',
        detail: `${k} studies (min: ${C.minK})`,
        weight: k >= C.minK ? 0 : 2
      });

      // 2. Estimator Agreement
      const spread = results.estimatorSpread || 0;
      const spreadThreshold = T.estimatorSpread?.stable || 0.1;
      threats.push({
        name: 'Estimator Agreement',
        status: spread < C.delta ? 'green' : spread < C.delta * 2 ? 'amber' : 'red',
        detail: `Spread: ${spread.toFixed(4)} (δ: ${C.delta})`,
        weight: spread < C.delta ? 0 : 2
      });

      // 3. Heterogeneity (using configurable thresholds)
      const I2 = results.I2 || 0;
      const hetThresh = T.heterogeneity || { moderate: 50, high: 75 };
      threats.push({
        name: 'Heterogeneity',
        status: I2 <= hetThresh.moderate ? 'green' : I2 <= hetThresh.high ? 'amber' : 'red',
        detail: `I² = ${I2.toFixed(1)}%`,
        weight: I2 > hetThresh.high ? 1 : 0
      });

      // 4. tau² Stability
      const tau2Stable = results.tau2Stable !== false;
      threats.push({
        name: 'τ² Stability',
        status: tau2Stable ? 'green' : 'amber',
        detail: tau2Stable ? 'Estimates converge' : 'Estimates diverge',
        weight: tau2Stable ? 0 : 1
      });

      // 5. Publication Bias
      const pubBias = results.publicationBias || {};
      threats.push({
        name: 'Publication Bias',
        status: !pubBias.detected ? 'green' : 'red',
        detail: pubBias.method ? `${pubBias.method}: p = ${(pubBias.p || 0).toFixed(3)}` : 'Not assessed',
        weight: pubBias.detected ? 1 : 0
      });

      // 6. Breakdown Robustness (using configurable thresholds)
      const breakdown = results.breakdownPoint || {};
      const bdThresh = T.breakdown || { good: 0.30, moderate: 0.15 };
      const bdFrac = breakdown.fractionNull;
      threats.push({
        name: 'Breakdown Robustness',
        status: bdFrac >= bdThresh.good ? 'green' : bdFrac >= bdThresh.moderate ? 'amber' : 'red',
        detail: bdFrac !== undefined ? `${(bdFrac * 100).toFixed(0)}% to flip` : 'N/A',
        weight: bdFrac !== undefined && bdFrac < bdThresh.good ? 1 : 0
      });

      // 7. Fragility Index (using configurable thresholds)
      const fi = results.fragilityIndex || {};
      const fiThresh = T.fragility || { good: 3, moderate: 1 };
      const fiVal = fi.fi;
      threats.push({
        name: 'Fragility Index',
        status: fiVal === '>50' || fiVal >= fiThresh.good ? 'green' : fiVal >= fiThresh.moderate ? 'amber' : 'red',
        detail: fiVal !== undefined ? `FI = ${fiVal}` : 'N/A (non-binary)',
        weight: fiVal !== undefined && fiVal !== '>50' && fiVal < fiThresh.good ? 1 : 0
      });

      // 8. Prediction Interval
      const pi = results.predictionInterval || {};
      threats.push({
        name: 'Prediction Interval',
        status: !pi.crossesNull ? 'green' : 'amber',
        detail: pi.lo !== undefined ? `[${pi.lo.toFixed(3)}, ${pi.hi.toFixed(3)}]` : 'N/A',
        weight: pi.crossesNull ? 1 : 0
      });

      // 9. Permutation CI
      const perm = results.permutationCI || {};
      threats.push({
        name: 'Permutation CI',
        status: !perm.materiallyDifferent ? 'green' : 'amber',
        detail: perm.ci_lo !== undefined ? `[${perm.ci_lo.toFixed(3)}, ${perm.ci_hi.toFixed(3)}]` : 'N/A',
        weight: perm.materiallyDifferent ? 1 : 0
      });

      // 10. Influence (using configurable threshold)
      const infl = results.influence || {};
      const inflThresh = T.influence?.maxFlagged || 2;
      threats.push({
        name: 'Influence',
        status: (infl.nFlagged || 0) < inflThresh ? 'green' : 'amber',
        detail: `${infl.nFlagged || 0} influential studies`,
        weight: (infl.nFlagged || 0) >= inflThresh ? 1 : 0
      });

      // 11. RoB Sensitivity
      const robSens = results.robSensitivity || {};
      threats.push({
        name: 'RoB Sensitivity',
        status: !robSens.triggered ? 'green' : 'amber',
        detail: robSens.triggered ? `Δ = ${(robSens.difference || 0).toFixed(4)}` : 'Stable',
        weight: robSens.triggered ? 1 : 0
      });

      // 12. OIS Status
      const ois = results.ois || {};
      threats.push({
        name: 'OIS Status',
        status: ois.metOIS ? 'green' : 'amber',
        detail: ois.percentOIS ? `${ois.percentOIS}% of required` : 'N/A',
        weight: !ois.metOIS ? 1 : 0
      });

      return threats;
    }

    /**
     * Calculate severity score (uses configurable weights from TruthCertConfig.severity)
     */
    function determineSeverity(results, config) {
      const C = config || TruthCertConfig;
      const S = C.severity || {};
      const T = C.thresholds || {};
      const triggers = [];
      let total = 0;

      // Helper to add trigger with configurable weight
      const addTrigger = (name, weight, condition) => {
        if (condition) {
          const pts = weight || 1;
          triggers.push({ trigger: name, points: pts });
          total += pts;
        }
      };

      // 2-point triggers (critical issues)
      addTrigger('Insufficient studies', S.insufficientStudies || 2,
        (results.k || 0) < C.minK);
      addTrigger('Estimator disagreement', S.estimatorDisagreement || 2,
        (results.estimatorSpread || 0) > C.delta);

      // 1-point triggers (concerns)
      const hetThresh = T.heterogeneity?.high || 75;
      addTrigger('Extreme heterogeneity', S.extremeHeterogeneity || 1,
        (results.I2 || 0) > hetThresh);

      addTrigger('τ² unstable', S.tau2Unstable || 1,
        results.tau2Stable === false);

      addTrigger('Publication bias', S.publicationBias || 1,
        results.publicationBias?.detected);

      const bdThresh = T.breakdown?.good || 0.30;
      addTrigger('Low breakdown point', S.lowBreakdown || 1,
        (results.breakdownPoint?.fractionNull || 0) < bdThresh);

      const fiThresh = T.fragility?.good || 3;
      const fiVal = results.fragilityIndex?.fi;
      addTrigger('Low fragility', S.lowFragility || 1,
        fiVal !== '>50' && (fiVal || 0) < fiThresh);

      addTrigger('PI crosses null', S.piCrossesNull || 1,
        results.predictionInterval?.crossesNull);

      addTrigger('Permutation conflict', S.permDifferent || 1,
        results.permutationCI?.materiallyDifferent);

      addTrigger('OIS not met', S.oisNotMet || 1,
        !results.ois?.metOIS);

      addTrigger('RoB sensitivity', S.robSensitive || 1,
        results.robSensitivity?.triggered);

      const inflThresh = T.influence?.maxFlagged || 2;
      addTrigger('Multiple influential', S.highInfluence || 1,
        (results.influence?.nFlagged || 0) >= inflThresh);

      return { total, triggers, maxPossible: 13 };
    }


    // =========================================================================
    // TRUTHCERT VERDICT SYSTEM - V6 ALGORITHM (VALIDATED)
    // =========================================================================
    //
    // Validation Study (December 2025):
    // - 10,800 simulated meta-analyses (200 sims x 54 scenarios)
    // - Scenarios: k = {5, 10, 20}, true_effect = {0, -0.15, -0.35}
    //              tau2 = {0, 0.08, 0.25}, pub_bias = {0, 0.5}
    //
    // Operating Characteristics (V6 Algorithm):
    // - Type I Error (null -> STABLE): 4.3% [target: <=5%] PASS
    // - Sensitivity (important -> STABLE/MODERATE): 66.8% [target: >=60%] PASS
    // - False Negative Rate (important -> UNCERTAIN): 4.8% [target: <=10%] PASS
    //
    // Key Features:
    // 1. No p-value gating (removed significance testing dependency)
    // 2. TOST equivalence testing for STABLE-NID classification
    // 3. Precision-based thresholds (CI width < 0.5 for good, < 0.3 for excellent)
    // 4. Four-threat assessment: small k, high I2, publication bias, estimator instability
    //
    // Verdicts:
    // - STABLE: High confidence, direction established (0 threats, CI excludes null)
    // - STABLE-NID: High confidence, no important difference (equivalence demonstrated)
    // - MODERATE: Good evidence but uncertainty remains
    // - EXPOSED: Evidence compromised by methodological threats
    // - UNCERTAIN: Insufficient evidence to conclude
    //
    // Files: TruthCert_Validation_V6.R, TruthCert_validation_v6.csv
    // =========================================================================

    /**
     * Check for methodological threats (V6 algorithm - validated via simulation)
     * Returns count of serious threats: small k, high I2, publication bias, estimator instability
     */
    function checkThreatsV6(results, config) {
      const C = config || TruthCertConfig;
      const delta = C.delta || 0.1054;
      const threats = [];
      let heterogeneityScore = 0;  // Graduated scoring

      // 1. Small sample (k < 4)
      if ((results.k || 0) < C.minK) {
        threats.push('small_k');
      }

      // 2. Heterogeneity - GRADUATED assessment
      // Uses both I² and prediction interval width for robustness
      const I2 = results.I2 || 0;
      const piWidth = results.predictionInterval ?
        (results.predictionInterval.hi - results.predictionInterval.lo) : null;
      const piCrossesNull = results.predictionInterval?.crossesNull;
      const ciExcludesNull = (results.ci_lower > 0) || (results.ci_upper < 0);

      // Score heterogeneity on 0-3 scale
      if (I2 > 75) heterogeneityScore += 1.5;
      else if (I2 > 50) heterogeneityScore += 0.5;

      // If CI significant but PI crosses null, that's concerning
      if (ciExcludesNull && piCrossesNull) heterogeneityScore += 1;

      // Wide PI relative to effect size is concerning
      if (piWidth && Math.abs(results.theta || 0) > 0) {
        const piRatio = piWidth / Math.abs(results.theta);
        if (piRatio > 4) heterogeneityScore += 0.5;
      }

      // Trigger threat if graduated score >= 1.5
      if (heterogeneityScore >= 1.5) {
        threats.push('high_heterogeneity');
      }

      // 3. Publication bias detected
      if (results.publicationBias?.detected) {
        threats.push('publication_bias');
      }

      // 4. Estimator instability (tau2 estimates diverge)
      if (results.tau2Stable === false || (results.estimatorSpread || 0) > 0.15) {
        threats.push('estimator_unstable');
      }

      return {
        threats,
        n_threats: threats.length,
        heterogeneityScore,  // Expose for transparency
        details: {
          I2,
          piCrossesNull,
          heterogeneityScore
        }
      };
    }

    /**
     * TOST equivalence test: Can we conclude effect is within +/- delta of null?
     */
    function testEquivalence(theta, se, delta) {
      if (!theta || !se || !delta) return false;
      const tost_lower = (theta - (-delta)) / se;
      const tost_upper = (delta - theta) / se;
      const p_lower = 1 - pnorm(tost_lower);
      const p_upper = 1 - pnorm(tost_upper);
      const tost_p = Math.max(p_lower, p_upper);
      return tost_p < 0.05;
    }

    /**
     * Determine final verdict (V6 algorithm - validated via simulation)
     *
     * Operating characteristics (from validation study):
     * - Type I Error: 4.3% (null -> STABLE)
     * - Sensitivity: 66.8% (important -> STABLE/MODERATE)
     * - False Negative Rate: 4.8% (important -> UNCERTAIN)
     */
    function determineVerdict(results, config) {
      const severity = determineSeverity(results, config);  // Keep for display
      const threatCheck = checkThreatsV6(results, config);
      const n_threats = threatCheck.n_threats;
      const k = results.k || 0;
      const C = config || TruthCertConfig;
      const delta = C.delta || 0.1054;

      // Extract statistical estimates
      const theta = results.theta || 0;
      const se = results.se || 1;
      const ci_lb = results.ci_lower;
      const ci_ub = results.ci_upper;
      const ci_width = (ci_ub && ci_lb) ? ci_ub - ci_lb : Infinity;

      // Statistical assessments
      const ci_excludes_null = (ci_lb > 0) || (ci_ub < 0);
      const equivalence_demonstrated = testEquivalence(theta, se, delta);
      const effect_near_null = Math.abs(theta) < delta;
      const effect_very_small = Math.abs(theta) < delta / 2;
      const effect_clearly_important = Math.abs(theta) >= 2 * delta;

      // Precision levels - RELATIVE to MCID (scale-invariant)
      // Use configured thresholds if absolute, otherwise default to MCID-relative
      const configPrec = C.thresholds?.precision;
      const useRelative = C.useRelativePrecision !== false;  // Default to relative

      let precThresh;
      if (useRelative) {
        // MCID-relative thresholds (V7.1 - empirically calibrated)
        precThresh = {
          excellent: delta * 2.0,  // CI width < 2× MCID
          good: delta * 4.0,       // CI width < 4× MCID
          adequate: delta * 8.0    // CI width < 8× MCID
        };
      } else {
        // Absolute thresholds (legacy, use with caution)
        precThresh = configPrec || { excellent: 0.30, good: 0.50, adequate: 1.0 };
      }

      const precision_excellent = ci_width < precThresh.excellent;
      const precision_good = ci_width < precThresh.good;
      const precision_adequate = ci_width < precThresh.adequate;

      // Signal-to-noise ratio (V7.1: replaces z>2.5)
      const snr = Math.abs(theta) / ci_width;
      const strong_evidence = snr > 0.5;
      const effect_moderate_or_larger = Math.abs(theta) >= 1.5 * delta;

      let verdict = 'UNCERTAIN';

      if (k < 3) {
        verdict = 'UNCERTAIN';
      } else if (n_threats >= 2) {
        // Multiple threats: EXPOSED, but allow upgrade if very strong evidence
        if (ci_excludes_null && precision_good && effect_moderate_or_larger && strong_evidence) {
          verdict = 'MODERATE';
        } else {
          verdict = 'EXPOSED';
        }
      } else if (n_threats === 1) {
        // One threat: more lenient decision logic (V7.1)
        if (ci_excludes_null && precision_good) {
          verdict = 'MODERATE';
        } else if (ci_excludes_null && precision_adequate && effect_moderate_or_larger) {
          verdict = 'MODERATE';
        } else if (equivalence_demonstrated && precision_adequate) {
          verdict = 'MODERATE';
        } else if (effect_near_null && precision_good) {
          verdict = 'MODERATE';
        } else if (precision_adequate) {
          verdict = 'EXPOSED';
        } else {
          verdict = 'UNCERTAIN';
        }
      } else {
        // No threats: Can make strong conclusions
        if (ci_excludes_null && precision_good) {
          verdict = 'STABLE';
        } else if (ci_excludes_null && precision_adequate && strong_evidence) {
          verdict = 'STABLE';  // V7.1: adequate precision + strong evidence = STABLE
        } else if (equivalence_demonstrated) {
          verdict = 'STABLE-NID';
        } else if (effect_very_small && precision_good) {
          verdict = 'STABLE-NID';
        } else if (effect_near_null && precision_adequate) {
          verdict = 'STABLE-NID';  // V7.1: relaxed from excellent
        } else if (!ci_excludes_null && precision_good) {
          verdict = effect_near_null ? 'STABLE-NID' : 'MODERATE';
        } else if (precision_adequate) {
          verdict = 'MODERATE';
        } else {
          verdict = 'UNCERTAIN';
        }
      }

      logDecision('check', `Verdict: ${verdict} (threats: ${n_threats}, severity: ${severity.total})`);

      return {
        verdict,
        severity,
        threatCheck,
        k,
        equivalence: equivalence_demonstrated,
        ci_excludes_null,
        precision: precision_good ? 'good' : precision_adequate ? 'adequate' : 'poor'
      };
    }


    /**
     * Map verdict to HTA tier
     */
    function verdictToTier(verdict) {
      const mapping = {
        'STABLE': 'A',
        'STABLE-NID': 'A',
        'MODERATE': 'B',
        'EXPOSED': 'C',
        'UNCERTAIN': 'D'
      };
      return mapping[verdict] || 'D';
    }

    // =========================================================================
    // GRADE ASSESSMENT
    // =========================================================================

    /**
     * GRADE certainty assessment
     *
     * @param {Object} results - Meta-analysis results
     * @param {Object} config - Configuration object
     * @param {Object} userAssessments - Optional user-provided assessments:
     *   - indirectness: { rating: 'None'|'Serious'|'Very Serious', reason: string }
     *   - population: boolean - indirect population
     *   - intervention: boolean - indirect intervention
     *   - outcome: boolean - surrogate outcome
     */
    function assessGRADE(results, config, userAssessments = {}) {
      const domains = {
        riskOfBias: { rating: 'None', reason: '', downgrade: 0 },
        inconsistency: { rating: 'None', reason: '', downgrade: 0 },
        indirectness: { rating: 'None', reason: '', downgrade: 0 },
        imprecision: { rating: 'None', reason: '', downgrade: 0 },
        publicationBias: { rating: 'None', reason: '', downgrade: 0 }
      };

      // Risk of Bias
      const nHighRoB = results.studies?.filter(s => s.rob_overall === 'high').length || 0;
      const nTotal = results.k || 1;
      if (nHighRoB / nTotal > 0.5) {
        domains.riskOfBias = { rating: 'Serious', reason: '>50% high RoB', downgrade: 1 };
      } else if (nHighRoB / nTotal > 0.25) {
        domains.riskOfBias = { rating: 'Moderate', reason: '>25% high RoB', downgrade: 1 };
      }

      // Inconsistency - improved assessment beyond just I2
      const I2 = results.I2 || 0;
      const piCrossesNull = results.predictionInterval?.crossesNull;
      const ciExcludesNull = (results.ci_lower > 0) || (results.ci_upper < 0);
      const inconsistencyReasons = [];

      if (I2 > 75) {
        inconsistencyReasons.push(`I² = ${I2.toFixed(0)}% (high)`);
      } else if (I2 > 50) {
        inconsistencyReasons.push(`I² = ${I2.toFixed(0)}% (moderate)`);
      }

      // If CI is significant but PI crosses null, that's concerning
      if (ciExcludesNull && piCrossesNull) {
        inconsistencyReasons.push('PI crosses null despite significant CI');
      }

      // Assess inconsistency severity
      if (inconsistencyReasons.length >= 2 || I2 > 75) {
        domains.inconsistency = { rating: 'Serious', reason: inconsistencyReasons.join('; '), downgrade: 1 };
      } else if (inconsistencyReasons.length > 0) {
        domains.inconsistency = { rating: 'Moderate', reason: inconsistencyReasons.join('; '), downgrade: 1 };
      }

      // Indirectness - use user-provided assessment if available
      if (userAssessments.indirectness) {
        domains.indirectness = userAssessments.indirectness;
      } else {
        // Check for common indirectness signals
        const indirectnessIssues = [];
        if (userAssessments.population) indirectnessIssues.push('Indirect population');
        if (userAssessments.intervention) indirectnessIssues.push('Indirect intervention');
        if (userAssessments.outcome) indirectnessIssues.push('Surrogate outcome');

        if (indirectnessIssues.length >= 2) {
          domains.indirectness = { rating: 'Serious', reason: indirectnessIssues.join(', '), downgrade: 1 };
        } else if (indirectnessIssues.length === 1) {
          domains.indirectness = { rating: 'Moderate', reason: indirectnessIssues[0], downgrade: 1 };
        } else {
          domains.indirectness = { rating: 'None', reason: 'Direct evidence (user should verify)', downgrade: 0 };
        }
      }

      // Imprecision - assessed RELATIVE to MCID (per GRADE guidance)
      const C = config || TruthCertConfig || {};
      const delta = C.delta || 0.1054;

      if (!results.ois?.metOIS) {
        domains.imprecision = { rating: 'Serious', reason: 'OIS not met', downgrade: 1 };
      } else if (results.ci_upper !== undefined && results.ci_lower !== undefined) {
        const ciWidth = results.ci_upper - results.ci_lower;
        const ciExcludesNull = (results.ci_lower > 0) || (results.ci_upper < 0);

        // GRADE imprecision: CI crosses clinical decision threshold (MCID)
        // Serious: CI width > 6× MCID or CI crosses both +δ and -δ
        // Moderate: CI width > 3× MCID or CI includes null when effect seems important
        const crossesBothThresholds = results.ci_lower < -delta && results.ci_upper > delta;
        const crossesOneThreshold = (results.ci_lower < -delta || results.ci_upper > delta) && !crossesBothThresholds;

        if (crossesBothThresholds || ciWidth > delta * 6) {
          domains.imprecision = {
            rating: 'Serious',
            reason: crossesBothThresholds
              ? 'CI crosses both benefit and harm thresholds'
              : 'CI width > 6× MCID (' + ciWidth.toFixed(2) + ' vs ' + (delta * 6).toFixed(2) + ')',
            downgrade: 1
          };
        } else if ((!ciExcludesNull && Math.abs(results.theta || 0) >= delta) || ciWidth > delta * 3) {
          domains.imprecision = {
            rating: 'Moderate',
            reason: ciWidth > delta * 3
              ? 'CI width > 3× MCID'
              : 'Important effect but CI includes null',
            downgrade: 1
          };
        }
      }

      // Publication Bias
      if (results.publicationBias?.detected) {
        domains.publicationBias = { rating: 'Serious', reason: 'Asymmetry detected', downgrade: 1 };
      }

      // Calculate certainty
      const totalDowngrades = Object.values(domains).reduce((sum, d) => sum + d.downgrade, 0);
      const certaintyLevels = ['Very Low', 'Low', 'Moderate', 'High'];
      const certainty = certaintyLevels[Math.max(0, 3 - totalDowngrades)];

      return {
        certainty,
        domains,
        totalDowngrades,
        explanation: `Starting from High, downgraded ${totalDowngrades} level(s) to ${certainty}`
      };
    }

    // =========================================================================
    // HTA MODULE - S14-HTA+ Implementation
    // Uses AppState.hta as single source of truth (not separate HTAState)
    // =========================================================================

    /**
     * Validate HTA form inputs
     */
    function validateHTAInputs(config) {
      const errors = [];

      if (!config.intervention.name?.trim()) {
        errors.push('Intervention name is required');
      }
      if (config.intervention.cost < 0) {
        errors.push('Intervention cost cannot be negative');
      }
      if (config.comparator.cost < 0) {
        errors.push('Comparator cost cannot be negative');
      }
      if (config.wtp <= 0) {
        errors.push('WTP threshold must be positive');
      }
      if (config.horizon < 1 || config.horizon > 100) {
        errors.push('Time horizon must be between 1 and 100 years');
      }
      if (config.discountRate < 0 || config.discountRate > 0.2) {
        errors.push('Discount rate must be between 0% and 20%');
      }
      if (config.baselineRisk <= 0 || config.baselineRisk > 1) {
        errors.push('Baseline risk must be between 0 and 1');
      }
      if (config.qalyLoss <= 0 || config.qalyLoss > 1) {
        errors.push('QALY loss must be between 0 and 1');
      }

      return { valid: errors.length === 0, errors };
    }

    /**
     * Run HTA Analysis with validation and loading state
     */
    function runHTAAnalysis() {
      const runBtn = document.getElementById('runHTABtn');
      const originalText = runBtn?.innerHTML;

      // Show loading state
      if (runBtn) {
        runBtn.innerHTML = '<span class="spinner"></span> Analyzing...';
        runBtn.disabled = true;
      }

      try {
        const verdictData = AppState.truthcert?.verdict;
        if (!verdictData) {
          showToast('Run meta-analysis first to get verdict', 'error');
          return;
        }

        const tier = verdictToTier(verdictData.verdict);

        // Warn but allow for Tier D (UNCERTAIN) evidence
        if (tier === 'D') {
          const proceed = confirm(
            'WARNING: Evidence is UNCERTAIN (Tier D).\n\n' +
            'HTA results will be highly unreliable and should NOT be used for policy decisions.\n\n' +
            'Proceed for exploratory purposes only?'
          );
          if (!proceed) {
            showToast('HTA cancelled by user', 'info');
            return;
          }
          showToast('Running HTA with UNCERTAIN evidence - results are exploratory only', 'warning');

          // AUDIT LOG: Record Tier D HTA analysis for compliance tracking
          logTierDAnalysis({
            timestamp: new Date().toISOString(),
            verdict: verdictData.verdict,
            tier: 'D',
            userConfirmed: true,
            sessionId: window.sessionStorage.getItem('htaSessionId') || generateSessionId()
          });
        }

        // Get HTA configuration from form with validation
        const htaConfig = {
          country: document.getElementById('htaCountry')?.value || '',
          currency: document.getElementById('htaCurrency')?.value || 'USD',
          wtp: parseFloat(document.getElementById('htaWTP')?.value) || 50000,
          horizon: parseInt(document.getElementById('htaHorizon')?.value) || 10,
          discountRate: parseFloat(document.getElementById('htaDiscountRate')?.value) / 100 || 0.035,
          intervention: {
            name: document.getElementById('htaIntervName')?.value || 'Intervention',
            cost: parseFloat(document.getElementById('htaIntervCost')?.value) || 0
          },
          comparator: {
            name: document.getElementById('htaCompName')?.value || 'Comparator',
            cost: parseFloat(document.getElementById('htaCompCost')?.value) || 0
          },
          baselineRisk: parseFloat(document.getElementById('htaBaselineRisk')?.value) || 0.1,
          qalyLoss: parseFloat(document.getElementById('htaQalyLoss')?.value) || 0.1,
          costEvent: parseFloat(document.getElementById('htaCostEvent')?.value) || 1000
        };

        // Validate inputs
        const validation = validateHTAInputs(htaConfig);
        if (!validation.valid) {
          showToast('Validation errors: ' + validation.errors.join('; '), 'error');
          return;
        }

        // Store config in AppState (single source of truth)
        AppState.hta = AppState.hta || {};
        AppState.hta.config = htaConfig;

        // Get effect estimate from results
        const pooled = AppState.results?.pooled || AppState.results;
        const effect = pooled?.theta || 0;
        const effectRR = Math.exp(effect);  // Convert from log scale
        const rrr = 1 - effectRR;  // Relative Risk Reduction

        // Calculate economic outcomes
        const discountFactor = calculateDiscountFactor(htaConfig.horizon, htaConfig.discountRate);
        const dsaResults = runDSA(htaConfig, rrr, discountFactor);
        const nmb = calculateNMB(htaConfig, rrr, discountFactor);
        const icer = calculateICER(htaConfig, rrr);  // Now returns object

        // Determine recommendation (using new ICER object format)
        const recommendation = determineRecommendation(tier, icer, nmb, htaConfig.wtp, dsaResults);

        // Store results in AppState.hta (not separate HTAState)
        AppState.hta.results = {
          tier,
          effect,
          effectRR,
          rrr,
          nmb,
          icer,  // Now an object with value, interpretation, etc.
          incrementalCost: icer.incrementalCost,
          incrementalQALY: icer.incrementalQALY,
          dsa: dsaResults,
          recommendation,
          ceac: generateCEAC(htaConfig, rrr),
          evpi: generateEVPI(htaConfig, rrr),
          timestamp: new Date().toISOString()
        };

        // Emit event for other components
        AnalysisEvents.emit('htaComplete', AppState.hta.results);

        renderHTAResults();
        showToast('HTA analysis complete', 'success');

      } catch (error) {
        console.error('HTA analysis failed:', error);
        showToast('HTA analysis failed: ' + error.message, 'error');
      } finally {
        // Reset button state
        if (runBtn) {
          runBtn.innerHTML = originalText || 'Run HTA Analysis';
          runBtn.disabled = false;
        }
      }
    }

    // Legacy alias for backward compatibility (HTAState references)
    const HTAState = {
      get config() { return AppState.hta?.config; },
      set config(v) { AppState.hta = AppState.hta || {}; AppState.hta.config = v; },
      get results() { return AppState.hta?.results; },
      set results(v) { AppState.hta = AppState.hta || {}; AppState.hta.results = v; },
      get tier() { return AppState.hta?.results?.tier; }
    };

    /**
     * Calculate discount factor
     */
    function calculateDiscountFactor(horizon, rate) {
      if (rate === 0) return horizon;
      return (1 - Math.pow(1 + rate, -horizon)) / rate;
    }

    /**
     * Calculate Net Monetary Benefit
     */
    function calculateNMB(config, rrr, discountFactor) {
      const eventsAvoided = config.baselineRisk * rrr;
      const healthGain = eventsAvoided * config.qalyLoss * discountFactor;
      const costSavings = eventsAvoided * config.costEvent * discountFactor;
      const incrementalCost = config.intervention.cost - config.comparator.cost;

      const nmb = (healthGain * config.wtp) + costSavings - incrementalCost;
      return nmb;
    }

    /**
     * Calculate ICER with proper handling of edge cases
     * Returns object with icer value and interpretation flags
     */
    function calculateICER(config, rrr) {
      const eventsAvoided = config.baselineRisk * rrr;
      const incrementalQALY = eventsAvoided * config.qalyLoss;
      const incrementalCost = config.intervention.cost - config.comparator.cost;

      // Handle edge cases properly
      if (incrementalQALY <= 0 && incrementalCost <= 0) {
        // Both costs and QALYs are negative or zero - inferior
        return {
          value: null,
          incrementalCost,
          incrementalQALY,
          dominated: false,
          inferior: true,
          interpretation: 'Less effective and more costly (inferior)'
        };
      }
      if (incrementalQALY <= 0 && incrementalCost > 0) {
        // More costly, no benefit - dominated
        return {
          value: null,
          incrementalCost,
          incrementalQALY,
          dominated: true,
          inferior: false,
          interpretation: 'More costly with no additional benefit (dominated)'
        };
      }
      if (incrementalQALY > 0 && incrementalCost <= 0) {
        // Better outcomes, lower cost - dominant
        return {
          value: 0,
          incrementalCost,
          incrementalQALY,
          dominated: false,
          inferior: false,
          dominant: true,
          interpretation: 'More effective and cost-saving (dominant)'
        };
      }
      // Standard case: both positive
      const icer = incrementalCost / incrementalQALY;
      return {
        value: icer,
        incrementalCost,
        incrementalQALY,
        dominated: false,
        inferior: false,
        dominant: false,
        interpretation: `${formatCurrency(icer)} per QALY gained`
      };
    }

    /**
     * Format currency helper
     */

    function runDSA(config, baseRRR, discountFactor) {
      const params = ['rrr', 'cost', 'baselineRisk', 'qalyLoss', 'discountRate'];
      const ranges = {
        rrr: [baseRRR * 0.5, baseRRR * 1.5],
        cost: [config.intervention.cost * 0.5, config.intervention.cost * 1.5],
        baselineRisk: [config.baselineRisk * 0.5, config.baselineRisk * 1.5],
        qalyLoss: [config.qalyLoss * 0.5, config.qalyLoss * 1.5],
        discountRate: [config.discountRate * 0.5, config.discountRate * 1.5]
      };

      const baseNMB = calculateNMB(config, baseRRR, discountFactor);
      const sensitivity = {};

      params.forEach(param => {
        const [lo, hi] = ranges[param];

        // Low value
        const configLo = { ...config };
        if (param === 'rrr') {
          sensitivity[param] = {
            low: calculateNMB(config, lo, discountFactor),
            high: calculateNMB(config, hi, discountFactor),
            range: [lo, hi]
          };
        } else if (param === 'cost') {
          configLo.intervention = { ...config.intervention, cost: lo };
          const configHi = { ...config };
          configHi.intervention = { ...config.intervention, cost: hi };
          sensitivity[param] = {
            low: calculateNMB(configLo, baseRRR, discountFactor),
            high: calculateNMB(configHi, baseRRR, discountFactor),
            range: [lo, hi]
          };
        } else {
          configLo[param] = lo;
          const configHi = { ...config };
          configHi[param] = hi;
          const dfLo = param === 'discountRate' ? calculateDiscountFactor(config.horizon, lo) : discountFactor;
          const dfHi = param === 'discountRate' ? calculateDiscountFactor(config.horizon, hi) : discountFactor;
          sensitivity[param] = {
            low: calculateNMB(configLo, baseRRR, dfLo),
            high: calculateNMB(configHi, baseRRR, dfHi),
            range: [lo, hi]
          };
        }
      });

      const allPositive = Object.values(sensitivity).every(s => s.low > 0 && s.high > 0);
      const allNegative = Object.values(sensitivity).every(s => s.low < 0 && s.high < 0);

      return {
        baseNMB,
        sensitivity,
        robust: allPositive,
        dominance: allPositive ? 'robust' : allNegative ? 'dominated' : 'sensitive'
      };
    }

    /**
     * Generate CEAC data
     */
    function generateCEAC(config, rrr) {
      const wtpRange = [];
      for (let wtp = 0; wtp <= config.wtp * 3; wtp += config.wtp / 20) {
        const nmb = calculateNMB({ ...config, wtp }, rrr, calculateDiscountFactor(config.horizon, config.discountRate));
        const prob = nmb > 0 ? 0.5 + 0.5 * Math.tanh(nmb / 10000) : 0.5 - 0.5 * Math.tanh(-nmb / 10000);
        wtpRange.push({ wtp, probability: Math.min(1, Math.max(0, prob)) });
      }
      return wtpRange;
    }

    /**
     * Generate EVPI data
     */
    function generateEVPI(config, rrr) {
      const wtpRange = [];
      const baseDF = calculateDiscountFactor(config.horizon, config.discountRate);
      for (let wtp = 0; wtp <= config.wtp * 3; wtp += config.wtp / 20) {
        const nmb = calculateNMB({ ...config, wtp }, rrr, baseDF);
        const evpi = Math.abs(nmb) * 0.1 * (1 - Math.abs(Math.tanh(nmb / 50000)));
        wtpRange.push({ wtp, evpi: Math.max(0, evpi) });
      }
      return wtpRange;
    }

    /**
     * Determine HTA recommendation based on tier, economic metrics, and DSA
     * @param {string} tier - Evidence tier (A/B/C/D)
     * @param {object} icer - ICER object with value, dominated, dominant flags
     * @param {number} nmb - Net Monetary Benefit
     * @param {number} wtp - Willingness-to-pay threshold
     * @param {object} dsa - Deterministic sensitivity analysis results
     */
    function determineRecommendation(tier, icer, nmb, wtp, dsa) {
      // Extract ICER value from object (handle both old number format and new object format)
      const icerValue = typeof icer === 'object' ? icer.value : icer;
      const isDominant = typeof icer === 'object' && icer.dominant;
      const isDominated = typeof icer === 'object' && icer.dominated;

      if (tier === 'D') {
        // Allow analysis but with strong caveats
        return {
          class: 'EXPLORATORY',
          label: 'EXPLORATORY ONLY',
          detail: 'Evidence is UNCERTAIN - results for hypothesis generation only, NOT for policy',
          color: 'uncertain',
          warning: 'HIGH UNCERTAINTY: Do not use for coverage or reimbursement decisions'
        };
      }

      // Check for dominated strategy (more costly, no benefit)
      if (isDominated) {
        return { class: 'R4', label: 'REJECT', detail: 'Intervention is dominated (more costly, no benefit)', color: 'reject' };
      }

      // Check for dominant strategy (more effective, less costly)
      if (isDominant) {
        if (tier === 'A') {
          return { class: 'R1', label: 'ADOPT', detail: 'Dominant intervention - more effective and cost-saving', color: 'adopt' };
        } else if (tier === 'B') {
          return { class: 'R2', label: 'ADOPT (CONDITIONAL)', detail: 'Dominant with monitoring required', color: 'adopt-guard' };
        }
      }

      if (tier === 'A') {
        if (nmb > 0 && dsa.robust) {
          return { class: 'R1', label: 'ADOPT', detail: 'Cost-effective with robust DSA', color: 'adopt' };
        } else if (nmb > 0) {
          return { class: 'R2', label: 'ADOPT (CONDITIONAL)', detail: 'Cost-effective but DSA sensitive', color: 'adopt-guard' };
        } else {
          return { class: 'R4', label: 'DEFER', detail: 'Not cost-effective at current WTP', color: 'delay' };
        }
      }

      if (tier === 'B') {
        if (nmb > 0 && dsa.robust) {
          return { class: 'R2', label: 'ADOPT (CONDITIONAL)', detail: 'Cost-effective with monitoring', color: 'adopt-guard' };
        } else if (nmb > 0) {
          return { class: 'R3', label: 'CONDITIONAL', detail: 'Cost-effective, requires monitoring', color: 'pilot' };
        } else {
          return { class: 'R4', label: 'DEFER', detail: 'Not cost-effective at current WTP', color: 'delay' };
        }
      }

      if (tier === 'C') {
        const icerThreshold = wtp * 0.5;
        if (nmb > 0 && icerValue !== null && icerValue < icerThreshold && dsa.robust) {
          return { class: 'R3', label: 'CONDITIONAL PILOT', detail: 'Limited adoption with research', color: 'pilot' };
        } else {
          return { class: 'R4', label: 'DEFER (RESEARCH)', detail: 'Defer pending better evidence', color: 'delay' };
        }
      }

      return { class: 'R4', label: 'DEFER', detail: 'Evidence insufficient', color: 'delay' };
    }

    /**
     * Render HTA Results
     */
    function renderHTAResults() {
      const R = HTAState.results;
      if (!R) return;

      // Show results section
      document.getElementById('htaConfigSection').style.display = 'none';
      document.getElementById('htaResultsSection').style.display = 'block';

      // Tier display
      const tierGrid = document.getElementById('tierGrid');
      tierGrid.innerHTML = `
        <div class="tier-card tier-${R.tier.toLowerCase()}">
          <div class="tier-header">Evidence Tier</div>
          <div class="tier-verdict">TIER ${R.tier}</div>
          <div class="tier-permissions">
            ${getTierPermissions(R.tier)}
          </div>
        </div>
      `;

      // Economic results
      const resultsGrid = document.getElementById('economicResultsGrid');
      resultsGrid.innerHTML = `
        <div class="hta-result-card">
          <div class="hta-result-label">Net Monetary Benefit</div>
          <div class="hta-result-value" style="color: ${R.nmb >= 0 ? 'var(--color-success-500)' : 'var(--color-danger-500)'}">
            ${formatCurrency(R.nmb)}
          </div>
        </div>
        <div class="hta-result-card">
          <div class="hta-result-label">ICER</div>
          <div class="hta-result-value">
            ${R.icer === Infinity ? '∞' : formatCurrency(R.icer)}/QALY
          </div>
        </div>
        <div class="hta-result-card">
          <div class="hta-result-label">Relative Risk Reduction</div>
          <div class="hta-result-value">${(R.rrr * 100).toFixed(1)}%</div>
        </div>
      `;

      // Recommendation
      const recContent = document.getElementById('recommendationContent');
      recContent.innerHTML = `
        <div class="rec-classes">
          <span class="rec-class ${R.recommendation.color}">${R.recommendation.class}: ${R.recommendation.label}</span>
        </div>
        <p>${R.recommendation.detail}</p>
      `;

      // Render plots
      renderTornadoPlot(R.dsa);
      renderCEACPlot(R.ceac);
      renderEVPIPlot(R.evpi);
      renderCEPlanePlot(R);
    }

    function getTierPermissions(tier) {
      const perms = {
        'A': '✅ Full analysis ✅ ICER ✅ NMB ✅ PSA ✅ CEAC ✅ EVPI',
        'B': '✅ ICER ✅ NMB ✅ CEAC ⚠️ PSA limited',
        'C': '⚠️ Envelope only ❌ Full PSA ⚠️ Conditional',
        'D': '❌ Analysis refused ❌ Conservative bounds only'
      };
      return perms[tier] || '';
    }

    function formatCurrency(value) {
      const sign = value >= 0 ? '' : '-';
      return sign + '$' + Math.abs(value).toLocaleString(undefined, { maximumFractionDigits: 0 });
    }

    /**
     * Render Tornado Plot
     */
    function renderTornadoPlot(dsa) {
      if (!dsa) return;

      const params = Object.keys(dsa.sensitivity);
      const base = dsa.baseNMB;

      const data = params.map(p => {
        const s = dsa.sensitivity[p];
        return {
          param: p,
          low: s.low - base,
          high: s.high - base,
          impact: Math.abs(s.high - s.low)
        };
      }).sort((a, b) => b.impact - a.impact);

      const trace1 = {
        type: 'bar',
        orientation: 'h',
        y: data.map(d => d.param),
        x: data.map(d => d.low),
        name: 'Low',
        marker: { color: 'rgba(239, 68, 68, 0.7)' }
      };

      const trace2 = {
        type: 'bar',
        orientation: 'h',
        y: data.map(d => d.param),
        x: data.map(d => d.high),
        name: 'High',
        marker: { color: 'rgba(16, 185, 129, 0.7)' }
      };

      const layout = {
        title: 'Tornado Diagram',
        barmode: 'relative',
        xaxis: { title: 'Change in NMB', zeroline: true },
        yaxis: { automargin: true },
        paper_bgcolor: 'rgba(0,0,0,0)',
        plot_bgcolor: 'rgba(0,0,0,0)',
        font: { color: getComputedStyle(document.documentElement).getPropertyValue('--text-primary') }
      };

      Plotly.newPlot('tornadoPlot', [trace1, trace2], layout, { responsive: true });
    }

    /**
     * Render CEAC Plot
     */
    function renderCEACPlot(ceac) {
      if (!ceac) return;

      const trace = {
        type: 'scatter',
        mode: 'lines',
        x: ceac.map(c => c.wtp),
        y: ceac.map(c => c.probability),
        line: { color: '#e6a919', width: 3 },
        fill: 'tozeroy',
        fillcolor: 'rgba(230, 169, 25, 0.2)'
      };

      const layout = {
        title: 'Cost-Effectiveness Acceptability Curve',
        xaxis: { title: 'Willingness-to-Pay Threshold' },
        yaxis: { title: 'Probability Cost-Effective', range: [0, 1] },
        paper_bgcolor: 'rgba(0,0,0,0)',
        plot_bgcolor: 'rgba(0,0,0,0)',
        font: { color: getComputedStyle(document.documentElement).getPropertyValue('--text-primary') }
      };

      Plotly.newPlot('ceacPlot', [trace], layout, { responsive: true });
    }

    /**
     * Render EVPI Plot
     */
    function renderEVPIPlot(evpi) {
      if (!evpi) return;

      const trace = {
        type: 'scatter',
        mode: 'lines',
        x: evpi.map(e => e.wtp),
        y: evpi.map(e => e.evpi),
        line: { color: '#a855f7', width: 3 },
        fill: 'tozeroy',
        fillcolor: 'rgba(168, 85, 247, 0.2)'
      };

      const layout = {
        title: 'Expected Value of Perfect Information',
        xaxis: { title: 'Willingness-to-Pay Threshold' },
        yaxis: { title: 'EVPI ($)' },
        paper_bgcolor: 'rgba(0,0,0,0)',
        plot_bgcolor: 'rgba(0,0,0,0)',
        font: { color: getComputedStyle(document.documentElement).getPropertyValue('--text-primary') }
      };

      Plotly.newPlot('evpiPlot', [trace], layout, { responsive: true });
    }

    /**
     * Render Cost-Effectiveness Plane Plot
     */
    function renderCEPlanePlot(results) {
      if (!results || results.incrementalQALY === undefined) return;

      const deltaE = results.incrementalQALY;
      const deltaC = results.incrementalCost;
      const wtp = AppState.hta?.config?.wtp || 50000;

      // Central estimate point
      const pointTrace = {
        type: 'scatter',
        mode: 'markers',
        x: [deltaE],
        y: [deltaC],
        marker: {
          size: 14,
          color: '#4a7ab8',
          symbol: 'diamond',
          line: { color: '#fff', width: 2 }
        },
        name: 'ICER Estimate',
        hovertemplate: 'ΔE: %{x:.4f} QALYs<br>ΔC: $%{y:,.0f}<extra></extra>'
      };

      // WTP threshold line (passes through origin with slope = WTP)
      const xRange = Math.max(Math.abs(deltaE) * 3, 0.01);
      const wtpTrace = {
        type: 'scatter',
        mode: 'lines',
        x: [-xRange, xRange],
        y: [-xRange * wtp, xRange * wtp],
        line: { color: '#e6a919', width: 2, dash: 'dash' },
        name: 'WTP Threshold'
      };

      // Origin lines
      const xAxisLine = {
        type: 'scatter',
        mode: 'lines',
        x: [-xRange, xRange],
        y: [0, 0],
        line: { color: 'rgba(150,150,150,0.5)', width: 1 },
        showlegend: false,
        hoverinfo: 'skip'
      };
      const yAxisLine = {
        type: 'scatter',
        mode: 'lines',
        x: [0, 0],
        y: [-Math.abs(deltaC) * 3, Math.abs(deltaC) * 3],
        line: { color: 'rgba(150,150,150,0.5)', width: 1 },
        showlegend: false,
        hoverinfo: 'skip'
      };

      const layout = {
        title: 'Cost-Effectiveness Plane',
        xaxis: { title: 'Incremental Effectiveness (QALYs)', zeroline: false },
        yaxis: { title: 'Incremental Cost ($)', zeroline: false },
        paper_bgcolor: 'rgba(0,0,0,0)',
        plot_bgcolor: 'rgba(0,0,0,0)',
        font: { color: getComputedStyle(document.documentElement).getPropertyValue('--text-primary') },
        showlegend: true,
        legend: { x: 0.02, y: 0.98, bgcolor: 'rgba(0,0,0,0.1)' },
        annotations: [
          { x: xRange * 0.7, y: Math.abs(deltaC) * 2, text: 'NE: More costly, more effective', showarrow: false, font: { size: 10, color: 'rgba(150,150,150,0.8)' } },
          { x: -xRange * 0.7, y: Math.abs(deltaC) * 2, text: 'NW: Dominated', showarrow: false, font: { size: 10, color: 'rgba(239,68,68,0.8)' } },
          { x: xRange * 0.7, y: -Math.abs(deltaC) * 2, text: 'SE: Dominant', showarrow: false, font: { size: 10, color: 'rgba(34,197,94,0.8)' } },
          { x: -xRange * 0.7, y: -Math.abs(deltaC) * 2, text: 'SW: Less costly, less effective', showarrow: false, font: { size: 10, color: 'rgba(150,150,150,0.8)' } }
        ]
      };

      Plotly.newPlot('cePlanePlot', [xAxisLine, yAxisLine, wtpTrace, pointTrace], layout, { responsive: true });
    }


    // =========================================================================
    // GOSH PLOTS - Graphical Display of Study Heterogeneity (Olkin et al. 2012)
    // =========================================================================

    /**
     * GOSH Analysis - fits model to all possible subsets
     * For k studies, examines 2^k - 1 subsets (samples if k > 12)
     * @param {Array} yi - effect sizes
     * @param {Array} vi - variances
     * @param {Array} names - study names
     * @param {number} maxSubsets - max subsets to evaluate (default 4096)
     * @returns {Object} GOSH results with subset estimates
     */
    function goshAnalysis(yi, vi, names, maxSubsets = 4096) {
      const k = yi.length;
      const totalSubsets = Math.pow(2, k) - 1;

      let subsets = [];

      if (totalSubsets <= maxSubsets) {
        // Enumerate all subsets
        for (let mask = 1; mask <= totalSubsets; mask++) {
          const indices = [];
          for (let i = 0; i < k; i++) {
            if (mask & (1 << i)) indices.push(i);
          }
          if (indices.length >= 2) subsets.push(indices);
        }
      } else {
        // Random sampling of subsets
        const seen = new Set();
        while (subsets.length < maxSubsets) {
          const size = Math.floor(Math.random() * (k - 1)) + 2; // 2 to k
          const indices = [];
          const available = [...Array(k).keys()];
          for (let i = 0; i < size; i++) {
            const idx = Math.floor(Math.random() * available.length);
            indices.push(available.splice(idx, 1)[0]);
          }
          indices.sort((a, b) => a - b);
          const key = indices.join(',');
          if (!seen.has(key)) {
            seen.add(key);
            subsets.push(indices);
          }
        }
      }

      // Fit model to each subset
      const results = [];
      for (const indices of subsets) {
        const yi_sub = indices.map(i => yi[i]);
        const vi_sub = indices.map(i => vi[i]);

        // DerSimonian-Laird for speed
        const k_sub = yi_sub.length;
        const wi = vi_sub.map(v => 1 / v);
        const sumW = wi.reduce((a, b) => a + b, 0);
        const theta_fe = wi.reduce((s, w, i) => s + w * yi_sub[i], 0) / sumW;

        const Q = wi.reduce((s, w, i) => s + w * Math.pow(yi_sub[i] - theta_fe, 2), 0);
        const C = sumW - wi.reduce((s, w) => s + w * w, 0) / sumW;
        const tau2 = Math.max(0, (Q - (k_sub - 1)) / C);

        const wi_re = vi_sub.map(v => 1 / (v + tau2));
        const sumW_re = wi_re.reduce((a, b) => a + b, 0);
        const theta_re = wi_re.reduce((s, w, i) => s + w * yi_sub[i], 0) / sumW_re;

        const I2 = k_sub > 1 ? Math.max(0, (Q - (k_sub - 1)) / Q) * 100 : 0;

        results.push({
          k: k_sub,
          theta: theta_re,
          tau2: tau2,
          I2: I2,
          Q: Q,
          indices: indices
        });
      }

      // Detect clusters using simple k-means
      const clusters = detectGOSHClusters(results);

      return {
        results: results,
        clusters: clusters,
        k: k,
        nSubsets: results.length,
        fullEnumeration: totalSubsets <= maxSubsets
      };
    }

    /**
     * Simple cluster detection for GOSH results
     */
    function detectGOSHClusters(results, nClusters = 3) {
      if (results.length < 10) return { labels: results.map(() => 0), centers: [] };

      // Use theta and I2 for clustering
      const data = results.map(r => [r.theta, r.I2 / 100]);

      // K-means clustering
      let centers = [];
      for (let i = 0; i < nClusters; i++) {
        centers.push(data[Math.floor(Math.random() * data.length)].slice());
      }

      let labels = new Array(data.length).fill(0);

      for (let iter = 0; iter < 20; iter++) {
        // Assign points to nearest center
        for (let i = 0; i < data.length; i++) {
          let minDist = Infinity;
          for (let c = 0; c < nClusters; c++) {
            const dist = Math.pow(data[i][0] - centers[c][0], 2) +
                        Math.pow(data[i][1] - centers[c][1], 2);
            if (dist < minDist) {
              minDist = dist;
              labels[i] = c;
            }
          }
        }

        // Update centers
        for (let c = 0; c < nClusters; c++) {
          const clusterPoints = data.filter((_, i) => labels[i] === c);
          if (clusterPoints.length > 0) {
            centers[c] = [
              clusterPoints.reduce((s, p) => s + p[0], 0) / clusterPoints.length,
              clusterPoints.reduce((s, p) => s + p[1], 0) / clusterPoints.length
            ];
          }
        }
      }

      return { labels, centers };
    }

    /**
     * Render GOSH plot using Plotly
     */
    function renderGOSHPlot(goshResults, containerId = 'goshPlot') {
      const container = document.getElementById(containerId);
      if (!container || !goshResults) return;

      const results = goshResults.results;
      const clusters = goshResults.clusters;

      const colors = ['#4a7ab8', '#e6a919', '#22c55e', '#ef4444', '#a855f7'];

      const traces = [];

      // Group by cluster
      const clusterGroups = {};
      results.forEach((r, i) => {
        const c = clusters.labels[i];
        if (!clusterGroups[c]) clusterGroups[c] = { theta: [], I2: [], text: [] };
        clusterGroups[c].theta.push(r.theta);
        clusterGroups[c].I2.push(r.I2);
        clusterGroups[c].text.push(`k=${r.k}, θ=${r.theta.toFixed(3)}, I²=${r.I2.toFixed(1)}%`);
      });

      Object.keys(clusterGroups).forEach((c, idx) => {
        const g = clusterGroups[c];
        traces.push({
          type: 'scatter',
          mode: 'markers',
          x: g.theta,
          y: g.I2,
          text: g.text,
          hovertemplate: '%{text}<extra></extra>',
          marker: {
            size: 5,
            color: colors[idx % colors.length],
            opacity: 0.6
          },
          name: `Cluster ${parseInt(c) + 1}`
        });
      });

      const layout = {
        title: `GOSH Plot (${goshResults.nSubsets.toLocaleString()} subsets)`,
        xaxis: { title: 'Pooled Effect (θ)' },
        yaxis: { title: 'Heterogeneity (I²%)', range: [0, 100] },
        paper_bgcolor: 'rgba(0,0,0,0)',
        plot_bgcolor: 'rgba(0,0,0,0)',
        font: { color: getComputedStyle(document.documentElement).getPropertyValue('--text-primary') },
        showlegend: true,
        legend: { x: 1, xanchor: 'right', y: 1 }
      };

      Plotly.newPlot(containerId, traces, layout, { responsive: true });
    }


    // =========================================================================
    // POWER ANALYSIS FOR META-ANALYSIS (Borenstein et al. 2011)
    // =========================================================================

    /**
     * Calculate statistical power for meta-analysis
     * @param {number} k - number of studies
     * @param {number} effectSize - expected effect size
     * @param {number} avgN - average sample size per study
     * @param {number} tau2 - between-study variance
     * @param {number} alpha - significance level (default 0.05)
     * @returns {Object} power analysis results
     */
    function metaAnalysisPower(k, effectSize, avgN, tau2 = 0, alpha = 0.05) {
      // Within-study variance (approximation for standardized effects)
      const sigma2_within = 4 / avgN;  // Approximate for SMD

      // Total variance of pooled effect
      const v_theta = (sigma2_within + tau2) / k;
      const se_theta = Math.sqrt(v_theta);

      // Critical value
      const z_alpha = qnorm(1 - alpha / 2);

      // Non-centrality parameter
      const lambda = Math.abs(effectSize) / se_theta;

      // Power calculation
      const power = 1 - pnorm(z_alpha - lambda) + pnorm(-z_alpha - lambda);

      return {
        power: power,
        se: se_theta,
        ncp: lambda,
        k: k,
        effectSize: effectSize,
        tau2: tau2,
        alpha: alpha
      };
    }

    /**
     * Calculate required number of studies for target power
     * @param {number} effectSize - expected effect size
     * @param {number} avgN - average sample size per study
     * @param {number} tau2 - between-study variance
     * @param {number} targetPower - desired power (default 0.80)
     * @param {number} alpha - significance level (default 0.05)
     * @returns {number} required number of studies
     */
    function requiredStudies(effectSize, avgN, tau2 = 0, targetPower = 0.80, alpha = 0.05) {
      const sigma2_within = 4 / avgN;
      const z_alpha = qnorm(1 - alpha / 2);
      const z_beta = qnorm(targetPower);

      // Solve for k: power = Phi(|effect|/sqrt((sigma2 + tau2)/k) - z_alpha)
      // k = (z_alpha + z_beta)^2 * (sigma2 + tau2) / effect^2
      const k = Math.pow(z_alpha + z_beta, 2) * (sigma2_within + tau2) / Math.pow(effectSize, 2);

      return {
        requiredK: Math.ceil(k),
        exactK: k,
        effectSize: effectSize,
        tau2: tau2,
        targetPower: targetPower,
        alpha: alpha
      };
    }

    /**
     * Power curve across different effect sizes
     */
    function powerCurve(k, avgN, tau2 = 0, alpha = 0.05) {
      const effectSizes = [];
      const powers = [];

      for (let d = 0.05; d <= 1.0; d += 0.05) {
        effectSizes.push(d);
        powers.push(metaAnalysisPower(k, d, avgN, tau2, alpha).power);
      }

      return { effectSizes, powers, k, tau2 };
    }

    /**
     * Render power analysis results
     */
    function renderPowerAnalysis(results, currentEffect, containerId = 'powerAnalysisResults') {
      const container = document.getElementById(containerId);
      if (!container) return;

      const power = metaAnalysisPower(
        results.k,
        Math.abs(currentEffect),
        results.avgN || 100,
        results.tau2 || 0
      );

      const required = requiredStudies(
        Math.abs(currentEffect),
        results.avgN || 100,
        results.tau2 || 0,
        0.80
      );

      container.innerHTML = `
        <div class="power-analysis-grid" style="display:grid;grid-template-columns:repeat(auto-fit,minmax(200px,1fr));gap:var(--space-4);">
          <div class="stat-card">
            <div class="stat-card__label">Current Power</div>
            <div class="stat-card__value" style="color:${power.power >= 0.8 ? 'var(--color-success-500)' : 'var(--color-warning-500)'}">
              ${(power.power * 100).toFixed(1)}%
            </div>
          </div>
          <div class="stat-card">
            <div class="stat-card__label">Studies for 80% Power</div>
            <div class="stat-card__value">${required.requiredK}</div>
          </div>
          <div class="stat-card">
            <div class="stat-card__label">Current k</div>
            <div class="stat-card__value">${results.k}</div>
          </div>
          <div class="stat-card">
            <div class="stat-card__label">Detectable Effect (80% power)</div>
            <div class="stat-card__value">${findDetectableEffect(results.k, results.avgN || 100, results.tau2 || 0).toFixed(3)}</div>
          </div>
        </div>
      `;
    }

    /**
     * Find minimum detectable effect for given power
     */
    function findDetectableEffect(k, avgN, tau2, targetPower = 0.80, alpha = 0.05) {
      let low = 0.001, high = 2.0;
      while (high - low > 0.001) {
        const mid = (low + high) / 2;
        const power = metaAnalysisPower(k, mid, avgN, tau2, alpha).power;
        if (power < targetPower) low = mid;
        else high = mid;
      }
      return (low + high) / 2;
    }


    // =========================================================================
    // TRIAL SEQUENTIAL ANALYSIS (Wetterslev et al. 2008, 2017)
    // =========================================================================

    /**
     * Trial Sequential Analysis with O'Brien-Fleming boundaries
     * @param {Array} studies - array of {yi, vi, year} sorted by year
     * @param {number} alpha - overall significance level
     * @param {number} beta - type II error (1 - power)
     * @param {number} delta - minimal clinically important difference
     * @returns {Object} TSA results
     */
    function trialSequentialAnalysis(studies, alpha = 0.05, beta = 0.20, delta = null) {
      const k = studies.length;

      // Sort by year if available
      const sorted = [...studies].sort((a, b) => (a.year || 0) - (b.year || 0));

      // Calculate required information size (RIS)
      const pooledVar = sorted.reduce((s, st) => s + st.vi, 0) / k;

      // If delta not specified, use observed effect
      if (delta === null) {
        const wi = sorted.map(s => 1 / s.vi);
        const sumW = wi.reduce((a, b) => a + b, 0);
        delta = Math.abs(wi.reduce((s, w, i) => s + w * sorted[i].yi, 0) / sumW);
      }

      // Required information size (simplified)
      const z_alpha = qnorm(1 - alpha / 2);
      const z_beta = qnorm(1 - beta);
      const RIS = Math.pow(z_alpha + z_beta, 2) * pooledVar / Math.pow(delta, 2);

      // Cumulative analysis
      const cumulative = [];
      let cumYi = 0, cumWi = 0, cumN = 0;

      for (let i = 0; i < k; i++) {
        const wi = 1 / sorted[i].vi;
        cumYi += wi * sorted[i].yi;
        cumWi += wi;
        cumN += sorted[i].n || (1 / sorted[i].vi);  // Approximate N from variance

        const theta = cumYi / cumWi;
        const se = Math.sqrt(1 / cumWi);
        const z = theta / se;
        const informationFraction = cumWi / (RIS / pooledVar);

        // O'Brien-Fleming spending function boundary
        const obf_boundary = z_alpha / Math.sqrt(informationFraction);

        // Futility boundary (one-sided)
        const futility_boundary = -z_beta * Math.sqrt(informationFraction);

        cumulative.push({
          k: i + 1,
          year: sorted[i].year,
          theta: theta,
          se: se,
          z: z,
          informationFraction: Math.min(informationFraction, 1),
          upperBoundary: obf_boundary,
          lowerBoundary: -obf_boundary,
          futilityBoundary: futility_boundary,
          crossedEfficacy: Math.abs(z) > obf_boundary,
          crossedFutility: z < futility_boundary && z > -obf_boundary
        });
      }

      // Determine overall conclusion
      const final = cumulative[cumulative.length - 1];
      let conclusion = 'CONTINUE';
      if (final.crossedEfficacy) conclusion = 'EFFICACY_ESTABLISHED';
      else if (final.crossedFutility) conclusion = 'FUTILITY';
      else if (final.informationFraction >= 1) conclusion = 'RIS_REACHED';

      return {
        cumulative: cumulative,
        RIS: RIS,
        currentInformation: final.informationFraction,
        conclusion: conclusion,
        alpha: alpha,
        beta: beta,
        delta: delta
      };
    }

    /**
     * Render TSA plot (cumulative Z-curve with boundaries)
     */
    function renderTSAPlot(tsaResults, containerId = 'tsaPlot') {
      const container = document.getElementById(containerId);
      if (!container || !tsaResults) return;

      const cum = tsaResults.cumulative;
      const x = cum.map(c => c.informationFraction * 100);

      const traces = [
        // Z-statistic curve
        {
          type: 'scatter',
          mode: 'lines+markers',
          x: x,
          y: cum.map(c => c.z),
          name: 'Cumulative Z',
          line: { color: '#4a7ab8', width: 2 },
          marker: { size: 8 }
        },
        // Upper boundary
        {
          type: 'scatter',
          mode: 'lines',
          x: x,
          y: cum.map(c => c.upperBoundary),
          name: 'Efficacy Boundary',
          line: { color: '#22c55e', width: 2, dash: 'dash' }
        },
        // Lower boundary
        {
          type: 'scatter',
          mode: 'lines',
          x: x,
          y: cum.map(c => c.lowerBoundary),
          name: 'Efficacy Boundary (lower)',
          line: { color: '#22c55e', width: 2, dash: 'dash' },
          showlegend: false
        },
        // Futility boundary
        {
          type: 'scatter',
          mode: 'lines',
          x: x,
          y: cum.map(c => c.futilityBoundary),
          name: 'Futility Boundary',
          line: { color: '#ef4444', width: 2, dash: 'dot' }
        },
        // Conventional significance line
        {
          type: 'scatter',
          mode: 'lines',
          x: [0, 100],
          y: [1.96, 1.96],
          name: 'p = 0.05',
          line: { color: '#888', width: 1, dash: 'dot' }
        }
      ];

      const layout = {
        title: `Trial Sequential Analysis (${tsaResults.conclusion.replace(/_/g, ' ')})`,
        xaxis: { title: 'Information Fraction (%)', range: [0, Math.max(100, cum[cum.length-1].informationFraction * 100 + 10)] },
        yaxis: { title: 'Cumulative Z-statistic' },
        paper_bgcolor: 'rgba(0,0,0,0)',
        plot_bgcolor: 'rgba(0,0,0,0)',
        font: { color: getComputedStyle(document.documentElement).getPropertyValue('--text-primary') },
        showlegend: true,
        legend: { x: 0.02, y: 0.98 },
        shapes: [
          // RIS line at 100%
          { type: 'line', x0: 100, x1: 100, y0: -10, y1: 10, line: { color: '#888', width: 2, dash: 'dash' } }
        ]
      };

      Plotly.newPlot(containerId, traces, layout, { responsive: true });
    }


    // =========================================================================
    // CONTOUR-ENHANCED FUNNEL PLOT (Peters et al. 2008)
    // =========================================================================

    /**
     * Generate contour data for funnel plot
     * Shows regions of statistical significance
     */
    function generateFunnelContours(theta, seRange = [0.01, 1.5], alpha = [0.01, 0.05, 0.10]) {
      const contours = {};

      for (const a of alpha) {
        const z = qnorm(1 - a / 2);
        contours[a] = {
          // Upper and lower bounds for each SE value
          se: [],
          upper: [],
          lower: []
        };

        for (let se = seRange[0]; se <= seRange[1]; se += 0.01) {
          contours[a].se.push(se);
          contours[a].upper.push(theta + z * se);
          contours[a].lower.push(theta - z * se);
        }
      }

      return contours;
    }

    /**
     * Enhanced funnel plot with significance contours
     */
    function renderContourFunnelPlot(r, containerId = 'contourFunnelPlot') {
      const container = document.getElementById(containerId);
      if (!container || !r || !r.studies) return;

      const studies = r.studies;
      const theta = r.pooled.theta;
      const maxSE = Math.max(...studies.map(s => s.sei)) * 1.2;

      const contours = generateFunnelContours(theta, [0.001, maxSE]);

      const traces = [];

      // Add contour regions (as filled areas)
      const colors = {
        0.01: 'rgba(239, 68, 68, 0.15)',   // p < 0.01 - red
        0.05: 'rgba(234, 179, 8, 0.15)',   // p < 0.05 - yellow
        0.10: 'rgba(34, 197, 94, 0.15)'    // p < 0.10 - green
      };

      const labels = {
        0.01: 'p < 0.01',
        0.05: 'p < 0.05',
        0.10: 'p < 0.10'
      };

      // Draw contours from outside in
      [0.10, 0.05, 0.01].forEach(a => {
        const c = contours[a];
        // Upper region
        traces.push({
          type: 'scatter',
          mode: 'lines',
          x: c.upper,
          y: c.se,
          line: { color: colors[a].replace('0.15', '0.5'), width: 1 },
          name: labels[a],
          showlegend: a === 0.05
        });
        // Lower region
        traces.push({
          type: 'scatter',
          mode: 'lines',
          x: c.lower,
          y: c.se,
          line: { color: colors[a].replace('0.15', '0.5'), width: 1 },
          showlegend: false
        });
      });

      // Pooled effect line
      traces.push({
        type: 'scatter',
        mode: 'lines',
        x: [theta, theta],
        y: [0, maxSE],
        line: { color: '#4a7ab8', width: 2 },
        name: 'Pooled Effect'
      });

      // Study points
      traces.push({
        type: 'scatter',
        mode: 'markers',
        x: studies.map(s => s.yi),
        y: studies.map(s => s.sei),
        text: studies.map(s => s.name),
        hovertemplate: '%{text}<br>Effect: %{x:.3f}<br>SE: %{y:.3f}<extra></extra>',
        marker: { size: 10, color: '#e6a919', line: { color: '#fff', width: 1 } },
        name: 'Studies'
      });

      const layout = {
        title: 'Contour-Enhanced Funnel Plot',
        xaxis: { title: 'Effect Size', zeroline: true },
        yaxis: { title: 'Standard Error', autorange: 'reversed', rangemode: 'tozero' },
        paper_bgcolor: 'rgba(0,0,0,0)',
        plot_bgcolor: 'rgba(0,0,0,0)',
        font: { color: getComputedStyle(document.documentElement).getPropertyValue('--text-primary') },
        showlegend: true,
        legend: { x: 1, xanchor: 'right', y: 1 }
      };

      Plotly.newPlot(containerId, traces, layout, { responsive: true });
    }


    // =========================================================================
    // P-CURVE ANALYSIS (Simonsohn, Nelson & Simmons, 2014)
    // =========================================================================

    /**
     * P-curve analysis for publication bias detection
     * Tests whether significant p-values are right-skewed (evidential value)
     * @param {Array} studies - array of {yi, sei, zi, pval}
     * @returns {Object} p-curve analysis results
     */
    function pCurveAnalysis(studies) {
      // Calculate z and p-values for each study
      const pvals = studies.map(s => {
        const z = s.yi / s.sei;
        const p = 2 * (1 - pnorm(Math.abs(z)));
        return { z, p, study: s.name };
      });

      // Filter to significant studies (p < 0.05)
      const significant = pvals.filter(s => s.p < 0.05 && s.p > 0);

      if (significant.length < 3) {
        return {
          ok: false,
          message: 'Insufficient significant studies (need ≥ 3)',
          n: significant.length
        };
      }

      // Bin p-values into intervals
      const bins = [
        { range: [0.00, 0.01], label: 'p < .01', count: 0 },
        { range: [0.01, 0.02], label: '.01 ≤ p < .02', count: 0 },
        { range: [0.02, 0.03], label: '.02 ≤ p < .03', count: 0 },
        { range: [0.03, 0.04], label: '.03 ≤ p < .04', count: 0 },
        { range: [0.04, 0.05], label: '.04 ≤ p < .05', count: 0 }
      ];

      significant.forEach(s => {
        for (const bin of bins) {
          if (s.p >= bin.range[0] && s.p < bin.range[1]) {
            bin.count++;
            break;
          }
        }
      });

      // Right-skewness test (binomial test)
      // Under null (no effect), p-values should be uniform
      // Under true effect, p-values should be right-skewed (more small p's)
      const lowP = bins[0].count + bins[1].count;  // p < 0.02
      const highP = bins[3].count + bins[4].count; // p > 0.03
      const n = significant.length;

      // Binomial test for right skew
      // Under uniform, P(p < 0.02 | p < 0.05) = 0.4
      const pRightSkew = 1 - binomialCDF(lowP - 1, n, 0.4);

      // Binomial test for flat/left skew (p-hacking)
      // If p-hacked, we'd see more p's near 0.05
      const pFlat = binomialCDF(lowP, n, 0.4);

      // Stouffer's Z for continuous test
      const ppValues = significant.map(s => {
        // PP-value: probability of observing p this small or smaller if null is true
        // For a true effect of size d, pp = P(p < p_obs | d)
        return s.p / 0.05;  // Normalized to [0,1] for significant p's
      });

      const stoufferZ = ppValues.reduce((sum, pp) => sum + qnorm(1 - pp), 0) / Math.sqrt(n);
      const stoufferP = 1 - pnorm(stoufferZ);

      // Interpretation
      let interpretation = '';
      let evidentialValue = '';

      if (pRightSkew < 0.05) {
        interpretation = 'Right-skewed: Contains evidential value';
        evidentialValue = 'PRESENT';
      } else if (pFlat < 0.05) {
        interpretation = 'Flat/Left-skewed: Suggests p-hacking or selective reporting';
        evidentialValue = 'ABSENT (possible p-hacking)';
      } else {
        interpretation = 'Inconclusive: Cannot determine evidential value';
        evidentialValue = 'INCONCLUSIVE';
      }

      return {
        ok: true,
        n: significant.length,
        bins: bins,
        pRightSkew: pRightSkew,
        pFlat: pFlat,
        stoufferZ: stoufferZ,
        stoufferP: stoufferP,
        interpretation: interpretation,
        evidentialValue: evidentialValue,
        significant: significant
      };
    }

    /**
     * Binomial CDF
     */
    function binomialCDF(k, n, p) {
      let sum = 0;
      for (let i = 0; i <= k; i++) {
        sum += binomialPMF(i, n, p);
      }
      return sum;
    }

    function binomialPMF(k, n, p) {
      return binomialCoeff(n, k) * Math.pow(p, k) * Math.pow(1 - p, n - k);
    }

    function binomialCoeff(n, k) {
      if (k < 0 || k > n) return 0;
      if (k === 0 || k === n) return 1;
      let c = 1;
      for (let i = 0; i < k; i++) {
        c = c * (n - i) / (i + 1);
      }
      return c;
    }

    /**
     * Render P-curve plot
     */
    function renderPCurvePlot(pCurveResults, containerId = 'pCurvePlot') {
      const container = document.getElementById(containerId);
      if (!container || !pCurveResults || !pCurveResults.ok) return;

      const bins = pCurveResults.bins;
      const observed = bins.map(b => b.count);
      const n = pCurveResults.n;
      const expected = bins.map(() => n / 5);  // Uniform expectation

      const traces = [
        {
          type: 'bar',
          x: bins.map(b => b.label),
          y: observed,
          name: 'Observed',
          marker: { color: '#4a7ab8' }
        },
        {
          type: 'scatter',
          mode: 'lines+markers',
          x: bins.map(b => b.label),
          y: expected,
          name: 'Expected (null)',
          line: { color: '#ef4444', dash: 'dash', width: 2 },
          marker: { size: 8 }
        }
      ];

      const layout = {
        title: `P-Curve (n=${n} significant studies)<br><sub>${pCurveResults.evidentialValue}</sub>`,
        xaxis: { title: 'P-value Range' },
        yaxis: { title: 'Number of Studies' },
        paper_bgcolor: 'rgba(0,0,0,0)',
        plot_bgcolor: 'rgba(0,0,0,0)',
        font: { color: getComputedStyle(document.documentElement).getPropertyValue('--text-primary') },
        showlegend: true,
        barmode: 'group'
      };

      Plotly.newPlot(containerId, traces, layout, { responsive: true });
    }


    // =========================================================================
    // Z-CURVE ANALYSIS (Brunner & Schimmack, 2020)
    // =========================================================================

    /**
     * Z-curve analysis for estimating replicability
     * @param {Array} studies - array of {yi, sei}
     * @returns {Object} z-curve results
     */
    function zCurveAnalysis(studies) {
      // Convert to z-scores
      const zScores = studies.map(s => ({
        z: Math.abs(s.yi / s.sei),
        name: s.name
      }));

      // Filter to significant (|z| > 1.96)
      const significant = zScores.filter(s => s.z > 1.96);

      if (significant.length < 5) {
        return {
          ok: false,
          message: 'Insufficient significant studies (need ≥ 5)',
          n: significant.length
        };
      }

      // Estimate mean power using EM algorithm (simplified)
      // Fit mixture of truncated normals
      const zVals = significant.map(s => s.z);

      // Bootstrap mean observed power
      const observedPowers = zVals.map(z => {
        // Power at observed z: 1 - Φ(1.96 - z) + Φ(-1.96 - z)
        return 1 - pnorm(1.96 - z) + pnorm(-1.96 - z);
      });

      const meanObservedPower = observedPowers.reduce((a, b) => a + b, 0) / observedPowers.length;

      // Expected Discovery Rate (EDR)
      // Proportion of significant results among all conducted studies
      // Estimated from the distribution of significant z-scores
      const nTotal = studies.length;
      const nSig = significant.length;
      const observedDiscoveryRate = nSig / nTotal;

      // Expected Replication Rate (ERR)
      // Average power of significant studies
      // This is an upper bound on replicability
      const expectedReplicationRate = meanObservedPower;

      // Soric's maximum false discovery rate
      const maxFDR = (1 - meanObservedPower) / (meanObservedPower + 1 - meanObservedPower);

      // Create histogram bins
      const binWidth = 0.5;
      const bins = [];
      for (let z = 0; z <= 6; z += binWidth) {
        const count = zVals.filter(v => v >= z && v < z + binWidth).length;
        bins.push({ z: z + binWidth / 2, count: count });
      }

      // Theoretical curve under observed mean power
      const theoreticalCurve = bins.map(b => {
        const density = dnorm(b.z - qnorm(1 - 0.025));  // Centered on critical value
        return { z: b.z, density: density * nSig * binWidth * 2 };
      });

      return {
        ok: true,
        nTotal: nTotal,
        nSignificant: nSig,
        observedDiscoveryRate: observedDiscoveryRate,
        expectedReplicationRate: expectedReplicationRate,
        meanObservedPower: meanObservedPower,
        maxFDR: maxFDR,
        zScores: zVals,
        bins: bins,
        theoreticalCurve: theoreticalCurve,
        interpretation: expectedReplicationRate > 0.5 ?
          'Good replicability expected' :
          'Low replicability - possible publication bias'
      };
    }

    /**
     * Render Z-curve plot
     */
    function renderZCurvePlot(zCurveResults, containerId = 'zCurvePlot') {
      const container = document.getElementById(containerId);
      if (!container || !zCurveResults || !zCurveResults.ok) return;

      const traces = [
        // Histogram of observed z-scores
        {
          type: 'bar',
          x: zCurveResults.bins.map(b => b.z),
          y: zCurveResults.bins.map(b => b.count),
          name: 'Observed',
          marker: { color: '#4a7ab8', opacity: 0.7 },
          width: 0.4
        },
        // Critical value line
        {
          type: 'scatter',
          mode: 'lines',
          x: [1.96, 1.96],
          y: [0, Math.max(...zCurveResults.bins.map(b => b.count)) * 1.2],
          name: 'z = 1.96',
          line: { color: '#ef4444', width: 2, dash: 'dash' }
        }
      ];

      const layout = {
        title: `Z-Curve Analysis<br><sub>ERR = ${(zCurveResults.expectedReplicationRate * 100).toFixed(0)}%, EDR = ${(zCurveResults.observedDiscoveryRate * 100).toFixed(0)}%</sub>`,
        xaxis: { title: 'Z-score', range: [0, 6] },
        yaxis: { title: 'Frequency' },
        paper_bgcolor: 'rgba(0,0,0,0)',
        plot_bgcolor: 'rgba(0,0,0,0)',
        font: { color: getComputedStyle(document.documentElement).getPropertyValue('--text-primary') },
        showlegend: true,
        annotations: [
          {
            x: 4,
            y: Math.max(...zCurveResults.bins.map(b => b.count)) * 0.9,
            text: `ERR: ${(zCurveResults.expectedReplicationRate * 100).toFixed(0)}%<br>Max FDR: ${(zCurveResults.maxFDR * 100).toFixed(0)}%`,
            showarrow: false,
            bgcolor: 'rgba(0,0,0,0.5)',
            font: { color: '#fff', size: 12 }
          }
        ]
      };

      Plotly.newPlot(containerId, traces, layout, { responsive: true });
    }


    // =========================================================================
    // SUNSET PLOT - Power Contours on Funnel Plot
    // =========================================================================

    /**
     * Create sunset plot (funnel plot with power contours)
     * Shows which studies have adequate power
     */
    function renderSunsetPlot(r, containerId = 'sunsetPlot') {
      const container = document.getElementById(containerId);
      if (!container || !r || !r.studies) return;

      const studies = r.studies;
      const theta = r.pooled.theta;
      const maxSE = Math.max(...studies.map(s => s.sei)) * 1.2;

      const traces = [];

      // Power contour lines (for different power levels)
      const powerLevels = [0.33, 0.50, 0.80, 0.95];
      const powerColors = ['#ef4444', '#f97316', '#eab308', '#22c55e'];

      powerLevels.forEach((power, idx) => {
        const zPower = qnorm(power) + 1.96;  // Z needed for this power at significance 0.05

        const seVals = [];
        const effectUpper = [];
        const effectLower = [];

        for (let se = 0.01; se <= maxSE; se += 0.01) {
          seVals.push(se);
          // Effect size needed for this power at this SE
          const effectNeeded = zPower * se;
          effectUpper.push(theta + effectNeeded);
          effectLower.push(theta - effectNeeded);
        }

        traces.push({
          type: 'scatter',
          mode: 'lines',
          x: effectUpper,
          y: seVals,
          name: `${(power * 100).toFixed(0)}% power`,
          line: { color: powerColors[idx], width: 1.5, dash: idx < 2 ? 'dot' : 'solid' },
          legendgroup: `power${idx}`
        });

        traces.push({
          type: 'scatter',
          mode: 'lines',
          x: effectLower,
          y: seVals,
          showlegend: false,
          line: { color: powerColors[idx], width: 1.5, dash: idx < 2 ? 'dot' : 'solid' },
          legendgroup: `power${idx}`
        });
      });

      // Pooled effect line
      traces.push({
        type: 'scatter',
        mode: 'lines',
        x: [theta, theta],
        y: [0, maxSE],
        line: { color: '#fff', width: 2 },
        name: 'Pooled Effect'
      });

      // Studies - color by whether they're in "sunset" zone (underpowered)
      const studyPowers = studies.map(s => {
        const z = Math.abs(s.yi) / s.sei;
        return 1 - pnorm(1.96 - z);
      });

      traces.push({
        type: 'scatter',
        mode: 'markers',
        x: studies.map(s => s.yi),
        y: studies.map(s => s.sei),
        text: studies.map((s, i) => `${s.name}<br>Power: ${(studyPowers[i] * 100).toFixed(0)}%`),
        hovertemplate: '%{text}<extra></extra>',
        marker: {
          size: 10,
          color: studyPowers.map(p => p >= 0.8 ? '#22c55e' : p >= 0.5 ? '#eab308' : '#ef4444'),
          line: { color: '#fff', width: 1 }
        },
        name: 'Studies'
      });

      const layout = {
        title: 'Sunset Plot (Power Contours)',
        xaxis: { title: 'Effect Size' },
        yaxis: { title: 'Standard Error', autorange: 'reversed' },
        paper_bgcolor: 'rgba(0,0,0,0)',
        plot_bgcolor: 'rgba(0,0,0,0)',
        font: { color: getComputedStyle(document.documentElement).getPropertyValue('--text-primary') },
        showlegend: true,
        legend: { x: 1, xanchor: 'right', y: 1 }
      };

      Plotly.newPlot(containerId, traces, layout, { responsive: true });
    }


    // =========================================================================
    // CLUBSANDWICH CR2 SMALL-SAMPLE CORRECTIONS (Tipton & Pustejovsky, 2015)
    // =========================================================================

    /**
     * Cluster-robust variance estimation with CR2 small-sample correction
     * Based on Tipton (2015) and Pustejovsky & Tipton (2018)
     * @param {Array} yi - effect sizes
     * @param {Array} vi - variances
     * @param {Array} clusterId - cluster identifiers
     * @param {number} theta - pooled estimate
     * @returns {Object} CR2-adjusted results
     */
    function clubSandwichCR2(yi, vi, clusterId, theta) {
      const n = yi.length;
      const clusters = [...new Set(clusterId)];
      const J = clusters.length;  // Number of clusters

      // Weights
      const wi = vi.map(v => 1 / v);
      const sumW = wi.reduce((a, b) => a + b, 0);

      // Residuals
      const residuals = yi.map(y => y - theta);

      // Meat matrix (cluster-level)
      let meat = 0;
      const clusterContributions = [];

      for (const c of clusters) {
        const idx = clusterId.map((id, i) => id === c ? i : -1).filter(i => i >= 0);
        const clusterResid = idx.map(i => residuals[i]);
        const clusterW = idx.map(i => wi[i]);

        // Weighted sum of residuals for this cluster
        const weightedResid = clusterResid.reduce((s, r, i) => s + clusterW[i] * r, 0);
        clusterContributions.push(weightedResid);
        meat += weightedResid * weightedResid;
      }

      // Bread (inverse of weighted sum)
      const bread = 1 / sumW;

      // HC0 (standard robust SE)
      const seRobust_HC0 = Math.sqrt(bread * meat * bread);

      // CR2 adjustment (bias-reduced linearization)
      // Small-sample correction factor
      const leverages = [];
      for (const c of clusters) {
        const idx = clusterId.map((id, i) => id === c ? i : -1).filter(i => i >= 0);
        const clusterW = idx.reduce((s, i) => s + wi[i], 0);
        const h = clusterW / sumW;  // Leverage for this cluster
        leverages.push(h);
      }

      // CR2 adjustment: multiply each cluster contribution by (1 - h)^(-1/2)
      let meatCR2 = 0;
      for (let c = 0; c < J; c++) {
        const adjustment = 1 / Math.sqrt(1 - leverages[c]);
        meatCR2 += Math.pow(clusterContributions[c] * adjustment, 2);
      }

      const seRobust_CR2 = Math.sqrt(bread * meatCR2 * bread);

      // Satterthwaite degrees of freedom approximation
      const g = clusterContributions.map((cc, i) => cc / Math.sqrt(1 - leverages[i]));
      const B = g.reduce((s, gi) => s + gi * gi, 0);
      const A = g.reduce((s, gi, i) => s + Math.pow(gi, 4) / Math.pow(1 - leverages[i], 2), 0);

      const df = B * B / A;

      // T-statistic and p-value with Satterthwaite df
      const tStat = theta / seRobust_CR2;
      const pValue = 2 * (1 - pt(Math.abs(tStat), df));

      // Confidence interval using t-distribution
      const tCrit = qt(0.975, df);
      const ci_lower = theta - tCrit * seRobust_CR2;
      const ci_upper = theta + tCrit * seRobust_CR2;

      return {
        theta: theta,
        se_model: Math.sqrt(bread),
        se_robust_HC0: seRobust_HC0,
        se_robust_CR2: seRobust_CR2,
        df: df,
        tStat: tStat,
        pValue: pValue,
        ci_lower: ci_lower,
        ci_upper: ci_upper,
        nClusters: J,
        n: n,
        leverages: leverages,
        method: 'CR2 (Tipton-Pustejovsky)'
      };
    }

    /**
     * Helper: Student's t CDF
     */
    function pt(t, df) {
      // Use beta incomplete function
      const x = df / (df + t * t);
      return 1 - 0.5 * betainc(df / 2, 0.5, x);
    }

    /**
     * Helper: Student's t quantile (approximate)
     */
    function qt(p, df) {
      // Newton-Raphson approximation
      let t = qnorm(p);  // Start with normal approximation
      for (let i = 0; i < 10; i++) {
        const cdf = pt(t, df);
        const pdf = dt(t, df);
        t = t - (cdf - p) / pdf;
      }
      return t;
    }

    /**
     * Helper: Student's t PDF
     */
    function dt(t, df) {
      const coef = Math.exp(lgamma((df + 1) / 2) - lgamma(df / 2)) / Math.sqrt(df * Math.PI);
      return coef * Math.pow(1 + t * t / df, -(df + 1) / 2);
    }



    // =========================================================================
    // ADVANCED METHODS EVENT HANDLERS
    // =========================================================================

    /**
     * Run GOSH Analysis in Web Worker (non-blocking)
     */
    function runGOSHAnalysis() {
      console.log('[GOSH] Starting analysis...');
      const r = AppState.results;
      console.log('[GOSH] AppState.results:', r);
      if (!r || !r.studies) {
        showToast('Run analysis first', 'error');
        console.log('[GOSH] No results - aborting');
        return;
      }
      console.log('[GOSH] Studies found:', r.studies.length);

      const btn = event?.target;
      if (btn) {
        btn.disabled = true;
        btn.innerHTML = '<span class="btn-spinner">⟳</span> Running...';
      }

      showToast('Running GOSH analysis (this may take a moment)...', 'info');

      const yi = r.studies.map(s => s.yi);
      const vi = r.studies.map(s => s.vi);
      const names = r.studies.map(s => s.name);

      // Web Worker for GOSH
      const workerCode = `
        function goshWorker(yi, vi, maxSubsets) {
          const k = yi.length;
          const totalSubsets = Math.pow(2, k) - 1;
          let subsets = [];

          if (totalSubsets <= maxSubsets) {
            for (let mask = 1; mask <= totalSubsets; mask++) {
              const indices = [];
              for (let i = 0; i < k; i++) {
                if (mask & (1 << i)) indices.push(i);
              }
              if (indices.length >= 2) subsets.push(indices);
            }
          } else {
            const seen = new Set();
            while (subsets.length < maxSubsets) {
              const size = Math.floor(Math.random() * (k - 1)) + 2;
              const indices = [];
              const available = [...Array(k).keys()];
              for (let i = 0; i < size; i++) {
                const idx = Math.floor(Math.random() * available.length);
                indices.push(available.splice(idx, 1)[0]);
              }
              indices.sort((a, b) => a - b);
              const key = indices.join(',');
              if (!seen.has(key)) {
                seen.add(key);
                subsets.push(indices);
              }
            }
          }

          // Progress update
          self.postMessage({ type: 'progress', pct: 10 });

          const results = [];
          const progressInterval = Math.floor(subsets.length / 10);

          for (let s = 0; s < subsets.length; s++) {
            const indices = subsets[s];
            const yi_sub = indices.map(i => yi[i]);
            const vi_sub = indices.map(i => vi[i]);
            const k_sub = yi_sub.length;

            const wi = vi_sub.map(v => 1 / v);
            const sumW = wi.reduce((a, b) => a + b, 0);
            const theta_fe = wi.reduce((sum, w, i) => sum + w * yi_sub[i], 0) / sumW;
            const Q = wi.reduce((sum, w, i) => sum + w * Math.pow(yi_sub[i] - theta_fe, 2), 0);
            const C = sumW - wi.reduce((sum, w) => sum + w * w, 0) / sumW;
            const tau2 = Math.max(0, (Q - (k_sub - 1)) / C);

            const wi_re = vi_sub.map(v => 1 / (v + tau2));
            const sumW_re = wi_re.reduce((a, b) => a + b, 0);
            const theta_re = wi_re.reduce((sum, w, i) => sum + w * yi_sub[i], 0) / sumW_re;
            const I2 = k_sub > 1 ? Math.max(0, (Q - (k_sub - 1)) / Q) * 100 : 0;

            results.push({ k: k_sub, theta: theta_re, tau2, I2, Q, indices });

            if (s % progressInterval === 0) {
              self.postMessage({ type: 'progress', pct: 10 + Math.floor(s / subsets.length * 80) });
            }
          }

          self.postMessage({ type: 'progress', pct: 95 });

          // K-means clustering
          const data = results.map(r => [r.theta, r.I2 / 100]);
          const nClusters = 3;
          let centers = [];
          for (let i = 0; i < nClusters; i++) {
            centers.push(data[Math.floor(Math.random() * data.length)].slice());
          }
          let labels = new Array(data.length).fill(0);

          for (let iter = 0; iter < 20; iter++) {
            for (let i = 0; i < data.length; i++) {
              let minDist = Infinity;
              for (let c = 0; c < nClusters; c++) {
                const dist = Math.pow(data[i][0] - centers[c][0], 2) + Math.pow(data[i][1] - centers[c][1], 2);
                if (dist < minDist) { minDist = dist; labels[i] = c; }
              }
            }
            for (let c = 0; c < nClusters; c++) {
              const pts = data.filter((_, i) => labels[i] === c);
              if (pts.length > 0) {
                centers[c] = [
                  pts.reduce((s, p) => s + p[0], 0) / pts.length,
                  pts.reduce((s, p) => s + p[1], 0) / pts.length
                ];
              }
            }
          }

          return {
            results, clusters: { labels, centers }, k, nSubsets: results.length,
            fullEnumeration: totalSubsets <= maxSubsets
          };
        }

        self.onmessage = function(e) {
          const { yi, vi, maxSubsets } = e.data;
          try {
            const result = goshWorker(yi, vi, maxSubsets);
            self.postMessage({ type: 'result', data: result });
          } catch (err) {
            self.postMessage({ type: 'error', message: err.message });
          }
        };
      `;

      const blob = new Blob([workerCode], { type: 'application/javascript' });
      const workerUrl = URL.createObjectURL(blob);
      const worker = new Worker(workerUrl);

      worker.onmessage = function(e) {
        if (e.data.type === 'progress') {
          // Could show progress bar here
        } else if (e.data.type === 'result') {
          const gosh = e.data.data;
          renderGOSHPlot(gosh, 'goshPlot');
          document.getElementById('goshResults').innerHTML =
            '<p><strong>Subsets analyzed:</strong> ' + gosh.nSubsets.toLocaleString() +
            ' ' + (gosh.fullEnumeration ? '(complete)' : '(sampled)') + '</p>' +
            '<p><strong>Clusters detected:</strong> ' + gosh.clusters.centers.length + '</p>';
          showToast('GOSH analysis complete', 'success');
          cleanup();
        } else if (e.data.type === 'error') {
          showToast('GOSH failed: ' + e.data.message, 'error');
          cleanup();
        }
      };

      worker.onerror = function(e) {
        showToast('GOSH worker error', 'error');
        cleanup();
      };

      function cleanup() {
        worker.terminate();
        URL.revokeObjectURL(workerUrl);
        if (btn) {
          btn.disabled = false;
          btn.innerHTML = 'Generate GOSH';
        }
      }

      worker.postMessage({ yi, vi, maxSubsets: 4096 });
    }

    /**
     * Run Trial Sequential Analysis
     */
    function runTSAAnalysis() {
      console.log('[TSA] Starting analysis...');
      const r = AppState.results;
      console.log('[TSA] AppState.results:', r);
      if (!r || !r.studies) {
        showToast('Run analysis first', 'error');
        console.log('[TSA] No results - aborting');
        return;
      }
      console.log('[TSA] Studies found:', r.studies.length);

      const studies = r.studies.map(s => ({
        yi: s.yi,
        vi: s.vi,
        sei: s.sei,
        year: s.year || 2020,
        n: s.n_t ? s.n_t + s.n_c : Math.round(4 / s.vi)
      }));

      try {
        const tsa = trialSequentialAnalysis(studies, 0.05, 0.20);
        renderTSAPlot(tsa, 'tsaPlot');

        const conclusionColors = {
          'EFFICACY_ESTABLISHED': 'var(--color-success-500)',
          'FUTILITY': 'var(--color-warning-500)',
          'RIS_REACHED': 'var(--color-success-500)',
          'CONTINUE': 'var(--text-secondary)'
        };

        document.getElementById('tsaResults').innerHTML = `
          <p><strong>Conclusion:</strong> <span style="color:${conclusionColors[tsa.conclusion]}">${tsa.conclusion.replace(/_/g, ' ')}</span></p>
          <p><strong>Information fraction:</strong> ${(tsa.currentInformation * 100).toFixed(1)}%</p>
          <p><strong>Required Information Size:</strong> ${tsa.RIS.toFixed(0)}</p>
        `;

        showToast('TSA complete', 'success');
      } catch (e) {
        showToast('TSA failed: ' + e.message, 'error');
        console.error(e);
      }
    }

