    /**
     * Run CR2 (clubSandwich) Analysis
     */
    function runCR2Analysis() {
      const r = AppState.results;
      if (!r || !r.studies) {
        showToast('Run analysis first', 'error');
        return;
      }

      const yi = r.studies.map(s => s.yi);
      const vi = r.studies.map(s => s.vi);

      // Use study indices as clusters (each study is its own cluster for independent studies)
      const clusterId = yi.map((_, i) => i);

      try {
        const cr2 = clubSandwichCR2(yi, vi, clusterId, r.pooled.theta);

        document.getElementById('cr2Results').innerHTML = `
          <div class="stat-grid" style="grid-template-columns: repeat(2, 1fr); gap: var(--space-3);">
            <div class="stat-card">
              <div class="stat-card__label">Model SE</div>
              <div class="stat-card__value">${cr2.se_model.toFixed(4)}</div>
            </div>
            <div class="stat-card">
              <div class="stat-card__label">CR2 Robust SE</div>
              <div class="stat-card__value">${cr2.se_robust_CR2.toFixed(4)}</div>
            </div>
            <div class="stat-card">
              <div class="stat-card__label">Satterthwaite df</div>
              <div class="stat-card__value">${cr2.df.toFixed(1)}</div>
            </div>
            <div class="stat-card">
              <div class="stat-card__label">p-value (CR2)</div>
              <div class="stat-card__value">${cr2.pValue < 0.001 ? '<0.001' : cr2.pValue.toFixed(4)}</div>
            </div>
          </div>
          <p style="margin-top: var(--space-3);"><strong>95% CI (CR2):</strong> [${cr2.ci_lower.toFixed(4)}, ${cr2.ci_upper.toFixed(4)}]</p>
          <p style="font-size: var(--text-xs); color: var(--text-secondary);">Method: ${cr2.method}</p>
        `;

        showToast('CR2 analysis complete', 'success');
      } catch (e) {
        showToast('CR2 failed: ' + e.message, 'error');
        console.error(e);
      }
    }

