    /**
     * Export verdict as YAML
     */
    function exportVerdictYAML() {
      const tc = AppState.truthcert;
      if (!tc) {
        showToast('No verdict data to export', 'warning');
        return;
      }

      let yaml = '# TruthCert-PairwisePro v1.0 Verdict Export\n';
      yaml += `timestamp: "${new Date().toISOString()}"\n`;
      yaml += `version: "1.0.0"\n\n`;

      yaml += 'verdict:\n';
      yaml += `  classification: "${tc.verdict?.verdict || 'N/A'}"\n`;
      yaml += `  tier: "${tc.verdict?.tier || 'N/A'}"\n`;
      yaml += `  severity: ${tc.verdict?.severity?.total || 0}\n`;

      yaml += '\nseverity_triggers:\n';
      (tc.verdict?.severity?.triggers || []).forEach(t => {
        yaml += `  - trigger: "${t.trigger}"\n    points: ${t.points}\n`;
      });

      yaml += '\nthreat_ledger:\n';
      (tc.threatLedger || []).forEach(t => {
        yaml += `  - name: "${t.name}"\n    status: "${t.status}"\n    detail: "${t.detail}"\n`;
      });

      yaml += '\ngrade:\n';
      yaml += `  certainty: "${tc.grade?.certainty || 'N/A'}"\n`;
      yaml += `  total_downgrades: ${tc.grade?.totalDowngrades || 0}\n`;

      const blob = new Blob([yaml], { type: 'text/yaml' });
      const a = document.createElement('a');
      a.href = URL.createObjectURL(blob);
      a.download = `truthcert_verdict_${new Date().toISOString().slice(0,10)}.yaml`;
      a.click();

      showToast('YAML exported successfully', 'success');
    }

