    // =========================================================================
    // INTEGRATION - TruthCert verdict analysis (called after main runAnalysis)
    // =========================================================================

    /**
     * Optimized Leave-One-Out influence calculation
     * Uses incremental update formulas instead of full recalculation
     */
    function computeInfluentialStudies(studies, pooledTheta, delta) {
      if (studies.length < 3) return { nFlagged: 0, influential: [] };

      const n = studies.length;
      const yi = studies.map(s => s.yi);
      const vi = studies.map(s => s.sei * s.sei);

      // Pre-compute total weights and sums for DL estimator
      const wi = vi.map(v => 1 / v);
      const sumW = wi.reduce((a, b) => a + b, 0);
      const sumWY = yi.reduce((sum, y, i) => sum + wi[i] * y, 0);
      const thetaFE = sumWY / sumW;

      // Compute Q statistic
      const Q = yi.reduce((sum, y, i) => sum + wi[i] * Math.pow(y - thetaFE, 2), 0);
      const df = n - 1;
      const C = sumW - yi.reduce((sum, _, i) => sum + wi[i] * wi[i] / sumW, 0);

      const influential = [];
      let nFlagged = 0;

      // For each study, compute leave-one-out estimate efficiently
      for (let i = 0; i < n; i++) {
        // Leave-one-out sums
        const sumW_loo = sumW - wi[i];
        const sumWY_loo = sumWY - wi[i] * yi[i];

        if (sumW_loo <= 0) continue;

        // Fixed-effect LOO estimate (approximation for speed)
        const theta_loo = sumWY_loo / sumW_loo;

        // Check if removing this study changes estimate significantly
        const diff = Math.abs(theta_loo - pooledTheta);
        if (diff > delta) {
          nFlagged++;
          influential.push({
            index: i,
            study: studies[i].name || `Study ${i + 1}`,
            difference: diff
          });
        }
      }

      return { nFlagged, influential };
    }

    /**
     * Compute TruthCert verdict analysis
     * Called directly after runAnalysis completes (no setTimeout needed)
     */
    function runTruthCertAnalysis() {
      try {
        const r = AppState.results;

        // Validate results are available
        if (!r) {
          // log.warn('TruthCert: No results available');
          return;
        }

        // Get pooled estimate from results
        const pooled = r.pooled || r;
        if (!pooled?.theta && pooled?.theta !== 0) {
          // log.warn('TruthCert: No pooled estimate available');
          return;
        }

        // Prepare studies array with yi/sei
        const studiesRaw = AppState.studies || [];
        const studies = studiesRaw.map((s, idx) => ({
          ...s,
          yi: s.yi !== undefined ? s.yi : r.yi?.[idx],
          sei: s.sei !== undefined ? s.sei : r.sei?.[idx]
        })).filter(s => s.yi !== undefined && s.sei !== undefined && s.sei > 0);

        if (studies.length < 2) {
          // log.warn('TruthCert: Insufficient valid studies');
          return;
        }

        // Compute additional analyses
        const yi = studies.map(s => s.yi);
        const vi = studies.map(s => s.sei * s.sei);

        // Run analyses with error handling
        const safeRun = (fn, fallback = null) => {
          try { return fn(); }
          catch (e) { return fallback; }
        };

        const pubBias = safeRun(() => selectSmallStudyTest(studies, TruthCertConfig), { biasDetected: false });
        const trimFill = safeRun(() => trimAndFill(studies, r), {});
        const breakdown = safeRun(() => breakdownPoint(studies, r), {});
        const fragility = safeRun(() => fragilityIndex(studies, TruthCertConfig), {});
        const perm = safeRun(() => permutationCI(studies, TruthCertConfig), {});
        const rho = safeRun(() => rhoSweep(studies), []);
        const ois = safeRun(() => calcOIS(studies, TruthCertConfig), {});
        const robSens = safeRun(() => robSensitivity(studies), {});
        const cumulative = safeRun(() => cumulativeMeta(studies), []);
        const cumulativePrec = safeRun(() => cumulativeByPrecision(studies), []);
        const profileLik = safeRun(() => profileLikelihoodTau2CI(studies), {});

        // Estimator comparison with configurable threshold
        const T = TruthCertConfig.thresholds?.estimatorSpread || {};
        const tau2DL = safeRun(() => estimateTau2_DL(yi, vi).tau2, 0);
        const tau2REML = safeRun(() => estimateTau2_REML(yi, vi).tau2, 0);
        const tau2PM = safeRun(() => estimateTau2_PM(yi, vi).tau2, 0);
        const estimatorSpread = Math.max(tau2DL, tau2REML, tau2PM) - Math.min(tau2DL, tau2REML, tau2PM);
        const tau2Stable = estimatorSpread < (T.stable || 0.1);

        // Optimized influence calculation
        const influence = computeInfluentialStudies(studies, pooled.theta, TruthCertConfig.delta);

        // Build comprehensive results
        const truthCertResults = {
          k: studies.length,
          theta: pooled.theta,
          se: pooled.se,
          ci_lower: pooled.ci_lower,
          ci_upper: pooled.ci_upper,
          pValue: pooled.p_value,
          I2: r.het?.I2 || pooled.I2 || 0,
          tau2: r.tau2Result?.tau2 || pooled.tau2 || tau2REML,
          tau2Stable,
          estimatorSpread,
          publicationBias: {
            method: pubBias?.method,
            detected: pubBias?.biasDetected,
            p: pubBias?.p
          },
          trimAndFill: trimFill,
          breakdownPoint: breakdown,
          fragilityIndex: fragility,
          permutationCI: perm,
          rhoSweep: rho,
          ois,
          robSensitivity: robSens,
          influence,
          predictionInterval: {
            lo: r.pi?.standard?.lower ?? pooled.pi_lower,
            hi: r.pi?.standard?.upper ?? pooled.pi_upper,
            crossesNull: (r.pi?.standard?.lower ?? pooled.pi_lower) < 0 &&
                         (r.pi?.standard?.upper ?? pooled.pi_upper) > 0
          },
          cumulative,
          cumulativeByPrecision: cumulativePrec,
          profileLikelihood: profileLik,
          studies
        };

        // Build threat ledger and verdict
        const threatLedger = buildThreatLedger(truthCertResults, TruthCertConfig);
        const verdictResult = determineVerdict(truthCertResults, TruthCertConfig);
        const grade = assessGRADE({ ...truthCertResults, studies }, TruthCertConfig);

        // Store in AppState
        AppState.truthcert = {
          verdict: {
            ...verdictResult,
            tier: verdictToTier(verdictResult.verdict)
          },
          threatLedger,
          grade,
          results: truthCertResults
        };

        // Also store for backward compatibility
        AppState.verdict = AppState.truthcert.verdict;
        AppState.threatLedger = threatLedger;
        AppState.grade = grade;

        // Render verdict panel
        renderVerdictPanel();

        // Enable HTA if not Tier D
        const htaPrereq = document.getElementById('htaPrerequisites');
        const htaConfig = document.getElementById('htaConfigSection');
        if (verdictResult.verdict !== 'UNCERTAIN') {
          if (htaPrereq) htaPrereq.style.display = 'none';
          if (htaConfig) htaConfig.style.display = 'block';
          populateHTADropdowns();
        }

        logDecision('check', `TruthCert analysis complete: ${verdictResult.verdict}`);

        // Emit event for other components
        AnalysisEvents.emit('verdictComplete', AppState.truthcert);

      } catch (error) {
        console.error('TruthCert analysis failed:', error);
        logDecision('error', 'TruthCert analysis failed: ' + error.message);
      }
    }

    /**
     * Render verdict panel content
     */
    function renderVerdictPanel() {
      const tc = AppState.truthcert;
      if (!tc) return;

      // Verdict card
      const verdictContainer = document.getElementById('verdictCardContainer');
      const verdictClass = tc.verdict.verdict.toLowerCase().replace('-', '-');
      verdictContainer.innerHTML = `
        <div class="verdict-card ${verdictClass}">
          <div class="verdict-label">TruthCert Evidence Verdict</div>
          <div class="verdict-value">${tc.verdict.verdict}</div>
          <div style="font-size: var(--text-sm); color: var(--text-secondary);">
            Tier ${tc.verdict.tier} | Severity: ${tc.verdict.severity.total}/13
          </div>
        </div>
      `;

      // Severity
      document.getElementById('severityContainer').style.display = 'block';
      const severityClass = tc.verdict.severity.total <= 2 ? 'low' : tc.verdict.severity.total <= 4 ? 'med' : tc.verdict.severity.total <= 6 ? 'high' : 'crit';
      document.getElementById('severityScore').innerHTML = `
        <div class="severity-score ${severityClass}">${tc.verdict.severity.total}</div>
      `;
      document.getElementById('severityTriggers').innerHTML = tc.verdict.severity.triggers.map(t =>
        `<div class="threat-item amber"><span>${t.trigger}</span> <span style="margin-left:auto">+${t.points}</span></div>`
      ).join('');

      // Threat Ledger
      document.getElementById('threatLedgerContainer').style.display = 'block';
      document.getElementById('threatLedgerItems').innerHTML = tc.threatLedger.map(t =>
        `<div class="threat-item ${t.status}">
          <div class="threat-status ${t.status}">${t.status === 'green' ? '✓' : t.status === 'amber' ? '!' : '✗'}</div>
          <div><strong>${t.name}</strong><br><span style="font-size: var(--text-xs); color: var(--text-secondary)">${t.detail}</span></div>
        </div>`
      ).join('');

      // Gates
      document.getElementById('gatesContainer').style.display = 'block';
      const gates = [
        { name: 'Evidence Base', pass: tc.results.k >= TruthCertConfig.minK },
        { name: 'Significance', pass: tc.results.pValue < 0.05 },
        { name: 'Heterogeneity', pass: tc.results.I2 <= 75 },
        { name: 'Publication Bias', pass: !tc.results.publicationBias.detected },
        { name: 'OIS Met', pass: tc.results.ois.metOIS },
        { name: 'Verdict Safe', pass: tc.verdict.verdict !== 'UNCERTAIN' }
      ];
      document.getElementById('gatesGrid').innerHTML = gates.map(g =>
        `<div class="gate-item">
          <div class="gate-status ${g.pass ? 'pass' : 'fail'}">${g.pass ? '✓' : '✗'}</div>
          <span>${g.name}</span>
        </div>`
      ).join('');

      // GRADE
      document.getElementById('gradeContainer').style.display = 'block';
      document.getElementById('gradeCertainty').innerHTML = `
        <div style="font-size: var(--text-2xl); font-weight: 700; margin-bottom: var(--space-4);">
          Certainty: <span style="color: var(--color-accent-400)">${tc.grade.certainty}</span>
        </div>
      `;
      document.getElementById('gradeDomainsGrid').innerHTML = Object.entries(tc.grade.domains).map(([k, v]) =>
        `<div class="grade-domain">
          <div class="grade-domain-title">${k.replace(/([A-Z])/g, ' $1').trim()}</div>
          <div class="grade-domain-value ${v.rating.toLowerCase()}">${v.rating}</div>
          <div style="font-size: var(--text-xs); color: var(--text-secondary)">${v.reason || 'No concerns'}</div>
        </div>`
      ).join('');

      // Sensitivity Summary
      document.getElementById('sensitivitySummaryContainer').style.display = 'block';
      document.getElementById('oisResults').innerHTML = `
        <p><strong>${tc.results.ois.percentOIS}%</strong> of required</p>
        <p>${tc.results.ois.totalN.toLocaleString()} / ${tc.results.ois.oisRequired.toLocaleString()}</p>
      `;
      document.getElementById('fragilityResults').innerHTML = tc.results.fragilityIndex.ok ?
        `<p><strong>FI = ${tc.results.fragilityIndex.fi}</strong></p>` :
        `<p>${tc.results.fragilityIndex.reason}</p>`;
      document.getElementById('breakdownResults').innerHTML = tc.results.breakdownPoint.ok ?
        `<p><strong>${(tc.results.breakdownPoint.fractionNull * 100).toFixed(0)}%</strong> to flip</p>` :
        `<p>N/A</p>`;
      document.getElementById('rhoSweepResults').innerHTML = tc.results.rhoSweep.ok ?
        `<p>Spread: <strong>${tc.results.rhoSweep.spread.toFixed(4)}</strong></p>
         <p>${tc.results.rhoSweep.robust ? 'Robust' : 'Sensitive'}</p>` :
        `<p>N/A</p>`;

      // Decision Log
      document.getElementById('decisionLogContainer').style.display = 'block';
      document.getElementById('decisionLogContent').innerHTML = decisionLog.slice(-50).map(d =>
        `<div class="decision-log-item ${d.type}">[${d.type.toUpperCase()}] ${d.msg}</div>`
      ).join('');

      // Export container
      document.getElementById('verdictExportContainer').style.display = 'block';
    }

