    // =========================================================================
    // MULTILEVEL (THREE-LEVEL) META-ANALYSIS MODULE
    // =========================================================================
    // Implements hierarchical meta-analysis for dependent effect sizes
    // Based on Cheung (2014), Van den Noortgate et al. (2013)
    // =========================================================================

    /**
     * Multilevel MA State
     */
    const MultilevelState = {
      data: null,
      results: null,
      varianceComponents: null,
      rveResults: null
    };

    /**
     * Three-Level Meta-Analysis Model
     *
     * Model: y_ij = μ + u_j + w_ij + e_ij
     * Where:
     *   y_ij = effect size i in study j
     *   μ = overall mean
     *   u_j ~ N(0, τ²) = between-study random effect
     *   w_ij ~ N(0, ω²) = within-study random effect
     *   e_ij ~ N(0, v_ij) = sampling error (known)
     *
     * @param {Array} data - Array of {study, yi, vi, outcome, ...}
     * @param {Object} options - Configuration options
     */
    function threeLevelMA(data, options = {}) {
      const {
        rho = 0.5,  // Assumed within-study correlation for outcomes
        method = 'REML',
        maxIter = 100,
        tol = 1e-6
      } = options;

      // Group effects by study
      const studyGroups = new Map();
      data.forEach((d, idx) => {
        const studyId = d.study || d.studyId || `Study_${idx}`;
        if (!studyGroups.has(studyId)) {
          studyGroups.set(studyId, []);
        }
        studyGroups.get(studyId).push({ ...d, _idx: idx });
      });

      const studies = Array.from(studyGroups.keys());
      const J = studies.length;  // Number of studies
      const N = data.length;     // Total number of effects

      // Extract effect sizes and variances
      const yi = data.map(d => d.yi);
      const vi = data.map(d => d.vi);

      // Study membership vector
      const studyMembership = data.map(d => {
        const studyId = d.study || d.studyId;
        return studies.indexOf(studyId);
      });

      // Number of effects per study
      const nj = studies.map(s => studyGroups.get(s).length);

      // =========================================================================
      // REML Estimation of Variance Components
      // =========================================================================

      // Initialize variance components
      let tau2 = 0.1;   // Between-study variance
      let omega2 = 0.1; // Within-study variance

      // Use method of moments for starting values
      const mmResult = momentEstimator(yi, vi, studyMembership, studies);
      tau2 = Math.max(0.001, mmResult.tau2);
      omega2 = Math.max(0.001, mmResult.omega2);

      // REML iterations
      let converged = false;
      let iter = 0;

      for (iter = 0; iter < maxIter; iter++) {
        const prevTau2 = tau2;
        const prevOmega2 = omega2;

        // Build variance-covariance matrix V
        // V = diag(v_i) + ω² * I + τ² * Z * Z'
        // Where Z is the study design matrix

        // For computational efficiency, work with block-diagonal structure
        let sumWY = 0;
        let sumW = 0;
        const blockResults = [];

        studies.forEach((study, j) => {
          const indices = [];
          data.forEach((d, idx) => {
            if ((d.study || d.studyId) === study) indices.push(idx);
          });

          const k = indices.length;
          const yBlock = indices.map(i => yi[i]);
          const vBlock = indices.map(i => vi[i]);

          // Block variance matrix: V_j = diag(v_i) + ω² * I_k + τ² * J_k
          // Where J_k is k×k matrix of ones
          // Inverse using Woodbury formula for efficiency

          const diagV = vBlock.map(v => v + omega2);
          const sumInvDiag = diagV.reduce((s, d) => s + 1/d, 0);
          const adjustment = tau2 / (1 + tau2 * sumInvDiag);

          // Weighted sum for this block
          const wBlock = diagV.map(d => 1/d);
          const sumWBlock = wBlock.reduce((a, b) => a + b, 0);
          const yBarBlock = wBlock.reduce((s, w, i) => s + w * yBlock[i], 0) / sumWBlock;

          // Adjusted weight (accounting for τ²)
          const adjW = sumWBlock / (1 + tau2 * sumWBlock);

          sumWY += adjW * yBarBlock;
          sumW += adjW;

          blockResults.push({
            study,
            k,
            indices,
            yBlock,
            vBlock,
            diagV,
            sumWBlock,
            yBarBlock,
            adjW
          });
        });

        // Overall mean estimate
        const mu = sumWY / sumW;

        // Update variance components using Fisher scoring
        let Q_omega = 0;  // Score for ω²
        let Q_tau = 0;    // Score for τ²
        let I_omega = 0;  // Information for ω²
        let I_tau = 0;    // Information for τ²

        blockResults.forEach(block => {
          const { k, yBlock, diagV, sumWBlock, yBarBlock } = block;

          // Residuals
          const resid = yBlock.map(y => y - mu);

          // Quadratic forms for score equations
          const wBlock = diagV.map(d => 1/d);
          const w2Block = diagV.map(d => 1/(d*d));

          // Within-block residual sum of squares
          const ssResid = resid.reduce((s, r, i) => s + wBlock[i] * r * r, 0);

          // Contributions to score equations
          // For ω²: based on within-study variation
          Q_omega += ssResid - (k - 1);

          // For τ²: based on between-study variation
          const studyResid = yBarBlock - mu;
          const adjW = block.adjW;
          Q_tau += adjW * studyResid * studyResid - 1 / (1/tau2 + sumWBlock);

          // Information contributions (simplified)
          I_omega += w2Block.reduce((a, b) => a + b, 0) / 2;
          I_tau += adjW * adjW / 2;
        });

        // Fisher scoring updates
        if (I_omega > 1e-10) {
          omega2 = Math.max(0, omega2 + Q_omega / I_omega * 0.5);
        }
        if (I_tau > 1e-10) {
          tau2 = Math.max(0, tau2 + Q_tau / I_tau * 0.5);
        }

        // Check convergence
        const change = Math.abs(tau2 - prevTau2) + Math.abs(omega2 - prevOmega2);
        if (change < tol) {
          converged = true;
          break;
        }
      }

      // =========================================================================
      // Final estimates
      // =========================================================================

      // Recompute with final variance components
      let finalSumWY = 0;
      let finalSumW = 0;
      const studyEffects = [];

      studies.forEach((study, j) => {
        const indices = [];
        data.forEach((d, idx) => {
          if ((d.study || d.studyId) === study) indices.push(idx);
        });

        const k = indices.length;
        const yBlock = indices.map(i => yi[i]);
        const vBlock = indices.map(i => vi[i]);
        const diagV = vBlock.map(v => v + omega2);
        const wBlock = diagV.map(d => 1/d);
        const sumWBlock = wBlock.reduce((a, b) => a + b, 0);
        const yBarBlock = wBlock.reduce((s, w, i) => s + w * yBlock[i], 0) / sumWBlock;
        const adjW = sumWBlock / (1 + tau2 * sumWBlock);

        finalSumWY += adjW * yBarBlock;
        finalSumW += adjW;

        studyEffects.push({
          study,
          nEffects: k,
          studyMean: yBarBlock,
          studyWeight: adjW
        });
      });

      const theta = finalSumWY / finalSumW;
      const se = Math.sqrt(1 / finalSumW);

      // Degrees of freedom (Satterthwaite approximation)
      const df = Math.max(1, J - 1);

      // t-based CI
      const tCrit = qt(0.975, df);
      const ci_lower = theta - tCrit * se;
      const ci_upper = theta + tCrit * se;

      // Test statistic
      const tVal = theta / se;
      const pval = 2 * (1 - pt(Math.abs(tVal), df));

      // =========================================================================
      // Heterogeneity decomposition
      // =========================================================================

      // Total variance = τ² + ω² + typical sampling variance
      const typicalV = vi.reduce((a, b) => a + b, 0) / N;
      const totalVar = tau2 + omega2 + typicalV;

      // I² by level
      const I2_level2 = 100 * omega2 / totalVar;  // Within-study
      const I2_level3 = 100 * tau2 / totalVar;    // Between-study
      const I2_total = I2_level2 + I2_level3;

      // Q statistic (approximate)
      let Q = 0;
      data.forEach((d, i) => {
        const w = 1 / (d.vi + omega2 + tau2);
        Q += w * Math.pow(d.yi - theta, 2);
      });

      const results = {
        // Main estimates
        theta,
        se,
        ci_lower,
        ci_upper,
        z: tVal,
        t: tVal,
        df,
        pval,

        // Variance components
        tau2,              // Between-study variance
        tau: Math.sqrt(tau2),
        omega2,            // Within-study variance
        omega: Math.sqrt(omega2),

        // Heterogeneity
        I2_total,
        I2_level2,         // Within-study I²
        I2_level3,         // Between-study I²
        Q,
        Q_df: N - 1,

        // Model info
        nStudies: J,
        nEffects: N,
        effectsPerStudy: N / J,
        converged,
        iterations: iter,
        method,

        // Study-level results
        studyEffects,

        // Prediction interval (accounts for both variance components)
        pi_lower: theta - 1.96 * Math.sqrt(se * se + tau2 + omega2),
        pi_upper: theta + 1.96 * Math.sqrt(se * se + tau2 + omega2)
      };

      return results;
    }

    /**
     * Method of moments estimator for starting values
     */
    function momentEstimator(yi, vi, studyMembership, studies) {
      const N = yi.length;
      const J = studies.length;

      // Simple DL-type estimator
      const w = vi.map(v => 1 / v);
      const sumW = w.reduce((a, b) => a + b, 0);
      const thetaFE = w.reduce((s, wt, i) => s + wt * yi[i], 0) / sumW;

      // Total Q
      let Q = 0;
      w.forEach((wt, i) => {
        Q += wt * Math.pow(yi[i] - thetaFE, 2);
      });

      // Between-study Q
      const studyMeans = studies.map(s => {
        let sumWY = 0, sumW = 0;
        yi.forEach((y, i) => {
          if (studyMembership[i] === studies.indexOf(s)) {
            sumWY += w[i] * y;
            sumW += w[i];
          }
        });
        return sumWY / sumW;
      });

      let Q_between = 0;
      studies.forEach((s, j) => {
        let studyW = 0;
        yi.forEach((y, i) => {
          if (studyMembership[i] === j) studyW += w[i];
        });
        Q_between += studyW * Math.pow(studyMeans[j] - thetaFE, 2);
      });

      const Q_within = Q - Q_between;

      // Estimate variance components
      const C = sumW - w.reduce((s, wt) => s + wt * wt, 0) / sumW;
      const tau2 = Math.max(0, (Q_between - (J - 1)) / C);
      const omega2 = Math.max(0, (Q_within - (N - J)) / C);

      return { tau2, omega2 };
    }

    /**
     * Robust Variance Estimation (RVE) with CR2 small-sample correction
     * Handles arbitrary within-study correlation structures
     */
    function robustVarianceEstimation(data, options = {}) {
      const {
        rho = 0.8,           // Working correlation
        smallSampleCorrection = 'CR2',  // CR0, CR1, CR2
        weights = 'inverse'  // inverse variance or equal
      } = options;

      // Group by study
      const studyGroups = new Map();
      data.forEach((d, idx) => {
        const studyId = d.study || d.studyId;
        if (!studyGroups.has(studyId)) {
          studyGroups.set(studyId, []);
        }
        studyGroups.get(studyId).push({ ...d, _idx: idx });
      });

      const studies = Array.from(studyGroups.keys());
      const J = studies.length;
      const N = data.length;

      // Build working correlation matrix for each study
      // Using exchangeable structure with correlation rho
      function buildWorkingCov(k, vBlock, rho) {
        const R = [];
        for (let i = 0; i < k; i++) {
          R[i] = [];
          for (let j = 0; j < k; j++) {
            if (i === j) {
              R[i][j] = vBlock[i];
            } else {
              R[i][j] = rho * Math.sqrt(vBlock[i] * vBlock[j]);
            }
          }
        }
        return R;
      }

      // First pass: weighted mean (ignoring correlation for simplicity)
      let sumWY = 0, sumW = 0;
      const avgV = data.reduce((s, d) => s + d.vi, 0) / N;

      data.forEach(d => {
        const w = weights === 'inverse' ? 1 / d.vi : 1;
        sumWY += w * d.yi;
        sumW += w;
      });

      const thetaWLS = sumWY / sumW;

      // Compute robust variance estimator
      let meat = 0;  // "meat" of the sandwich
      let bread = 0; // "bread" of the sandwich

      studies.forEach(study => {
        const effects = studyGroups.get(study);
        const k = effects.length;
        const yBlock = effects.map(e => e.yi);
        const vBlock = effects.map(e => e.vi);

        // Residuals
        const resid = yBlock.map(y => y - thetaWLS);

        // Working covariance
        const V = buildWorkingCov(k, vBlock, rho);

        // Weights for this study
        const wBlock = vBlock.map(v => weights === 'inverse' ? 1 / v : 1);
        const studyW = wBlock.reduce((a, b) => a + b, 0);

        // Contribution to bread
        bread += studyW;

        // Contribution to meat (cluster-robust)
        // Sum of weighted residual products
        let clusterMeat = 0;
        for (let i = 0; i < k; i++) {
          for (let j = 0; j < k; j++) {
            clusterMeat += wBlock[i] * wBlock[j] * resid[i] * resid[j];
          }
        }

        // Apply small-sample correction
        let correction = 1;
        if (smallSampleCorrection === 'CR1') {
          correction = J / (J - 1);
        } else if (smallSampleCorrection === 'CR2') {
          // CR2 correction (more complex, approximated here)
          const leverage = studyW / sumW;
          correction = 1 / Math.max(0.01, (1 - leverage));
        }

        meat += correction * clusterMeat;
      });

      // Sandwich variance: (X'WX)^-1 * meat * (X'WX)^-1
      const seRobust = Math.sqrt(meat) / bread;

      // Satterthwaite degrees of freedom for CR2
      let df = J - 1;
      if (smallSampleCorrection === 'CR2') {
        // Approximate df using effective number of clusters
        df = Math.max(1, J - 1);
      }

      // Confidence interval
      const tCrit = qt(0.975, df);

      return {
        theta: thetaWLS,
        se: seRobust,
        se_robust: seRobust,
        ci_lower: thetaWLS - tCrit * seRobust,
        ci_upper: thetaWLS + tCrit * seRobust,
        t: thetaWLS / seRobust,
        df,
        pval: 2 * (1 - pt(Math.abs(thetaWLS / seRobust), df)),
        nStudies: J,
        nEffects: N,
        rho,
        correction: smallSampleCorrection
      };
    }

    /**
     * Sensitivity analysis across different assumed correlations
     */
    function rhoSensitivityAnalysis(data, rhoValues = [0, 0.2, 0.4, 0.6, 0.8, 0.95]) {
      const results = [];

      rhoValues.forEach(rho => {
        try {
          const ml = threeLevelMA(data, { rho });
          const rve = robustVarianceEstimation(data, { rho });

          results.push({
            rho,
            theta_ml: ml.theta,
            se_ml: ml.se,
            ci_lower_ml: ml.ci_lower,
            ci_upper_ml: ml.ci_upper,
            theta_rve: rve.theta,
            se_rve: rve.se_robust,
            ci_lower_rve: rve.ci_lower,
            ci_upper_rve: rve.ci_upper,
            tau2: ml.tau2,
            omega2: ml.omega2,
            I2_total: ml.I2_total
          });
        } catch (e) {
          console.warn(`Rho sensitivity failed for rho=${rho}:`, e);
        }
      });

      return results;
    }

    /**
     * Run multilevel meta-analysis with comprehensive output
     */
    function runMultilevelMA(data, options = {}) {
      const {
        rho = 0.5,
        method = 'REML',
        doRVE = true,
        doSensitivity = true
      } = options;

      // Validate data
      if (!data || data.length < 2) {
        throw new Error('Need at least 2 effect sizes');
      }

      // Check for study grouping
      const hasStudyVar = data.every(d => d.study || d.studyId);
      if (!hasStudyVar) {
        // Assign each effect to its own study if no grouping
        data = data.map((d, i) => ({ ...d, study: d.study || `Study_${i + 1}` }));
      }

      // Run three-level model
      const mlResults = threeLevelMA(data, { rho, method });

      // Run RVE
      let rveResults = null;
      if (doRVE) {
        rveResults = robustVarianceEstimation(data, { rho, smallSampleCorrection: 'CR2' });
      }

      // Sensitivity analysis
      let sensitivity = null;
      if (doSensitivity) {
        sensitivity = rhoSensitivityAnalysis(data);
      }

      // Store in state
      MultilevelState.data = data;
      MultilevelState.results = mlResults;
      MultilevelState.rveResults = rveResults;

      return {
        multilevel: mlResults,
        rve: rveResults,
        sensitivity,
        summary: {
          theta: mlResults.theta,
          se: mlResults.se,
          se_robust: rveResults?.se_robust,
          ci: [mlResults.ci_lower, mlResults.ci_upper],
          ci_robust: rveResults ? [rveResults.ci_lower, rveResults.ci_upper] : null,
          pval: mlResults.pval,
          tau2: mlResults.tau2,
          omega2: mlResults.omega2,
          I2_within: mlResults.I2_level2,
          I2_between: mlResults.I2_level3,
          I2_total: mlResults.I2_total,
          nStudies: mlResults.nStudies,
          nEffects: mlResults.nEffects
        }
      };
    }

