    function runInfluenceDiagnostics() {
      const r = AppState.results;
      if (!r || !r.studies) {
        showToast('Run analysis first', 'error');
        return;
      }

      const yi = r.studies.map(s => s.yi);
      const vi = r.studies.map(s => s.vi);
      const names = r.studies.map(s => s.name);
      const tau2 = r.tau2 || 0;

      try {
        const influence = calculateInfluenceDiagnostics(yi, vi, tau2);
        renderInfluencePlot(influence, names, 'influencePlot');

        const summary = influence.summary;
        document.getElementById('influenceResults').innerHTML = `
          <p><strong>Outliers detected:</strong> ${summary.n_outliers} (|studentized residual| > 2.5)</p>
          <p><strong>Influential studies:</strong> ${summary.n_influential} (Cook's D > ${influence.thresholds.cooks_d.toFixed(3)} or |DFBETAS| > ${influence.thresholds.dfbetas.toFixed(3)})</p>
          <p><strong>Max Cook's D:</strong> ${summary.max_cooks_d.toFixed(4)}</p>
          <p><strong>Max |DFBETAS|:</strong> ${summary.max_dfbetas.toFixed(4)}</p>
          <p style="margin-top: var(--space-2); font-style: italic;">${summary.interpretation}</p>
        `;

        showToast('Influence diagnostics complete', 'success');
      } catch (e) {
        showToast('Influence diagnostics failed: ' + e.message, 'error');
        console.error(e);
      }
    }

    function runCopasModel() {
      const r = AppState.results;
      if (!r || !r.studies) {
        showToast('Run analysis first', 'error');
        return;
      }

      const yi = r.studies.map(s => s.yi);
      const vi = r.studies.map(s => s.vi);

      showToast('Running Copas selection model...', 'info');

      setTimeout(() => {
        try {
          const copas = copasSelectionModel(yi, vi);

          if (!copas.success) {
            document.getElementById('copasResults').innerHTML = `
              <p class="text-danger">${copas.message}</p>
              <p><strong>Unadjusted estimate:</strong> ${copas.theta_unadj.toFixed(4)}</p>
            `;
            showToast('Copas model did not converge', 'warning');
            return;
          }

          document.getElementById('copasResults').innerHTML = `
            <table style="width: 100%; border-collapse: collapse;">
              <tr><td style="padding: 4px;"><strong>Unadjusted θ:</strong></td><td>${copas.theta_unadj.toFixed(4)}</td></tr>
              <tr><td style="padding: 4px;"><strong>Adjusted θ:</strong></td><td>${copas.theta_adj.toFixed(4)}</td></tr>
              <tr><td style="padding: 4px;"><strong>95% CI:</strong></td><td>[${copas.ci_lower.toFixed(4)}, ${copas.ci_upper.toFixed(4)}]</td></tr>
              <tr><td style="padding: 4px;"><strong>Bias estimate:</strong></td><td>${copas.bias_estimate.toFixed(4)} (${copas.bias_pct.toFixed(1)}%)</td></tr>
              <tr><td style="padding: 4px;"><strong>Selection params:</strong></td><td>γ₀=${copas.gamma0.toFixed(2)}, γ₁=${copas.gamma1.toFixed(2)}</td></tr>
            </table>
            <p style="margin-top: var(--space-2); font-style: italic;">${copas.interpretation}</p>
          `;

          showToast('Copas model complete', 'success');
        } catch (e) {
          showToast('Copas model failed: ' + e.message, 'error');
          console.error(e);
        }
      }, 50);
    }

    function runSmallSampleCI() {
      const r = AppState.results;
      if (!r || !r.studies) {
        showToast('Run analysis first', 'error');
        return;
      }

      const yi = r.studies.map(s => s.yi);
      const vi = r.studies.map(s => s.vi);
      const tau2 = r.tau2 || 0;
      const k = yi.length;

      try {
        const zej = zejnullahiCI(yi, vi, tau2);
        const pred = calculatePredictionInterval(yi, vi, tau2);
        const profLik = profileLikelihoodTau2CI(yi, vi, tau2);

        document.getElementById('smallSampleResults').innerHTML = `
          <h4 style="margin-bottom: var(--space-2);">Zejnullahi Small-Sample CI (k=${k})</h4>
          <table style="width: 100%; border-collapse: collapse; margin-bottom: var(--space-3);">
            <tr><td style="padding: 4px;"><strong>Pooled estimate:</strong></td><td>${zej.theta.toFixed(4)}</td></tr>
            <tr><td style="padding: 4px;"><strong>Standard (Wald) CI:</strong></td><td>[${zej.ci_wald.lower.toFixed(4)}, ${zej.ci_wald.upper.toFixed(4)}]</td></tr>
            <tr><td style="padding: 4px;"><strong>Zejnullahi CI:</strong></td><td>[${zej.ci_zejnullahi.lower.toFixed(4)}, ${zej.ci_zejnullahi.upper.toFixed(4)}]</td></tr>
            <tr><td style="padding: 4px;"><strong>CI width ratio:</strong></td><td>${zej.width_ratio.toFixed(2)}× wider</td></tr>
          </table>
          <p style="font-style: italic; margin-bottom: var(--space-3);">${zej.interpretation}</p>

          <h4 style="margin-bottom: var(--space-2);">Prediction Interval</h4>
          <table style="width: 100%; border-collapse: collapse; margin-bottom: var(--space-3);">
            <tr><td style="padding: 4px;"><strong>95% Prediction Interval:</strong></td><td>[${pred.lower.toFixed(4)}, ${pred.upper.toFixed(4)}]</td></tr>
            <tr><td style="padding: 4px;"><strong>SE (prediction):</strong></td><td>${pred.se_pred.toFixed(4)}</td></tr>
            <tr><td style="padding: 4px;"><strong>df:</strong></td><td>${pred.df}</td></tr>
          </table>
          <p style="font-style: italic; margin-bottom: var(--space-3);">${pred.interpretation}</p>

          <h4 style="margin-bottom: var(--space-2);">Profile Likelihood τ² CI</h4>
          <table style="width: 100%; border-collapse: collapse;">
            <tr><td style="padding: 4px;"><strong>τ² estimate:</strong></td><td>${profLik.tau2_hat.toFixed(4)}</td></tr>
            <tr><td style="padding: 4px;"><strong>95% Profile Lik CI:</strong></td><td>[${profLik.ci_profile.lower.toFixed(4)}, ${profLik.ci_profile.upper.toFixed(4)}]</td></tr>
            <tr><td style="padding: 4px;"><strong>τ (SD scale) CI:</strong></td><td>[${profLik.ci_profile_sqrt.lower.toFixed(4)}, ${profLik.ci_profile_sqrt.upper.toFixed(4)}]</td></tr>
            <tr><td style="padding: 4px;"><strong>I²:</strong></td><td>${profLik.I2.toFixed(1)}%</td></tr>
          </table>
          <p style="font-style: italic;">${profLik.interpretation}</p>
        `;

        showToast('Small-sample analyses complete', 'success');
      } catch (e) {
        showToast('Small-sample CI failed: ' + e.message, 'error');
        console.error(e);
      }
    }


    

