    /**
     * Run full validation comparison against metafor expected values
     */
    function runValidationSuite() {
      const results = [];

      for (const [key, dataset] of Object.entries(VALIDATION_DATASETS)) {
        const validation = validateAgainstMetafor(dataset);
        results.push({
          dataset: dataset.name,
          ...validation
        });
      }

      return {
        results: results,
        summary: summarizeValidation(results),
        timestamp: new Date().toISOString()
      };
    }

    function validateAgainstMetafor(dataset) {
      // Convert studies to effect sizes
      const studiesWithEffects = dataset.studies.map(s => {
        if (dataset.type === 'binary') {
          return convertBinaryToEffectSize(s, dataset.measure);
        } else {
          return convertContinuousToEffectSize(s, dataset.measure);
        }
      });

      const yi = studiesWithEffects.map(s => s.yi);
      const vi = studiesWithEffects.map(s => s.vi);

      // Run with REML
      const tau2_reml = estimateTau2_REML(yi, vi);
      const wi = vi.map(v => 1 / (v + tau2_reml));
      const sumW = wi.reduce((a, b) => a + b, 0);
      const theta = wi.reduce((s, w, i) => s + w * yi[i], 0) / sumW;
      const se = Math.sqrt(1 / sumW);
      const Q = vi.map((v, i) => (1/v) * Math.pow(yi[i] - theta, 2)).reduce((a,b) => a+b, 0);
      const k = yi.length;
      const I2 = Math.max(0, (Q - (k-1)) / Q) * 100;

      const expected = dataset.expected_metafor;

      // Calculate differences
      const diff_theta = Math.abs(theta - expected.theta);
      const diff_se = Math.abs(se - expected.se);
      const diff_tau2 = Math.abs(tau2_reml - expected.tau2);
      const diff_I2 = Math.abs(I2 - expected.I2);

      // Pass/fail criteria (within 0.01 for estimates, 1% for I2)
      const theta_pass = diff_theta < 0.02;
      const se_pass = diff_se < 0.02;
      const tau2_pass = diff_tau2 < 0.02;
      const I2_pass = diff_I2 < 2;

      return {
        computed: { theta, se, tau2: tau2_reml, I2, Q },
        expected: expected,
        differences: { theta: diff_theta, se: diff_se, tau2: diff_tau2, I2: diff_I2 },
        passed: { theta: theta_pass, se: se_pass, tau2: tau2_pass, I2: I2_pass },
        overall_pass: theta_pass && se_pass && tau2_pass && I2_pass
      };
    }

    function convertBinaryToEffectSize(study, measure) {
      const a = study.events_t;
      const b = study.n_t - study.events_t;
      const c = study.events_c;
      const d = study.n_c - study.events_c;

      // Apply 0.5 continuity correction if needed
      let a_adj = a, b_adj = b, c_adj = c, d_adj = d;
      if (a === 0 || b === 0 || c === 0 || d === 0) {
        a_adj = a + 0.5;
        b_adj = b + 0.5;
        c_adj = c + 0.5;
        d_adj = d + 0.5;
      }

      let yi, vi;
      if (measure === 'OR') {
        yi = Math.log((a_adj * d_adj) / (b_adj * c_adj));
        vi = 1/a_adj + 1/b_adj + 1/c_adj + 1/d_adj;
      } else if (measure === 'RR') {
        yi = Math.log((a_adj / (a_adj + b_adj)) / (c_adj / (c_adj + d_adj)));
        vi = 1/a_adj - 1/(a_adj + b_adj) + 1/c_adj - 1/(c_adj + d_adj);
      } else { // RD
        const p1 = a_adj / (a_adj + b_adj);
        const p2 = c_adj / (c_adj + d_adj);
        yi = p1 - p2;
        vi = (p1 * (1-p1)) / (a_adj + b_adj) + (p2 * (1-p2)) / (c_adj + d_adj);
      }

      return { ...study, yi, vi, sei: Math.sqrt(vi) };
    }

    function convertContinuousToEffectSize(study, measure) {
      const yi = study.mean_t - study.mean_c;
      const vi = (study.sd_t * study.sd_t / study.n_t) + (study.sd_c * study.sd_c / study.n_c);
      return { ...study, yi, vi, sei: Math.sqrt(vi) };
    }

    function summarizeValidation(results) {
      const passed = results.filter(r => r.overall_pass).length;
      const total = results.length;
      return {
        passed: passed,
        total: total,
        success_rate: (passed / total * 100).toFixed(1) + '%',
        conclusion: passed === total
          ? "All validation tests PASSED. Results match metafor within tolerance."
          : `${passed}/${total} tests passed. Review discrepancies.`
      };
    }

    // =========================================================================
    // 2. REML ALGORITHM DOCUMENTATION
    // =========================================================================

    /**
     * REML (Restricted Maximum Likelihood) Estimator for τ²
     *
     * Algorithm: Fisher Scoring with analytical gradient
     * Convergence: |τ²(i+1) - τ²(i)| < 1e-6 or max 100 iterations
     * Boundary: τ² constrained to [0, ∞)
     *
     * Reference: Viechtbauer (2005). Bias and Efficiency of Meta-Analytic
     *            Variance Estimators in the Random-Effects Model.
     *            Journal of Educational and Behavioral Statistics, 30(3), 261-293.
     */
    function estimateTau2_REML_Documented(yi, vi, maxIter = 100, tol = 1e-6, verbose = false) {
      const k = yi.length;

      // Initialize with DerSimonian-Laird estimate
      let tau2 = estimateTau2_DL(yi, vi);
      tau2 = Math.max(0, tau2);

      const iterations = [];
      let converged = false;

      for (let iter = 0; iter < maxIter; iter++) {
        const tau2_old = tau2;

        // Weights
        const wi = vi.map(v => 1 / (v + tau2));
        const W = wi.reduce((a, b) => a + b, 0);

        // Weighted mean
        const theta = wi.reduce((s, w, i) => s + w * yi[i], 0) / W;

        // Gradient (score function)
        let U = 0;
        for (let i = 0; i < k; i++) {
          U += -0.5 * wi[i] * wi[i] / W;  // REML adjustment
          U += 0.5 * wi[i] * wi[i];
          U -= 0.5 * wi[i] * wi[i] * Math.pow(yi[i] - theta, 2);
        }

        // Fisher information
        let I = 0;
        for (let i = 0; i < k; i++) {
          I += 0.5 * Math.pow(wi[i], 2);
        }
        // REML adjustment to Fisher info
        I -= 0.5 * Math.pow(wi.reduce((s, w) => s + w * w, 0), 2) / (W * W);

        // Fisher scoring update
        if (Math.abs(I) > 1e-10) {
          tau2 = tau2_old + U / I;
        }

        // Constrain to non-negative
        tau2 = Math.max(0, tau2);

        iterations.push({
          iter: iter + 1,
          tau2: tau2,
          gradient: U,
          fisher_info: I,
          change: Math.abs(tau2 - tau2_old)
        });

        // Check convergence
        if (Math.abs(tau2 - tau2_old) < tol) {
          converged = true;
          break;
        }
      }

      return {
        tau2: tau2,
        converged: converged,
        iterations: iterations.length,
        final_change: iterations.length > 0 ? iterations[iterations.length - 1].change : 0,
        log: verbose ? iterations : null,
        algorithm: "Fisher Scoring",
        tolerance: tol,
        max_iterations: maxIter,
        initialization: "DerSimonian-Laird"
      };
    }

    // =========================================================================
    // 3. SMALL-K WARNINGS
    // =========================================================================

    /**
     * Check for small sample concerns and generate appropriate warnings
     */
    function checkSmallSampleWarnings(k, tau2, I2) {
      const warnings = [];

      if (k < 3) {
        warnings.push({
          severity: 'critical',
          message: 'Only ' + k + ' studies. Meta-analysis not recommended. Cannot reliably estimate heterogeneity.',
          recommendation: 'Consider narrative synthesis instead of meta-analysis.'
        });
      } else if (k < 5) {
        warnings.push({
          severity: 'warning',
          message: 'Only ' + k + ' studies. Heterogeneity estimates unreliable.',
          recommendation: 'Use Hartung-Knapp-Sidik-Jonkman adjustment for CIs. Interpret τ² and I² with caution.'
        });
      } else if (k < 10) {
        warnings.push({
          severity: 'info',
          message: 'Fewer than 10 studies. Publication bias tests have low power.',
          recommendation: 'Egger test may be unreliable. Consider funnel plot visual assessment only.'
        });
      }

      // Power-related warnings
      if (k < 10 && I2 > 50) {
        warnings.push({
          severity: 'warning',
          message: 'High heterogeneity (I²=' + I2.toFixed(1) + '%) with few studies.',
          recommendation: 'Explore sources of heterogeneity. Consider not pooling if unexplained.'
        });
      }

      return warnings;
    }

    // =========================================================================
    // 4. HEDGES' g CORRECTION
    // =========================================================================

    /**
     * Calculate Hedges' g (bias-corrected standardized mean difference)
     * Corrects for small-sample bias in Cohen's d
     *
     * Reference: Hedges, L.V. (1981). Distribution theory for Glass's estimator
     *            of effect size and related estimators. JEBS, 6(2), 107-128.
     */
    function calculateHedgesG(mean_t, sd_t, n_t, mean_c, sd_c, n_c) {
      // Pooled standard deviation
      const df = n_t + n_c - 2;
      const s_pooled = Math.sqrt(
        ((n_t - 1) * sd_t * sd_t + (n_c - 1) * sd_c * sd_c) / df
      );

      // Cohen's d
      const d = (mean_t - mean_c) / s_pooled;

      // Hedges' correction factor J (exact formula)
      // J = 1 - 3/(4*df - 1)
      const J = 1 - 3 / (4 * df - 1);

      // Hedges' g
      const g = d * J;

      // Variance of g
      const var_d = (n_t + n_c) / (n_t * n_c) + (d * d) / (2 * (n_t + n_c));
      const var_g = var_d * J * J;

      return {
        cohens_d: d,
        hedges_g: g,
        correction_factor: J,
        variance: var_g,
        se: Math.sqrt(var_g),
        df: df,
        n_total: n_t + n_c,
        interpretation: Math.abs(g) < 0.2 ? 'small' :
                        Math.abs(g) < 0.5 ? 'medium' :
                        Math.abs(g) < 0.8 ? 'large' : 'very large'
      };
    }

    // =========================================================================
    // 5. MULTIPLE META-REGRESSION
    // =========================================================================

    /**
     * Multiple meta-regression with weighted least squares
     * Supports multiple continuous and categorical covariates
     *
     * Model: θ_i = β₀ + β₁X₁ᵢ + β₂X₂ᵢ + ... + uᵢ + εᵢ
     */
    function multipleMetaRegression(yi, vi, covariates, tau2 = null) {
      const k = yi.length;
      const p = covariates.length; // number of predictors

      // Estimate tau2 if not provided
      if (tau2 === null) {
        tau2 = estimateTau2_DL(yi, vi);
      }

      // Build design matrix X (k x (p+1) with intercept)
      const X = [];
      for (let i = 0; i < k; i++) {
        const row = [1]; // intercept
        for (let j = 0; j < p; j++) {
          row.push(covariates[j].values[i]);
        }
        X.push(row);
      }

      // Weight matrix (diagonal)
      const W = vi.map(v => 1 / (v + tau2));

      // Weighted least squares: β = (X'WX)^(-1) X'Wy
      // Calculate X'WX
      const XtWX = [];
      for (let i = 0; i <= p; i++) {
        XtWX.push([]);
        for (let j = 0; j <= p; j++) {
          let sum = 0;
          for (let m = 0; m < k; m++) {
            sum += X[m][i] * W[m] * X[m][j];
          }
          XtWX[i].push(sum);
        }
      }

      // Calculate X'Wy
      const XtWy = [];
      for (let i = 0; i <= p; i++) {
        let sum = 0;
        for (let m = 0; m < k; m++) {
          sum += X[m][i] * W[m] * yi[m];
        }
        XtWy.push(sum);
      }

      // Invert XtWX (using simple Gauss-Jordan for small matrices)
      const XtWX_inv = invertMatrix(XtWX);
      if (!XtWX_inv) {
        return { success: false, message: "Matrix inversion failed - covariates may be collinear" };
      }

      // Calculate coefficients: β = (X'WX)^(-1) X'Wy
      const beta = [];
      for (let i = 0; i <= p; i++) {
        let sum = 0;
        for (let j = 0; j <= p; j++) {
          sum += XtWX_inv[i][j] * XtWy[j];
        }
        beta.push(sum);
      }

      // Standard errors from diagonal of (X'WX)^(-1)
      const se_beta = XtWX_inv.map((row, i) => Math.sqrt(row[i]));

      // Calculate fitted values and residuals
      const fitted = X.map(row => row.reduce((s, x, j) => s + x * beta[j], 0));
      const residuals = yi.map((y, i) => y - fitted[i]);

      // Q-test for residual heterogeneity
      const Q_resid = residuals.reduce((s, r, i) => s + W[i] * r * r, 0);
      const df_resid = k - p - 1;
      const p_resid = 1 - pchisq(Q_resid, df_resid);

      // Q-test for moderators
      const Q_model = yi.reduce((s, y, i) => s + W[i] * Math.pow(fitted[i] - yi.reduce((a, b, j) => a + W[j] * b, 0) / W.reduce((a, b) => a + b, 0), 2), 0);
      const df_model = p;
      const p_model = 1 - pchisq(Q_model, df_model);

      // R² analog
      const Q_total = yi.reduce((s, y, i) => {
        const mean = yi.reduce((a, b, j) => a + W[j] * b, 0) / W.reduce((a, b) => a + b, 0);
        return s + W[i] * Math.pow(y - mean, 2);
      }, 0);
      const R2 = Q_total > 0 ? Math.max(0, (Q_total - Q_resid) / Q_total) : 0;

      // Build results
      const coefficients = [{
        name: 'Intercept',
        estimate: beta[0],
        se: se_beta[0],
        z: beta[0] / se_beta[0],
        p: 2 * (1 - pnorm(Math.abs(beta[0] / se_beta[0]))),
        ci_lower: beta[0] - 1.96 * se_beta[0],
        ci_upper: beta[0] + 1.96 * se_beta[0]
      }];

      for (let j = 0; j < p; j++) {
        coefficients.push({
          name: covariates[j].name,
          estimate: beta[j + 1],
          se: se_beta[j + 1],
          z: beta[j + 1] / se_beta[j + 1],
          p: 2 * (1 - pnorm(Math.abs(beta[j + 1] / se_beta[j + 1]))),
          ci_lower: beta[j + 1] - 1.96 * se_beta[j + 1],
          ci_upper: beta[j + 1] + 1.96 * se_beta[j + 1]
        });
      }

      return {
        success: true,
        coefficients: coefficients,
        tau2_residual: tau2,
        Q_model: Q_model,
        df_model: df_model,
        p_model: p_model,
        Q_residual: Q_resid,
        df_residual: df_resid,
        p_residual: p_resid,
        R2: R2,
        I2_residual: Math.max(0, (Q_resid - df_resid) / Q_resid) * 100,
        fitted: fitted,
        residuals: residuals,
        k: k,
        n_predictors: p
      };
    }

    // Simple matrix inversion for small matrices (Gauss-Jordan)
    function invertMatrix(matrix) {
      const n = matrix.length;
      const augmented = matrix.map((row, i) => {
        const newRow = [...row];
        for (let j = 0; j < n; j++) {
          newRow.push(i === j ? 1 : 0);
        }
        return newRow;
      });

      for (let i = 0; i < n; i++) {
        // Find pivot
        let maxRow = i;
        for (let j = i + 1; j < n; j++) {
          if (Math.abs(augmented[j][i]) > Math.abs(augmented[maxRow][i])) {
            maxRow = j;
          }
        }
        [augmented[i], augmented[maxRow]] = [augmented[maxRow], augmented[i]];

        if (Math.abs(augmented[i][i]) < 1e-10) return null; // Singular

        // Scale pivot row
        const pivot = augmented[i][i];
        for (let j = 0; j < 2 * n; j++) {
          augmented[i][j] /= pivot;
        }

        // Eliminate column
        for (let j = 0; j < n; j++) {
          if (i !== j) {
            const factor = augmented[j][i];
            for (let k = 0; k < 2 * n; k++) {
              augmented[j][k] -= factor * augmented[i][k];
            }
          }
        }
      }

      return augmented.map(row => row.slice(n));
    }

    // =========================================================================
    // 6. MULTIVARIATE META-ANALYSIS (Riley Method)
    // =========================================================================

    /**
     * Bivariate meta-analysis using Riley's method for unknown within-study correlations
     *
     * Reference: Riley et al. (2008). Bivariate random effects meta-analysis.
     *            Statistics in Medicine, 27(17), 3283-3307.
     */
    function bivariateMetaAnalysis(yi1, vi1, yi2, vi2, rho_within = 0.5) {
      const k = yi1.length;

      // Stack outcomes into single vectors
      const yi = [...yi1, ...yi2];
      const n_outcomes = 2;

      // Initial estimates using univariate meta-analysis
      const tau2_1 = estimateTau2_DL(yi1, vi1);
      const tau2_2 = estimateTau2_DL(yi2, vi2);

      // Initial between-study correlation
      let rho_between = 0.5;

      // Iterative estimation (simplified Riley approach)
      for (let iter = 0; iter < 20; iter++) {
        // Build block-diagonal within-study covariance
        const V_within = [];
        for (let i = 0; i < k; i++) {
          const cov_within = rho_within * Math.sqrt(vi1[i] * vi2[i]);
          V_within.push([
            [vi1[i], cov_within],
            [cov_within, vi2[i]]
          ]);
        }

        // Between-study covariance
        const cov_between = rho_between * Math.sqrt(tau2_1 * tau2_2);
        const Sigma = [
          [tau2_1, cov_between],
          [cov_between, tau2_2]
        ];

        // Total variance for each study (2x2 blocks)
        const V_total = V_within.map(Vw => [
          [Vw[0][0] + Sigma[0][0], Vw[0][1] + Sigma[0][1]],
          [Vw[1][0] + Sigma[1][0], Vw[1][1] + Sigma[1][1]]
        ]);

        // Weighted mean (simplified - average of univariate estimates)
        const wi1 = vi1.map((v, i) => 1 / (v + tau2_1));
        const wi2 = vi2.map((v, i) => 1 / (v + tau2_2));
        const sumW1 = wi1.reduce((a, b) => a + b, 0);
        const sumW2 = wi2.reduce((a, b) => a + b, 0);
        const theta1 = wi1.reduce((s, w, i) => s + w * yi1[i], 0) / sumW1;
        const theta2 = wi2.reduce((s, w, i) => s + w * yi2[i], 0) / sumW2;

        // Update between-study correlation from residuals
        let cov_resid = 0;
        let var1_resid = 0;
        let var2_resid = 0;
        for (let i = 0; i < k; i++) {
          const r1 = yi1[i] - theta1;
          const r2 = yi2[i] - theta2;
          const w = Math.sqrt(wi1[i] * wi2[i]);
          cov_resid += w * r1 * r2;
          var1_resid += wi1[i] * r1 * r1;
          var2_resid += wi2[i] * r2 * r2;
        }
        if (var1_resid > 0 && var2_resid > 0) {
          rho_between = cov_resid / Math.sqrt(var1_resid * var2_resid);
          rho_between = Math.max(-0.99, Math.min(0.99, rho_between));
        }
      }

      // Final estimates
      const wi1 = vi1.map((v, i) => 1 / (v + tau2_1));
      const wi2 = vi2.map((v, i) => 1 / (v + tau2_2));
      const sumW1 = wi1.reduce((a, b) => a + b, 0);
      const sumW2 = wi2.reduce((a, b) => a + b, 0);
      const theta1 = wi1.reduce((s, w, i) => s + w * yi1[i], 0) / sumW1;
      const theta2 = wi2.reduce((s, w, i) => s + w * yi2[i], 0) / sumW2;

      return {
        theta: [theta1, theta2],
        se: [Math.sqrt(1 / sumW1), Math.sqrt(1 / sumW2)],
        tau2: [tau2_1, tau2_2],
        rho_between: rho_between,
        rho_within_assumed: rho_within,
        borrowing_of_strength: Math.abs(rho_between) > 0.3 ? 'substantial' : 'minimal',
        ci_lower: [theta1 - 1.96 * Math.sqrt(1 / sumW1), theta2 - 1.96 * Math.sqrt(1 / sumW2)],
        ci_upper: [theta1 + 1.96 * Math.sqrt(1 / sumW1), theta2 + 1.96 * Math.sqrt(1 / sumW2)]
      };
    }

    // =========================================================================
    // 7. LEAVE-ONE-OUT WITH MODEL SELECTION CORRECTION (2024)
    // =========================================================================

    /**
     * Leave-one-out analysis with model selection correction
     * Addresses bias from post-hoc outlier removal
     *
     * Reference: Sensitivity analysis with iterative outlier detection.
     *            Statistics in Medicine, 2024.
     */
    function leaveOneOutCorrected(yi, vi, tau2, alpha = 0.05) {
      const k = yi.length;
      const results = [];

      // Full model
      const wi_full = vi.map(v => 1 / (v + tau2));
      const sumW_full = wi_full.reduce((a, b) => a + b, 0);
      const theta_full = wi_full.reduce((s, w, i) => s + w * yi[i], 0) / sumW_full;
      const se_full = Math.sqrt(1 / sumW_full);

      // Leave-one-out analyses
      for (let i = 0; i < k; i++) {
        const yi_loo = yi.filter((_, j) => j !== i);
        const vi_loo = vi.filter((_, j) => j !== i);

        // Re-estimate tau2 for leave-one-out
        const tau2_loo_result = estimateTau2_DL(yi_loo, vi_loo);
        const tau2_loo = tau2_loo_result.tau2 || 0;
        const wi_loo = vi_loo.map(v => 1 / (v + tau2_loo));
        const sumW_loo = wi_loo.reduce((a, b) => a + b, 0);
        const theta_loo = wi_loo.reduce((s, w, j) => s + w * yi_loo[j], 0) / sumW_loo;
        const se_loo = Math.sqrt(1 / sumW_loo);

        // Model selection correction (Bonferroni-style)
        // Adjust CI for multiple testing
        const alpha_adj = alpha / k;
        const z_adj = qnorm(1 - alpha_adj / 2);
        const ci_corrected_lower = theta_loo - z_adj * se_loo;
        const ci_corrected_upper = theta_loo + z_adj * se_loo;

        // Standard CI
        const z_std = qnorm(1 - alpha / 2);

        results.push({
          omitted: i,
          theta: theta_loo,
          se: se_loo,
          tau2: tau2_loo,  // Now correctly a number
          ci_standard: {
            lower: theta_loo - z_std * se_loo,
            upper: theta_loo + z_std * se_loo
          },
          ci_corrected: {
            lower: ci_corrected_lower,
            upper: ci_corrected_upper
          },
          change: theta_loo - theta_full,
          pct_change: ((theta_loo - theta_full) / Math.abs(theta_full)) * 100
        });
      }

      // Find most influential
      const max_change = Math.max(...results.map(r => Math.abs(r.change)));
      const most_influential = results.find(r => Math.abs(r.change) === max_change);

      // Sensitivity bound
      const theta_range = results.length > 0 ? [
        Math.min(...results.map(r => r.theta)),
        Math.max(...results.map(r => r.theta))
      ] : [theta_full, theta_full];

      return {
        full_model: { theta: theta_full, se: se_full },
        leave_one_out: results,
        most_influential_index: most_influential ? most_influential.omitted : 0,
        max_change: max_change,
        theta_range: theta_range,
        robust: max_change < 0.1 * Math.abs(theta_full),
        interpretation: max_change < 0.05 * Math.abs(theta_full)
          ? "Results are robust to removal of any single study."
          : max_change < 0.15 * Math.abs(theta_full)
            ? "Results are moderately sensitive to individual studies."
            : "Results are highly sensitive - one or more influential studies present."
      };
    }

    // =========================================================================
    // 8. ENHANCED FUNNEL PLOT WITH LABELS
    // =========================================================================

    function renderEnhancedFunnelPlot(studies, pooled, containerId, options = {}) {
      const container = document.getElementById(containerId);
      if (!container || !studies || studies.length === 0) return;

      const showLabels = options.showLabels !== false;
      const showContours = options.showContours !== false;
      const theta = pooled.theta;

      const yi = studies.map(s => s.yi);
      const sei = studies.map(s => s.sei || Math.sqrt(s.vi));
      const names = studies.map(s => s.name);

      const maxSE = Math.max(...sei) * 1.1;

      // Generate contour lines for p = 0.01, 0.05, 0.10
      const contours = [];
      const pValues = [0.01, 0.05, 0.10];
      const contourColors = ['rgba(239,68,68,0.3)', 'rgba(249,115,22,0.3)', 'rgba(234,179,8,0.3)'];

      if (showContours) {
        pValues.forEach((p, idx) => {
          const z = qnorm(1 - p / 2);
          const se_range = [];
          const upper = [];
          const lower = [];
          for (let se = 0.001; se <= maxSE; se += maxSE / 100) {
            se_range.push(se);
            upper.push(theta + z * se);
            lower.push(theta - z * se);
          }

          // Upper boundary
          contours.push({
            type: 'scatter',
            mode: 'lines',
            x: upper,
            y: se_range,
            name: 'p=' + p + ' boundary',
            line: { color: contourColors[idx], width: 1, dash: 'dot' },
            showlegend: idx === 0
          });
          // Lower boundary
          contours.push({
            type: 'scatter',
            mode: 'lines',
            x: lower,
            y: se_range,
            showlegend: false,
            line: { color: contourColors[idx], width: 1, dash: 'dot' }
          });
        });
      }

      // Study points
      const studyTrace = {
        type: 'scatter',
        mode: showLabels ? 'markers+text' : 'markers',
        x: yi,
        y: sei,
        text: names,
        textposition: 'top right',
        textfont: { size: 9 },
        name: 'Studies',
        marker: {
          size: 10,
          color: '#4a7ab8',
          line: { width: 1, color: '#1b263b' }
        }
      };

      // Pooled effect line
      const pooledLine = {
        type: 'scatter',
        mode: 'lines',
        x: [theta, theta],
        y: [0, maxSE],
        name: 'Pooled effect',
        line: { color: '#22c55e', width: 2, dash: 'dash' }
      };

      const layout = {
        title: 'Enhanced Funnel Plot',
        xaxis: { title: 'Effect Size', zeroline: true },
        yaxis: { title: 'Standard Error', autorange: 'reversed', rangemode: 'tozero' },
        paper_bgcolor: 'rgba(0,0,0,0)',
        plot_bgcolor: 'rgba(0,0,0,0)',
        font: { color: getComputedStyle(document.documentElement).getPropertyValue('--text-primary') },
        showlegend: true,
        legend: { x: 0.02, y: 0.98 }
      };

      Plotly.newPlot(containerId, [...contours, pooledLine, studyTrace], layout, { responsive: true });
    }

    // =========================================================================
    // 9. GRADE INTEGRATION WITH DOMAIN SCORING
    // =========================================================================

    /**
     * GRADE (Grading of Recommendations Assessment, Development and Evaluation)
     * Systematic assessment of evidence certainty across 5 domains
     */
    function assessGRADEDomains(results, config = {}) {
      const domains = {
        riskOfBias: assessRiskOfBiasDomain(results, config),
        inconsistency: assessInconsistencyDomain(results),
        indirectness: assessIndirectnessDomain(config),
        imprecision: assessImprecisionDomain(results, config),
        publicationBias: assessPublicationBiasDomain(results)
      };

      // Calculate total downgrade
      const totalDowngrade = Object.values(domains).reduce((s, d) => s + d.downgrade, 0);

      // Starting from HIGH for RCTs, MODERATE for observational
      const startingLevel = config.studyDesign === 'observational' ? 2 : 4;
      const finalScore = Math.max(1, startingLevel - totalDowngrade);

      const levels = ['', 'Very Low', 'Low', 'Moderate', 'High'];

      return {
        domains: domains,
        starting_level: levels[startingLevel],
        total_downgrade: totalDowngrade,
        final_score: finalScore,
        certainty: levels[finalScore],
        symbol: '⊕'.repeat(finalScore) + '⊖'.repeat(4 - finalScore),
        summary: generateGRADESummary(domains, levels[finalScore])
      };
    }

    function assessRiskOfBiasDomain(results, config) {
      // Check if RoB data available
      const robData = config.robAssessment || null;

      if (!robData) {
        return {
          rating: 'Not assessed',
          downgrade: 0,
          concerns: ['Risk of bias not formally assessed'],
          recommendation: 'Conduct domain-based RoB assessment (RoB 2 or ROBINS-I)'
        };
      }

      const highRiskCount = robData.filter(r => r.overall === 'high').length;
      const someCount = robData.filter(r => r.overall === 'some').length;
      const total = robData.length;

      let downgrade = 0;
      let concerns = [];

      if (highRiskCount / total > 0.5) {
        downgrade = 2;
        concerns.push('Majority of studies at high risk of bias');
      } else if (highRiskCount > 0 || someCount / total > 0.5) {
        downgrade = 1;
        concerns.push('Some studies at high/unclear risk of bias');
      }

      return {
        rating: downgrade === 0 ? 'No serious concerns' : downgrade === 1 ? 'Serious' : 'Very serious',
        downgrade: downgrade,
        concerns: concerns,
        high_risk_n: highRiskCount,
        some_concerns_n: someCount,
        total: total
      };
    }

    function assessInconsistencyDomain(results) {
      const I2 = results.I2 || 0;
      const Q_p = results.Q_pvalue || 1;
      const predInt = results.prediction_interval || null;

      let downgrade = 0;
      let concerns = [];

      if (I2 > 75 || Q_p < 0.001) {
        downgrade = 2;
        concerns.push('Very high heterogeneity (I²=' + I2.toFixed(1) + '%)');
      } else if (I2 > 50 || Q_p < 0.05) {
        downgrade = 1;
        concerns.push('Substantial heterogeneity (I²=' + I2.toFixed(1) + '%)');
      }

      // Check prediction interval
      if (predInt && predInt.lower * predInt.upper < 0) {
        if (downgrade < 1) downgrade = 1;
        concerns.push('Prediction interval crosses null');
      }

      return {
        rating: downgrade === 0 ? 'No serious concerns' : downgrade === 1 ? 'Serious' : 'Very serious',
        downgrade: downgrade,
        concerns: concerns,
        I2: I2,
        Q_p: Q_p
      };
    }

    function assessIndirectnessDomain(config) {
      // Based on user assessment of PICO matching
      const indirectness = config.indirectnessAssessment || 'none';

      const ratings = {
        'none': { downgrade: 0, rating: 'No serious concerns' },
        'some': { downgrade: 1, rating: 'Serious', concerns: ['Some concerns about applicability'] },
        'serious': { downgrade: 2, rating: 'Very serious', concerns: ['Major concerns about applicability'] }
      };

      return ratings[indirectness] || ratings['none'];
    }

    function assessImprecisionDomain(results, config) {
      const ci_lower = results.ci_lower;
      const ci_upper = results.ci_upper;
      const theta = results.theta;
      const ois = results.ois || null;

      let downgrade = 0;
      let concerns = [];

      // Check if CI crosses clinical decision thresholds
      const cdt = config.clinicalDecisionThreshold || 0;

      // For ratio measures, null is typically 1 (or 0 on log scale)
      const null_value = config.measureType === 'ratio' ? 0 : 0;

      // CI crosses null
      if (ci_lower < null_value && ci_upper > null_value) {
        downgrade = 1;
        concerns.push('Confidence interval crosses null');
      }

      // Check OIS if available
      if (ois && results.total_n < ois) {
        if (downgrade < 1) downgrade = 1;
        concerns.push('Sample size below optimal information size');
      }

      // Wide CI (more than 2x effect on either side)
      const ci_width = ci_upper - ci_lower;
      if (ci_width > 2 * Math.abs(theta)) {
        downgrade = Math.min(2, downgrade + 1);
        concerns.push('Very wide confidence interval');
      }

      return {
        rating: downgrade === 0 ? 'No serious concerns' : downgrade === 1 ? 'Serious' : 'Very serious',
        downgrade: downgrade,
        concerns: concerns,
        ci_width: ci_width
      };
    }

    function assessPublicationBiasDomain(results) {
      const egger_p = results.egger_p || 1;
      const trim_fill = results.trim_fill || null;

      let downgrade = 0;
      let concerns = [];

      if (egger_p < 0.01) {
        downgrade = 2;
        concerns.push('Strong evidence of publication bias (Egger p=' + egger_p.toFixed(3) + ')');
      } else if (egger_p < 0.10) {
        downgrade = 1;
        concerns.push('Possible publication bias (Egger p=' + egger_p.toFixed(3) + ')');
      }

      if (trim_fill && trim_fill.n_imputed > 0) {
        if (downgrade < 1) downgrade = 1;
        concerns.push('Trim-and-fill imputed ' + trim_fill.n_imputed + ' studies');
      }

      return {
        rating: downgrade === 0 ? 'No serious concerns' : downgrade === 1 ? 'Serious' : 'Very serious',
        downgrade: downgrade,
        concerns: concerns,
        egger_p: egger_p
      };
    }

    function generateGRADESummary(domains, certainty) {
      const concerns = [];
      for (const [name, domain] of Object.entries(domains)) {
        if (domain.downgrade > 0 && domain.concerns) {
          concerns.push(...domain.concerns);
        }
      }

      if (concerns.length === 0) {
        return 'Evidence certainty is ' + certainty + '. No serious concerns across GRADE domains.';
      }

      return 'Evidence certainty is ' + certainty + '. Key concerns: ' + concerns.join('; ') + '.';
    }

    // =========================================================================
    // 10. ZERO-CELL HANDLING
    // =========================================================================

    /**
     * Handle zero cells in 2x2 tables with appropriate warnings
     */
    function handleZeroCells(a, b, c, d, method = 'constant') {
      const hasZero = a === 0 || b === 0 || c === 0 || d === 0;
      const allZeroArm = (a === 0 && c === 0) || (b === 0 && d === 0);

      let warning = null;
      let correction = 0;
      let a_adj = a, b_adj = b, c_adj = c, d_adj = d;

      if (allZeroArm) {
        return {
          valid: false,
          warning: 'Both arms have zero events or zero non-events. Study cannot be included.',
          a: a, b: b, c: c, d: d
        };
      }

      if (hasZero) {
        if (method === 'constant') {
          correction = 0.5;
          a_adj = a + 0.5;
          b_adj = b + 0.5;
          c_adj = c + 0.5;
          d_adj = d + 0.5;
          warning = 'Zero cells present. Applied 0.5 continuity correction to all cells.';
        } else if (method === 'treatment_arm') {
          // Sweeting (2004) treatment arm continuity correction
          const n_t = a + b;
          const n_c = c + d;
          const R = n_t / (n_t + n_c);
          correction = R;
          a_adj = a + (1 - R);
          b_adj = b + (1 - R);
          c_adj = c + R;
          d_adj = d + R;
          warning = 'Zero cells present. Applied treatment-arm continuity correction (Sweeting 2004).';
        } else if (method === 'empirical') {
          // Empirical correction based on pooled rate
          const pooled_rate = (a + c) / (a + b + c + d);
          correction = pooled_rate;
          a_adj = a + pooled_rate;
          b_adj = b + (1 - pooled_rate);
          c_adj = c + pooled_rate;
          d_adj = d + (1 - pooled_rate);
          warning = 'Zero cells present. Applied empirical continuity correction.';
        }
      }

      return {
        valid: true,
        hasZero: hasZero,
        warning: warning,
        correction_method: method,
        correction_value: correction,
        original: { a, b, c, d },
        adjusted: { a: a_adj, b: b_adj, c: c_adj, d: d_adj }
      };
    }

