    function runValidation() {
      showToast('Running validation suite...', 'info');

      setTimeout(() => {
        try {
          const validation = runValidationSuite();

          let html = '<h4 style="margin-bottom: var(--space-3);">Validation Against metafor</h4>';
          html += '<table style="width: 100%; border-collapse: collapse; font-size: var(--text-sm);">';
          html += '<thead><tr style="border-bottom: 2px solid var(--border-color);">';
          html += '<th style="text-align: left; padding: 8px;">Dataset</th>';
          html += '<th>θ Match</th><th>SE Match</th><th>τ² Match</th><th>I² Match</th><th>Status</th>';
          html += '</tr></thead><tbody>';

          for (const r of validation.results) {
            const statusIcon = r.overall_pass ? '✅' : '⚠️';
            html += '<tr style="border-bottom: 1px solid var(--border-color);">';
            html += '<td style="padding: 8px;">' + r.dataset + '</td>';
            html += '<td style="text-align: center;">' + (r.passed.theta ? '✓' : '✗') + '</td>';
            html += '<td style="text-align: center;">' + (r.passed.se ? '✓' : '✗') + '</td>';
            html += '<td style="text-align: center;">' + (r.passed.tau2 ? '✓' : '✗') + '</td>';
            html += '<td style="text-align: center;">' + (r.passed.I2 ? '✓' : '✗') + '</td>';
            html += '<td style="text-align: center;">' + statusIcon + '</td>';
            html += '</tr>';
          }

          html += '</tbody></table>';
          html += '<p style="margin-top: var(--space-3); font-weight: 600;">' + validation.summary.conclusion + '</p>';

          document.getElementById('validationResults').innerHTML = html;
          showToast('Validation complete: ' + validation.summary.success_rate + ' passed',
                    validation.summary.passed === validation.summary.total ? 'success' : 'warning');
        } catch (e) {
          showToast('Validation failed: ' + e.message, 'error');
          console.error(e);
        }
      }, 100);
    }

    function runGRADEAssessment() {
      const r = AppState.results;
      if (!r || !r.studies) {
        showToast('Run analysis first', 'error');
        return;
      }

      try {
        // Build results object for GRADE
        const gradeInput = {
          theta: r.theta,
          ci_lower: r.ci_lower,
          ci_upper: r.ci_upper,
          I2: r.I2,
          Q_pvalue: r.Q_pvalue,
          egger_p: r.egger_p || 1,
          prediction_interval: r.prediction_interval || null
        };

        const config = {
          studyDesign: 'rct',  // Could be made configurable
          indirectnessAssessment: 'none'
        };

        const grade = assessGRADEDomains(gradeInput, config);

        let html = '<h4 style="margin-bottom: var(--space-3);">GRADE Evidence Certainty</h4>';
        html += '<div style="font-size: var(--text-2xl); margin-bottom: var(--space-2);">' + grade.symbol + '</div>';
        html += '<div style="font-size: var(--text-lg); font-weight: 600; margin-bottom: var(--space-3);">' + grade.certainty + '</div>';

        html += '<table style="width: 100%; border-collapse: collapse; font-size: var(--text-sm);">';
        html += '<thead><tr style="border-bottom: 2px solid var(--border-color);">';
        html += '<th style="text-align: left; padding: 8px;">Domain</th>';
        html += '<th>Rating</th><th>Downgrade</th>';
        html += '</tr></thead><tbody>';

        const domainNames = {
          riskOfBias: 'Risk of Bias',
          inconsistency: 'Inconsistency',
          indirectness: 'Indirectness',
          imprecision: 'Imprecision',
          publicationBias: 'Publication Bias'
        };

        for (const [key, domain] of Object.entries(grade.domains)) {
          const color = domain.downgrade === 0 ? 'var(--color-success-500)' :
                        domain.downgrade === 1 ? 'var(--color-warning-500)' : 'var(--color-danger-500)';
          html += '<tr style="border-bottom: 1px solid var(--border-color);">';
          html += '<td style="padding: 8px;">' + domainNames[key] + '</td>';
          html += '<td style="text-align: center; color: ' + color + ';">' + domain.rating + '</td>';
          html += '<td style="text-align: center;">' + (domain.downgrade > 0 ? '-' + domain.downgrade : '0') + '</td>';
          html += '</tr>';
        }

        html += '</tbody></table>';
        html += '<p style="margin-top: var(--space-3); font-style: italic;">' + grade.summary + '</p>';

        document.getElementById('gradeResults').innerHTML = html;
        showToast('GRADE assessment complete', 'success');
      } catch (e) {
        showToast('GRADE assessment failed: ' + e.message, 'error');
        console.error(e);
      }
    }

    function runMetaRegression() {
      const r = AppState.results;
      if (!r || !r.studies) {
        showToast('Run analysis first', 'error');
        return;
      }

      // For demo, use year as covariate if available
      const yi = r.studies.map(s => s.yi);
      const vi = r.studies.map(s => s.vi);

      // Check for year data
      const years = r.studies.map(s => s.year || null);
      if (years.every(y => y === null)) {
        showToast('No covariate data available. Add year or other moderators.', 'warning');
        return;
      }

      // Center year for interpretation
      const validYears = years.filter(y => y !== null);
      const meanYear = validYears.reduce((a, b) => a + b, 0) / validYears.length;
      const centeredYears = years.map(y => y !== null ? y - meanYear : 0);

      const covariates = [{
        name: 'Year (centered)',
        values: centeredYears
      }];

      try {
        const metareg = multipleMetaRegression(yi, vi, covariates, r.tau2);

        if (!metareg.success) {
          showToast(metareg.message, 'error');
          return;
        }

        let html = '<h4 style="margin-bottom: var(--space-3);">Meta-Regression Results</h4>';
        html += '<table style="width: 100%; border-collapse: collapse; font-size: var(--text-sm);">';
        html += '<thead><tr style="border-bottom: 2px solid var(--border-color);">';
        html += '<th style="text-align: left; padding: 8px;">Term</th>';
        html += '<th>Estimate</th><th>SE</th><th>z</th><th>p</th><th>95% CI</th>';
        html += '</tr></thead><tbody>';

        for (const coef of metareg.coefficients) {
          const sig = coef.p < 0.05 ? 'font-weight: 600;' : '';
          html += '<tr style="border-bottom: 1px solid var(--border-color); ' + sig + '">';
          html += '<td style="padding: 8px;">' + coef.name + '</td>';
          html += '<td style="text-align: right;">' + coef.estimate.toFixed(4) + '</td>';
          html += '<td style="text-align: right;">' + coef.se.toFixed(4) + '</td>';
          html += '<td style="text-align: right;">' + coef.z.toFixed(2) + '</td>';
          html += '<td style="text-align: right;">' + (coef.p < 0.001 ? '<0.001' : coef.p.toFixed(3)) + '</td>';
          html += '<td style="text-align: right;">[' + coef.ci_lower.toFixed(3) + ', ' + coef.ci_upper.toFixed(3) + ']</td>';
          html += '</tr>';
        }

        html += '</tbody></table>';
        html += '<div style="margin-top: var(--space-3);">';
        html += '<p><strong>R²:</strong> ' + (metareg.R2 * 100).toFixed(1) + '% of heterogeneity explained</p>';
        html += '<p><strong>Residual I²:</strong> ' + metareg.I2_residual.toFixed(1) + '%</p>';
        html += '<p><strong>Test of moderators:</strong> Q=' + metareg.Q_model.toFixed(2) + ', df=' + metareg.df_model + ', p=' + (metareg.p_model < 0.001 ? '<0.001' : metareg.p_model.toFixed(3)) + '</p>';
        html += '</div>';

        document.getElementById('metaregResults').innerHTML = html;
        showToast('Meta-regression complete', 'success');
      } catch (e) {
        showToast('Meta-regression failed: ' + e.message, 'error');
        console.error(e);
      }
    }

    function runLeaveOneOutCorrected() {
      const r = AppState.results;
      if (!r || !r.studies) {
        showToast('Run analysis first', 'error');
        return;
      }

      const yi = r.studies.map(s => s.yi);
      const vi = r.studies.map(s => s.vi);
      const names = r.studies.map(s => s.name);

      try {
        const loo = leaveOneOutCorrected(yi, vi, r.tau2);

        // Render plot
        const traces = [{
          type: 'scatter',
          mode: 'markers+lines',
          x: loo.leave_one_out.map((_, i) => i + 1),
          y: loo.leave_one_out.map(l => l.theta),
          error_y: {
            type: 'data',
            symmetric: false,
            array: loo.leave_one_out.map(l => l.ci_corrected.upper - l.theta),
            arrayminus: loo.leave_one_out.map(l => l.theta - l.ci_corrected.lower)
          },
          name: 'Leave-one-out estimate',
          marker: { size: 8, color: '#4a7ab8' }
        }];

        // Add full estimate line
        traces.push({
          type: 'scatter',
          mode: 'lines',
          x: [0, names.length + 1],
          y: [loo.full_model.theta, loo.full_model.theta],
          name: 'Full model',
          line: { color: '#22c55e', dash: 'dash', width: 2 }
        });

        const layout = {
          title: 'Leave-One-Out Analysis (Corrected CIs)',
          xaxis: {
            title: 'Study Omitted',
            tickmode: 'array',
            tickvals: loo.leave_one_out.map((_, i) => i + 1),
            ticktext: names
          },
          yaxis: { title: 'Pooled Estimate' },
          paper_bgcolor: 'rgba(0,0,0,0)',
          plot_bgcolor: 'rgba(0,0,0,0)',
          font: { color: getComputedStyle(document.documentElement).getPropertyValue('--text-primary') }
        };

        Plotly.newPlot('looPlot', traces, layout, { responsive: true });

        document.getElementById('looResults').innerHTML = `
          <p><strong>Full model estimate:</strong> ${loo.full_model.theta.toFixed(4)} (SE=${loo.full_model.se.toFixed(4)})</p>
          <p><strong>Estimate range:</strong> [${loo.theta_range[0].toFixed(4)}, ${loo.theta_range[1].toFixed(4)}]</p>
          <p><strong>Max change:</strong> ${loo.max_change.toFixed(4)} (omitting study ${loo.most_influential_index + 1})</p>
          <p style="font-style: italic; margin-top: var(--space-2);">${loo.interpretation}</p>
        `;

        showToast('Leave-one-out analysis complete', 'success');
      } catch (e) {
        showToast('LOO analysis failed: ' + e.message, 'error');
        console.error(e);
      }
    }


    
    /**
     * Display small-sample warnings in the UI
     */
    function displaySmallSampleWarnings(k, tau2, I2) {
      const warnings = checkSmallSampleWarnings(k, tau2, I2);

      if (warnings.length === 0) return;

      const warningContainer = document.getElementById('analysisWarnings');
      if (!warningContainer) {
        // Create warning container if doesn't exist
        const analysisPanel = document.getElementById('panel-analysis');
        if (analysisPanel) {
          const container = document.createElement('div');
          container.id = 'analysisWarnings';
          container.style.marginBottom = 'var(--space-4)';
          analysisPanel.insertBefore(container, analysisPanel.firstChild);
        }
      }

      const container = document.getElementById('analysisWarnings');
      if (!container) return;

      let html = '';
      for (const w of warnings) {
        const alertClass = w.severity === 'critical' ? 'alert--danger' :
                           w.severity === 'warning' ? 'alert--warning' : 'alert--info';
        const icon = w.severity === 'critical' ? '⚠️' :
                     w.severity === 'warning' ? '⚡' : 'ℹ️';

        html += '<div class="alert ' + alertClass + '" style="margin-bottom: var(--space-2);">';
        html += '<span class="alert__icon">' + icon + '</span>';
        html += '<div class="alert__content">';
        html += '<strong>' + w.message + '</strong>';
        html += '<p style="margin-top: var(--space-1); font-size: var(--text-sm);">' + w.recommendation + '</p>';
        html += '</div></div>';
      }

      container.innerHTML = html;
    }


    

