    /**
     * Run extended validation including HKSJ and Egger tests
     */
    function runExtendedValidation() {
      const results = [];

      // Original validation datasets
      for (const [key, dataset] of Object.entries(VALIDATION_DATASETS)) {
        const validation = validateAgainstMetafor(dataset);
        results.push({
          dataset: dataset.name,
          type: 'core',
          ...validation
        });
      }

      // Extended validation
      // 1. Extreme heterogeneity
      const antiDep = VALIDATION_DATASETS_EXTENDED.antidepressants;
      const antiDepResult = validateExtremeHeterogeneity(antiDep);
      results.push({
        dataset: antiDep.name,
        type: 'heterogeneity',
        ...antiDepResult
      });

      // 2. HKSJ validation
      const smallSample = VALIDATION_DATASETS_EXTENDED.small_sample;
      const hksjResult = validateHKSJ(smallSample);
      results.push({
        dataset: smallSample.name,
        type: 'hksj',
        ...hksjResult
      });

      // 3. Egger validation
      const asymmetric = VALIDATION_DATASETS_EXTENDED.asymmetric_funnel;
      const eggerResult = validateEgger(asymmetric);
      results.push({
        dataset: asymmetric.name,
        type: 'egger',
        ...eggerResult
      });

      return {
        results: results,
        summary: summarizeExtendedValidation(results),
        timestamp: new Date().toISOString()
      };
    }

    function validateExtremeHeterogeneity(dataset) {
      const studies = dataset.studies.map(s => {
        const n1 = s.n_t, n2 = s.n_c;
        const pooledSD = Math.sqrt(((n1-1)*s.sd_t*s.sd_t + (n2-1)*s.sd_c*s.sd_c) / (n1+n2-2));
        const d = (s.mean_t - s.mean_c) / pooledSD;
        const J = 1 - 3/(4*(n1+n2-2)-1);
        const g = d * J;
        const vi = (n1+n2)/(n1*n2) + g*g/(2*(n1+n2));
        return { yi: g, vi: vi };
      });

      const yi = studies.map(s => s.yi);
      const vi = studies.map(s => s.vi);

      const tau2 = estimateTau2_DL(yi, vi);
      const wi = vi.map(v => 1/(v + tau2));
      const sumW = wi.reduce((a,b) => a+b, 0);
      const theta = wi.reduce((s,w,i) => s + w*yi[i], 0) / sumW;

      // Q and I²
      const Q = vi.map((v,i) => (1/v) * Math.pow(yi[i] - theta, 2)).reduce((a,b) => a+b, 0);
      const k = yi.length;
      const I2 = Math.max(0, (Q - (k-1)) / Q) * 100;

      const passed = I2 >= dataset.expected.I2_min && tau2 >= dataset.expected.tau2_min;

      return {
        computed: { I2: I2, tau2: tau2, Q: Q, theta: theta },
        expected: dataset.expected,
        passed: { I2: I2 >= dataset.expected.I2_min, tau2: tau2 >= dataset.expected.tau2_min },
        overall_pass: passed,
        message: passed ?
          'Extreme heterogeneity correctly detected (I²=' + I2.toFixed(1) + '%)' :
          'WARNING: Heterogeneity detection may be inaccurate'
      };
    }

    function validateHKSJ(dataset) {
      const studies = dataset.studies.map(s => {
        const a = s.events_t + 0.5;
        const b = s.n_t - s.events_t + 0.5;
        const c = s.events_c + 0.5;
        const d = s.n_c - s.events_c + 0.5;
        const yi = Math.log((a*d)/(b*c));
        const vi = 1/a + 1/b + 1/c + 1/d;
        return { yi, vi };
      });

      const yi = studies.map(s => s.yi);
      const vi = studies.map(s => s.vi);
      const k = yi.length;

      const tau2 = estimateTau2_DL(yi, vi);
      const wi = vi.map(v => 1/(v + tau2));
      const sumW = wi.reduce((a,b) => a+b, 0);
      const theta = wi.reduce((s,w,i) => s + w*yi[i], 0) / sumW;

      // Standard CI (Wald)
      const se_std = Math.sqrt(1/sumW);
      const ci_std_lower = theta - 1.96 * se_std;
      const ci_std_upper = theta + 1.96 * se_std;
      const ci_std_width = ci_std_upper - ci_std_lower;

      // HKSJ adjustment
      const Q = wi.reduce((s,w,i) => s + w * Math.pow(yi[i] - theta, 2), 0);
      const q_adj = Math.max(1, Q / (k - 1));
      const se_hksj = Math.sqrt((1/sumW) * q_adj);
      const t_crit = qt(0.975, k - 1);
      const ci_hksj_lower = theta - t_crit * se_hksj;
      const ci_hksj_upper = theta + t_crit * se_hksj;
      const ci_hksj_width = ci_hksj_upper - ci_hksj_lower;

      const hksj_wider = ci_hksj_width > ci_std_width;
      const passed = hksj_wider === dataset.expected.hksj_wider;

      return {
        computed: {
          theta: theta,
          ci_std: { lower: ci_std_lower, upper: ci_std_upper, width: ci_std_width },
          ci_hksj: { lower: ci_hksj_lower, upper: ci_hksj_upper, width: ci_hksj_width },
          width_ratio: ci_hksj_width / ci_std_width
        },
        expected: dataset.expected,
        passed: { hksj_wider: hksj_wider },
        overall_pass: passed,
        message: passed ?
          'HKSJ correctly widened CI by ' + ((ci_hksj_width/ci_std_width - 1) * 100).toFixed(1) + '%' :
          'WARNING: HKSJ adjustment may be incorrect'
      };
    }

    function validateEgger(dataset) {
      const studies = dataset.studies.map(s => {
        const n1 = s.n_t, n2 = s.n_c;
        const pooledSD = Math.sqrt(((n1-1)*s.sd_t*s.sd_t + (n2-1)*s.sd_c*s.sd_c) / (n1+n2-2));
        const d = (s.mean_t - s.mean_c) / pooledSD;
        const vi = (n1+n2)/(n1*n2) + d*d/(2*(n1+n2));
        return { yi: d, vi: vi, sei: Math.sqrt(vi) };
      });

      const yi = studies.map(s => s.yi);
      const sei = studies.map(s => s.sei);
      const k = yi.length;

      // Egger's regression: yi/sei = a + b*(1/sei) + error
      // Regress standardized effect (yi/sei) on precision (1/sei)
      const x = sei.map(s => 1/s);  // precision
      const y = yi.map((y,i) => y/sei[i]);  // standardized effect

      const n = k;
      const sumX = x.reduce((a,b) => a+b, 0);
      const sumY = y.reduce((a,b) => a+b, 0);
      const sumXY = x.reduce((s,xi,i) => s + xi*y[i], 0);
      const sumX2 = x.reduce((s,xi) => s + xi*xi, 0);

      const b = (n*sumXY - sumX*sumY) / (n*sumX2 - sumX*sumX);
      const a = (sumY - b*sumX) / n;  // Intercept (bias indicator)

      // Standard error of intercept
      const yPred = x.map(xi => a + b*xi);
      const sse = y.reduce((s,yi,i) => s + Math.pow(yi - yPred[i], 2), 0);
      const mse = sse / (n - 2);
      const se_a = Math.sqrt(mse * (1/n + Math.pow(sumX/n, 2) / (sumX2 - sumX*sumX/n)));

      // t-test for intercept
      const t = a / se_a;
      const df = n - 2;
      const p = 2 * (1 - pt(Math.abs(t), df));

      const detected = p < dataset.expected.egger_p_max;
      const passed = detected;

      return {
        computed: {
          intercept: a,
          se_intercept: se_a,
          t_stat: t,
          p_value: p,
          slope: b
        },
        expected: dataset.expected,
        passed: { asymmetry_detected: detected },
        overall_pass: passed,
        message: passed ?
          'Egger test correctly detected asymmetry (p=' + p.toFixed(4) + ')' :
          'WARNING: Egger test may have low power or be incorrect'
      };
    }

    function summarizeExtendedValidation(results) {
      const core = results.filter(r => r.type === 'core');
      const extended = results.filter(r => r.type !== 'core');

      const corePassed = core.filter(r => r.overall_pass).length;
      const extendedPassed = extended.filter(r => r.overall_pass).length;

      return {
        core_passed: corePassed,
        core_total: core.length,
        extended_passed: extendedPassed,
        extended_total: extended.length,
        all_passed: corePassed + extendedPassed,
        all_total: core.length + extended.length,
        conclusion: (corePassed === core.length && extendedPassed === extended.length) ?
          'All validation tests PASSED including HKSJ, Egger, and extreme heterogeneity.' :
          'Some tests failed. Review detailed results.'
      };
    }

    // =========================================================================
    // 2. CUMULATIVE META-ANALYSIS PLOTS
    // =========================================================================

    /**
     * Cumulative meta-analysis by publication year
     */
    function cumulativeMetaAnalysisByYear(studies, tau2Method = 'DL') {
      // Sort by year
      const sorted = [...studies].sort((a, b) => (a.year || 2000) - (b.year || 2000));
      const results = [];

      for (let i = 0; i < sorted.length; i++) {
        const subset = sorted.slice(0, i + 1);
        const yi = subset.map(s => s.yi);
        const vi = subset.map(s => s.vi);

        const tau2 = estimateTau2_DL(yi, vi);
        const wi = vi.map(v => 1/(v + tau2));
        const sumW = wi.reduce((a,b) => a+b, 0);
        const theta = wi.reduce((s,w,j) => s + w*yi[j], 0) / sumW;
        const se = Math.sqrt(1/sumW);

        results.push({
          k: i + 1,
          year: sorted[i].year || 2000,
          study: sorted[i].name,
          theta: theta,
          se: se,
          ci_lower: theta - 1.96 * se,
          ci_upper: theta + 1.96 * se,
          tau2: tau2
        });
      }

      return results;
    }

    /**
     * Cumulative meta-analysis by precision (smallest SE first)
     */
    function cumulativeMetaAnalysisByPrecision(studies) {
      // Sort by SE (ascending = most precise first)
      const sorted = [...studies].sort((a, b) => a.sei - b.sei);
      const results = [];

      for (let i = 0; i < sorted.length; i++) {
        const subset = sorted.slice(0, i + 1);
        const yi = subset.map(s => s.yi);
        const vi = subset.map(s => s.vi);

        const tau2 = estimateTau2_DL(yi, vi);
        const wi = vi.map(v => 1/(v + tau2));
        const sumW = wi.reduce((a,b) => a+b, 0);
        const theta = wi.reduce((s,w,j) => s + w*yi[j], 0) / sumW;
        const se = Math.sqrt(1/sumW);

        results.push({
          k: i + 1,
          precision_rank: i + 1,
          study: sorted[i].name,
          study_se: sorted[i].sei,
          theta: theta,
          se: se,
          ci_lower: theta - 1.96 * se,
          ci_upper: theta + 1.96 * se,
          tau2: tau2
        });
      }

      return results;
    }

    function renderCumulativeMetaAnalysisPlot(cumResults, type, containerId) {
      const container = document.getElementById(containerId);
      if (!container) return;

      const xLabel = type === 'year' ? 'Year' : 'Precision Rank (Most Precise First)';
      const xValues = type === 'year' ?
        cumResults.map(r => r.year) :
        cumResults.map(r => r.precision_rank);

      const traces = [{
        type: 'scatter',
        mode: 'lines+markers',
        x: xValues,
        y: cumResults.map(r => r.theta),
        error_y: {
          type: 'data',
          symmetric: false,
          array: cumResults.map(r => r.ci_upper - r.theta),
          arrayminus: cumResults.map(r => r.theta - r.ci_lower),
          color: 'rgba(74, 122, 184, 0.4)'
        },
        name: 'Cumulative Estimate',
        line: { color: '#4a7ab8', width: 2 },
        marker: { size: 8 }
      }];

      // Add final estimate reference line
      const finalTheta = cumResults[cumResults.length - 1].theta;
      traces.push({
        type: 'scatter',
        mode: 'lines',
        x: [xValues[0], xValues[xValues.length - 1]],
        y: [finalTheta, finalTheta],
        name: 'Final Estimate',
        line: { color: '#22c55e', dash: 'dash', width: 2 }
      });

      // Add null reference line
      traces.push({
        type: 'scatter',
        mode: 'lines',
        x: [xValues[0], xValues[xValues.length - 1]],
        y: [0, 0],
        name: 'Null Effect',
        line: { color: '#888', dash: 'dot', width: 1 }
      });

      const layout = {
        title: type === 'year' ? 'Cumulative Meta-Analysis by Year' : 'Cumulative Meta-Analysis by Precision',
        xaxis: { title: xLabel },
        yaxis: { title: 'Pooled Effect Size' },
        paper_bgcolor: 'rgba(0,0,0,0)',
        plot_bgcolor: 'rgba(0,0,0,0)',
        font: { color: getComputedStyle(document.documentElement).getPropertyValue('--text-primary') },
        showlegend: true,
        legend: { x: 0.02, y: 0.98 }
      };

      Plotly.newPlot(containerId, traces, layout, { responsive: true });
    }

