    // =========================================================================
    // RUN FUNCTIONS
    // =========================================================================

    function runExtendedValidationUI() {
      showToast('Running extended validation suite...', 'info');

      setTimeout(() => {
        try {
          const validation = runExtendedValidation();

          let html = '<h4 style="margin-bottom: var(--space-3);">Extended Validation (incl. HKSJ, Egger, High I²)</h4>';
          html += '<table style="width: 100%; border-collapse: collapse; font-size: var(--text-sm);">';
          html += '<thead><tr style="border-bottom: 2px solid var(--border-color);">';
          html += '<th style="text-align: left; padding: 8px;">Test</th>';
          html += '<th>Type</th><th>Status</th><th>Details</th>';
          html += '</tr></thead><tbody>';

          for (const r of validation.results) {
            const statusIcon = r.overall_pass ? '✅' : '⚠️';
            const typeLabel = {
              'core': 'Core',
              'heterogeneity': 'I² Test',
              'hksj': 'HKSJ',
              'egger': 'Egger'
            }[r.type] || r.type;

            html += '<tr style="border-bottom: 1px solid var(--border-color);">';
            html += '<td style="padding: 8px;">' + r.dataset + '</td>';
            html += '<td style="text-align: center;">' + typeLabel + '</td>';
            html += '<td style="text-align: center;">' + statusIcon + '</td>';
            html += '<td style="font-size: var(--text-xs);">' + (r.message || 'Passed') + '</td>';
            html += '</tr>';
          }

          html += '</tbody></table>';
          html += '<p style="margin-top: var(--space-3); font-weight: 600;">' +
                  validation.summary.all_passed + '/' + validation.summary.all_total + ' tests passed. ' +
                  validation.summary.conclusion + '</p>';

          document.getElementById('validationResults').innerHTML = html;
          showToast('Extended validation complete',
                    validation.summary.all_passed === validation.summary.all_total ? 'success' : 'warning');
        } catch (e) {
          showToast('Validation failed: ' + e.message, 'error');
          console.error(e);
        }
      }, 100);
    }

    function runCumulativeAnalysis() {
      const r = AppState.results;
      if (!r || !r.studies) {
        showToast('Run analysis first', 'error');
        return;
      }

      try {
        // By year
        const cumYear = cumulativeMetaAnalysisByYear(r.studies);
        renderCumulativeMetaAnalysisPlot(cumYear, 'year', 'cumYearPlot');

        // By precision
        const cumPrec = cumulativeMetaAnalysisByPrecision(r.studies);
        renderCumulativeMetaAnalysisPlot(cumPrec, 'precision', 'cumPrecisionPlot');

        // Results summary
        const firstTheta = cumYear[0].theta;
        const lastTheta = cumYear[cumYear.length - 1].theta;
        const drift = lastTheta - firstTheta;

        document.getElementById('cumulativeResults').innerHTML = `
          <p><strong>Effect size drift:</strong> ${drift > 0 ? '+' : ''}${drift.toFixed(4)} from first to last study</p>
          <p><strong>Interpretation:</strong> ${Math.abs(drift) < 0.1 ?
            'Estimate stable over time - no evidence of temporal drift.' :
            'Notable drift detected - consider investigating temporal trends.'}</p>
        `;

        showToast('Cumulative analysis complete', 'success');
      } catch (e) {
        showToast('Cumulative analysis failed: ' + e.message, 'error');
        console.error(e);
      }
    }


    // Advanced methods exports
    window.runGOSHAnalysis = runGOSHAnalysis;
    window.runTSAAnalysis = runTSAAnalysis;
    window.runPCurveAnalysis = runPCurveAnalysis;
    window.runZCurveAnalysis = runZCurveAnalysis;
    window.runCR2Analysis = runCR2Analysis;
    window.runRoBMA = runRoBMA;
    window.renderContourFunnelPlot = renderContourFunnelPlot;
    window.renderSunsetPlot = renderSunsetPlot;
    window.autoRenderPowerAnalysis = autoRenderPowerAnalysis;
    window.runInfluenceDiagnostics = runInfluenceDiagnostics;
    window.runCopasModel = runCopasModel;
