    window.calculatePredictionInterval = calculatePredictionInterval;
    window.calculateInfluenceDiagnostics = calculateInfluenceDiagnostics;
    window.copasSelectionModel = copasSelectionModel;
    window.zejnullahiCI = zejnullahiCI;
    window.profileLikelihoodTau2CI = profileLikelihoodTau2CI;
    window.runValidation = runValidation;
    window.runValidationSuite = runValidationSuite;
    window.runGRADEAssessment = runGRADEAssessment;
    window.runMetaRegression = runMetaRegression;
    window.runLeaveOneOutCorrected = runLeaveOneOutCorrected;
    window.calculateHedgesG = calculateHedgesG;
