    window.handleZeroCells = handleZeroCells;
    window.renderEnhancedFunnelPlot = renderEnhancedFunnelPlot;
    window.generatePRISMAData = generatePRISMAData;
    window.renderPRISMADiagram = renderPRISMADiagram;
    window.estimateTau2_REML_Documented = estimateTau2_REML_Documented;
    window.VALIDATION_DATASETS = VALIDATION_DATASETS;
    window.displaySmallSampleWarnings = displaySmallSampleWarnings;
    window.runExtendedValidation = runExtendedValidation;
    window.runExtendedValidationUI = runExtendedValidationUI;
    window.cumulativeMetaAnalysisByYear = cumulativeMetaAnalysisByYear;
    window.cumulativeMetaAnalysisByPrecision = cumulativeMetaAnalysisByPrecision;
