/**
 * Run self-validation against metafor benchmarks
 * @returns {Object} Validation results summary
 */
function runSelfValidation() {
  const results = {
    passed: 0,
    failed: 0,
    tests: [],
    summary: {}
  };

  const tolerance = VALIDATION_BENCHMARKS.tolerance;

  for (const [datasetName, dataset] of Object.entries(VALIDATION_BENCHMARKS.datasets)) {
    const yi = dataset.yi;
    const vi = dataset.vi;
    const k = dataset.k;

    // Test each tau2 method
    const tau2Methods = ['DL', 'REML', 'ML', 'PM', 'HS', 'SJ', 'HE', 'EB'];

    for (const method of tau2Methods) {
      if (!dataset.tests[method]) continue;

      const expected = dataset.tests[method];

      try {
        // Calculate using our implementation
        let tau2;
        switch(method) {
          case 'DL': tau2 = estimateTau2_DL(yi, vi); break;
          case 'REML': tau2 = estimateTau2_REML(yi, vi); break;
          case 'ML': tau2 = estimateTau2_ML(yi, vi); break;
          case 'PM': tau2 = estimateTau2_PM(yi, vi); break;
          case 'HS': tau2 = estimateTau2_HS(yi, vi); break;
          case 'SJ': tau2 = estimateTau2_SJ(yi, vi); break;
          case 'HE': tau2 = estimateTau2_HE(yi, vi); break;
          case 'EB': tau2 = estimateTau2_EB(yi, vi); break;
        }

        // Calculate pooled estimate with this tau2
        const weights = vi.map(v => 1 / (v + tau2));
        const sumW = weights.reduce((a, b) => a + b, 0);
        const theta = yi.reduce((sum, y, i) => sum + weights[i] * y, 0) / sumW;

        // Compare
        const thetaDiff = Math.abs(theta - expected.theta);
        const tau2Diff = Math.abs(tau2 - expected.tau2);

        const passed = thetaDiff < tolerance.theta && tau2Diff < tolerance.tau2;

        if (passed) {
          results.passed++;
        } else {
          results.failed++;
        }

        results.tests.push({
          dataset: datasetName,
          method: method,
          passed: passed,
          expected: { theta: expected.theta, tau2: expected.tau2 },
          actual: { theta: theta, tau2: tau2 },
          diff: { theta: thetaDiff, tau2: tau2Diff }
        });

      } catch (e) {
        results.failed++;
        results.tests.push({
          dataset: datasetName,
          method: method,
          passed: false,
          error: e.message
        });
      }
    }

    // Test HKSJ
    if (dataset.tests.HKSJ) {
      try {
        const tau2 = estimateTau2_REML(yi, vi);
        const hksj = calculateHKSJ(yi, vi, tau2);

        const expected = dataset.tests.HKSJ;
        const ciLowerDiff = Math.abs(hksj.ci_lower - expected.ci_lower);
        const ciUpperDiff = Math.abs(hksj.ci_upper - expected.ci_upper);

        const passed = ciLowerDiff < 0.05 && ciUpperDiff < 0.05;

        if (passed) results.passed++;
        else results.failed++;

        results.tests.push({
          dataset: datasetName,
          method: 'HKSJ',
          passed: passed,
          expected: { ci_lower: expected.ci_lower, ci_upper: expected.ci_upper },
          actual: { ci_lower: hksj.ci_lower, ci_upper: hksj.ci_upper }
        });
      } catch (e) {
        results.failed++;
      }
    }

    // Test Egger
    if (dataset.tests.egger && k >= 3) {
      try {
        const egger = eggerTest({ yi, vi });

        const expected = dataset.tests.egger;
        const pDiff = Math.abs(egger.p - expected.p);

        const passed = pDiff < 0.01 || (egger.p < 0.05) === (expected.p < 0.05);

        if (passed) results.passed++;
        else results.failed++;

        results.tests.push({
          dataset: datasetName,
          method: 'Egger',
          passed: passed,
          expected: { p: expected.p, z: expected.z },
          actual: { p: egger.p, z: egger.z }
        });
      } catch (e) {
        results.failed++;
      }
    }
  }

  // Summary
  results.summary = {
    total: results.passed + results.failed,
    passed: results.passed,
    failed: results.failed,
    passRate: ((results.passed / (results.passed + results.failed)) * 100).toFixed(1) + '%',
    metaforVersion: VALIDATION_BENCHMARKS.metafor_version,
    generatedDate: VALIDATION_BENCHMARKS.generated
  };

  return results;
}

/**
 * Display validation results in console
 */
function showValidationResults() {
  const results = runSelfValidation();

  console.log('='.repeat(60));
  console.log('SELF-VALIDATION RESULTS');
  console.log('='.repeat(60));
  console.log(`Reference: metafor ${results.summary.metaforVersion}`);
  console.log(`Benchmarks generated: ${results.summary.generatedDate}`);
  console.log(`Total tests: ${results.summary.total}`);
  console.log(`Passed: ${results.summary.passed} (${results.summary.passRate})`);
  console.log(`Failed: ${results.summary.failed}`);
  console.log('='.repeat(60));

  if (results.failed > 0) {
    console.log('\nFailed tests:');
    results.tests.filter(t => !t.passed).forEach(t => {
      console.log(`  ${t.dataset} / ${t.method}: expected theta=${t.expected?.theta}, got ${t.actual?.theta}`);
    });
  }

  return results;
}

// Export validation functions
if (typeof window !== 'undefined') {
  window.runSelfValidation = runSelfValidation;
  window.showValidationResults = showValidationResults;
  window.VALIDATION_BENCHMARKS = VALIDATION_BENCHMARKS;
}



