/**
 * Get simulation evidence summary for display
 * @returns {Object} Summary of simulation performance
 */
function getSimulationSummary() {
  const scenarios = SIMULATION_EVIDENCE.scenarios;
  return {
    correct: {
      title: "Correct Specification",
      coverage_k10: scenarios.correct.k10.coverage,
      coverage_k50: scenarios.correct.k50.coverage,
      assessment: "Acceptable (near nominal 95%)"
    },
    nonnormal: {
      title: "Non-Normal Effects",
      coverage_k10: scenarios.nonnormal.k10.coverage,
      coverage_k50: scenarios.nonnormal.k50.coverage,
      assessment: "Robust (minimal impact)"
    },
    outliers: {
      title: "10% Outliers",
      coverage_k10: scenarios.outliers.k10.coverage,
      coverage_k50: scenarios.outliers.k50.coverage,
      assessment: "Acceptable (slight inflation)"
    },
    pub_bias: {
      title: "Publication Bias",
      coverage_k10: scenarios.pub_bias.k10.coverage,
      coverage_k50: scenarios.pub_bias.k50.coverage,
      egger_power: scenarios.pub_bias.k10.egger_power,
      assessment: "CRITICAL - Severe undercoverage"
    },
    dependent: {
      title: "Dependent Studies",
      coverage_k10: scenarios.dependent.k10.coverage,
      coverage_k50: scenarios.dependent.k50.coverage,
      assessment: "CRITICAL - Use RVE/multilevel"
    },
    variance_misspec: {
      title: "Variance Misspec",
      coverage_k10: scenarios.variance_misspec.k10.coverage,
      coverage_k50: scenarios.variance_misspec.k50.coverage,
      assessment: "Moderate - recovers with k"
    },
    heteroscedastic: {
      title: "Heteroscedastic tau2",
      coverage_k10: scenarios.heteroscedastic.k10.coverage,
      coverage_k50: scenarios.heteroscedastic.k50.coverage,
      assessment: "Low impact"
    },
    small_sample: {
      title: "Small Sample (k=3)",
      wald_coverage: scenarios.small_sample.results.wald_coverage,
      hksj_coverage: scenarios.small_sample.results.hksj_coverage,
      assessment: "Use HKSJ adjustment"
    }
  };
}

/**
 * Render simulation evidence panel
 * @param {string} containerId - DOM container ID
 */
function renderSimulationEvidence(containerId) {
  const container = document.getElementById(containerId);
  if (!container) return;

  const summary = getSimulationSummary();

  let html = `
    <div class="simulation-evidence">
      <h4>Performance Under Model Misspecification</h4>
      <p class="help-text">Based on ${SIMULATION_EVIDENCE.metadata.n_simulations.toLocaleString()} simulations per scenario.</p>

      <table class="simulation-table" style="width:100%;font-size:var(--text-sm);border-collapse:collapse;">
        <thead>
          <tr style="background:var(--surface-secondary);">
            <th style="padding:8px;text-align:left;">Scenario</th>
            <th style="padding:8px;text-align:center;">Coverage (k=10)</th>
            <th style="padding:8px;text-align:left;">Assessment</th>
          </tr>
        </thead>
        <tbody>
  `;

  for (const [key, data] of Object.entries(summary)) {
    const coverage = data.coverage_k10 || data.wald_coverage || data.hksj_coverage;
    const color = coverage >= 90 ? 'var(--color-success-500)' :
                  coverage >= 85 ? 'var(--color-warning-500)' : 'var(--color-danger-500)';

    html += `
      <tr>
        <td style="padding:6px;border-bottom:1px solid var(--border-subtle);">${data.title}</td>
        <td style="padding:6px;text-align:center;color:${color};border-bottom:1px solid var(--border-subtle);">${coverage.toFixed(1)}%</td>
        <td style="padding:6px;border-bottom:1px solid var(--border-subtle);">${data.assessment}</td>
      </tr>
    `;
  }

  html += `
        </tbody>
      </table>

      <div class="alert alert-danger" style="margin-top:var(--space-3);font-size:var(--text-xs);">
        <strong>CRITICAL:</strong> Publication bias (58% at k=50) and dependent studies (55% at k=50)
        cause severe undercoverage. Use trim-and-fill/selection models for pub bias,
        RVE/multilevel for dependent studies.
      </div>
      <div class="alert alert-info" style="margin-top:var(--space-2);font-size:var(--text-xs);">
        <strong>Key Finding:</strong> HKSJ adjustment improves small-sample (k=3) coverage from 93% to 94%.
        Always use HKSJ when k &lt; 20. Egger test has low power (13-16%).
      </div>
    </div>
  `;

  container.innerHTML = html;
}

